type Guides = NonNullable<InfoPageCopy['agentGuides']>;


export function localizedAgentGuidesPartH(en: Guides): Partial<Record<LandingLocaleCode, Guides>> {
  return {
    'it': {
      'claude-code': {
        ...en['claude-code']!,
        title: "Claude Code per il design — Open Design",
        description: "Come i designer usano Claude Code per il design di UI e web, e come Open Design lo trasforma in un vero agente di design — local-first, BYOK, con una libreria curata di skill e design system.",
        breadcrumb: "Claude Code",
        label: "Agente · Claude Code",
        heading: "Claude Code per il design.",
        lead: "Claude Code è l'agente di coding da terminale di Anthropic. Le persone lo usano già per costruire UI, design system e landing page. Open Design lo collega a un vero flusso di lavoro di design — porta la tua chiave Anthropic o il tuo abbonamento Claude, mantieni ogni file in locale.",
        rich: {"heroCtaLead": "Open Design trasforma Claude Code in un agente di design open-source e local-first — la tua chiave Anthropic o il tuo abbonamento Claude, i tuoi file, una libreria curata di skill e design system tutt'intorno.", "heroCtaActions": [{"label": "Usa Claude Code dentro Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Metti una stella su GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Scarica l'app desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Claude Code è ampiamente considerato l'agente di coding con il miglior gusto per il frontend — ragiona sulle interfacce con una specificità insolita, indicando valori hex esatti, spaziature e scale tipografiche, e rifattorizza la UI in un'intera grande codebase senza perdere il filo. Ma, di base, tende comunque a derivare verso un look generico a meno che non gli si forniscano un design system, delle skill e dei riferimenti reali. Questa è una guida pratica ed end-to-end all'uso di Claude Code per UI, frontend e design system, e a come integrarlo in un flusso di lavoro strutturato con Open Design.", "Copre cos'è realmente Claude Code, perché è forte nel frontend, come configurarlo da zero, il flusso di lavoro con CLAUDE.md e le Skill, il round-trip ufficiale con Figma, come si confronta con Codex e Cursor, le insidie che fanno apparire generico l'output dell'IA e come Open Design colma il divario come layer di design aperto e local-first."], "heroImage": {"src": "/agents/claude-code-design/claude-code-design-hero.webp", "alt": "Il ciclo di feedback del design con Claude Code: l'agente da terminale che prende decisioni di design specifiche, un browser che renderizza la UI e uno spazio di lavoro, con una freccia di feedback che ritorna", "caption": "Il ciclo centrale: Claude Code ragiona su decisioni di UI specifiche nel terminale, le renderizza e le verifica in un browser reale e converge rispetto ai tuoi riferimenti."}, "tocLabel": "In questa pagina", "toc": [{"id": "what-is-claude-code", "label": "Cos'è realmente Claude Code"}, {"id": "why-design", "label": "Perché Claude Code è bravo nel design"}, {"id": "setup", "label": "Configurare Claude Code per il design (da zero)"}, {"id": "skills-workflow", "label": "Il flusso di lavoro con CLAUDE.md e le Skill"}, {"id": "figma", "label": "Round-trip Claude Code + Figma"}, {"id": "vs", "label": "Claude Code vs Codex vs Cursor"}, {"id": "pitfalls", "label": "Insidie e l'estetica da \"sbobba dell'IA\""}, {"id": "open-design", "label": "Progettare con Claude Code in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-claude-code", "heading": "Cos'è realmente Claude Code", "blocks": [{"kind": "p", "text": "Claude Code è lo strumento di coding agentico di Anthropic. Legge la tua codebase, modifica file, esegue comandi e si integra con i tuoi strumenti di sviluppo — pianificando, scrivendo e verificando il lavoro a partire da compiti in linguaggio naturale, anziché limitarsi a completare righe in autocompletamento."}, {"kind": "p", "text": "È disponibile su diverse superfici che condividono tutte lo stesso motore: una CLI da terminale, estensioni IDE per VS Code, Cursor e JetBrains, un'app desktop con revisione visiva delle diff e un'esperienza web per i task a lunga esecuzione. I tuoi file CLAUDE.md, le impostazioni e i server MCP ti seguono su tutte."}, {"kind": "steps", "items": [{"label": "File di istruzioni", "body": "Claude Code legge un file CLAUDE.md nella root del progetto all'inizio di ogni sessione — il posto naturale dove codificare le tue convenzioni di design, i tokens e le checklist di revisione."}, {"label": "Skill", "body": "Le Agent Skill impacchettano istruzioni, script e risorse riutilizzabili che Claude carica su richiesta, inclusa la skill ufficiale Frontend Design di Anthropic per il gusto estetico."}, {"label": "Pianificazione e subagenti", "body": "Può pianificare prima di agire e generare subagenti che lavorano in parallelo su parti diverse di un task, il che mantiene coerenti i grandi refactoring di UI."}]}, {"kind": "ul", "items": ["Fornitore: Anthropic", "Credenziale: chiave API Anthropic (BYOK, tramite la Console) o un abbonamento Claude (Pro / Max)", "Superfici: CLI da terminale, estensioni VS Code / Cursor / JetBrains, app desktop, web"]}]}, {"id": "why-design", "heading": "Perché Claude Code è bravo nel design", "blocks": [{"kind": "p", "text": "Tra gli agenti di coding, Claude Code ha la reputazione di avere gusto nel lavoro frontend. Alcune cose lo spiegano."}, {"kind": "steps", "items": [{"label": "Decisioni specifiche, non vaghe", "body": "Claude Code tende a impegnarsi su scelte concrete — valori hex esatti, scale di spaziatura, ramp tipografici e gerarchia dei componenti — invece di tergiversare, ed è proprio questo che distingue una vera interfaccia da un segnaposto."}, {"label": "Ragionamento consapevole della codebase", "body": "Con un ampio contesto di lavoro rifattorizza la UI su molti file contemporaneamente, riutilizzando i tuoi componenti e tokens esistenti invece di reinventare stili improvvisati."}, {"label": "Una skill frontend ufficiale", "body": "Anthropic include una skill Frontend Design che fa scrivere a Claude prima una direzione di design e lo allontana deliberatamente da font di sistema generici e prevedibili gradienti viola."}]}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-taste-triangle.webp", "alt": "Diagramma che mostra design system, skill e immagine di riferimento che convergono in un buon output di design", "caption": "Il gusto nasce da tre input che fornisci tu: un design system, una skill e immagini di riferimento reali."}, {"kind": "p", "text": "La lezione è la stessa che Anthropic ripete sui propri modelli: Claude non ha gusto di default — lasciato a sé converge verso il centro statistico del web design (Inter, gradienti viola, ombre soft). Produce buon design quando gli dai dei vincoli. Open Design impacchetta esattamente quegli input, ed è per questo che i due si combinano bene (più sotto)."}]}, {"id": "setup", "heading": "Configurare Claude Code per il lavoro di design, da zero", "blocks": [{"kind": "p", "text": "Ecco il percorso completo, da una macchina pulita a un Claude Code in grado di costruire e verificare la UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Claude Code (native install, recommended)\ncurl -fsSL https://claude.ai/install.sh | bash\n# or: brew install --cask claude-code\n# Windows PowerShell: irm https://claude.ai/install.ps1 | iex\n\n# 2. Start it in your project and sign in on first run\ncd your-project\nclaude            # sign in with your Claude subscription or API key\n\n# 3. Generate project context\n/init             # creates a CLAUDE.md for this project\n\n# 4. Add the official Frontend Design skill\nclaude plugin install frontend-design@claude-plugins-official\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\nclaude plugin install figma@claude-plugins-official"}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-setup-flow.webp", "alt": "Flusso di configurazione in cinque passi: installa, autentica, configura CLAUDE.md, aggiungi la skill, verifica", "caption": "La sequenza di configurazione: installa → autentica → configura CLAUDE.md → aggiungi la skill Frontend Design → abilita la verifica nel browser."}, {"kind": "steps", "items": [{"label": "Codifica le tue regole di design", "body": "Inserisci i tuoi tokens, le primitive e le convenzioni in CLAUDE.md e indirizza Claude verso di essi, così l'output rispetta un brand invece di ripiegare su un look generico."}, {"label": "Aggiungi la verifica nel browser", "body": "Collega un MCP Playwright o Chrome così Claude renderizza in un browser reale e controlla il proprio output sui vari breakpoint, invece di confermare solo che la build passa."}]}]}, {"id": "skills-workflow", "heading": "Il flusso di lavoro con CLAUDE.md e le Skill", "blocks": [{"kind": "p", "text": "Il ciclo di design a maggior leva con Claude Code consiste nel fornirgli riferimenti reali più il tuo contesto di design, e poi iterare finché la UI non corrisponde — con CLAUDE.md e le Skill a portare i vincoli, così da non doverli rispiegare a ogni prompt."}, {"kind": "ol", "items": ["Parti dai riferimenti visivi più chiari di cui disponi — e includi più stati (desktop e mobile, hover, vuoto, caricamento), non solo un'unica immagine hero.", "Sii specifico nel prompt; prompt vaghi producono UI generiche anche con un agente forte.", "Tieni il tuo design system e le tue convenzioni in CLAUDE.md, e indica a Claude dove si trovano i tokens e le primitive canoniche.", "Aggiungi la skill Frontend Design così Claude si impegna su una vera direzione estetica prima di scrivere codice.", "Collega la verifica nel browser così Claude renderizza, ridimensiona ai breakpoint e confronta con i riferimenti — non si limita a confermare che la build funziona."]}, {"kind": "p", "text": "Inserisci un'immagine di riferimento nella sessione e formula il prompt con vincoli concreti:"}, {"kind": "code", "lang": "bash", "code": "claude \"Implement reference-desktop.png and reference-mobile.png in\n  React + Vite + Tailwind + TypeScript.\n  Reuse the design-system components and tokens described in CLAUDE.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser, verify it matches the references across\n  breakpoints, and iterate until it does.\""}, {"kind": "p", "text": "Tieni in esecuzione un dev server a fianco, mantieni i prompt piccoli e mirati e fai commit delle buone iterazioni / revert di quelle cattive (avvisando Claude quando fai revert) così ogni passaggio si costruisce su una base pulita. Usa la modalità plan per i refactoring più grandi così da poter rivedere l'approccio prima di qualsiasi modifica ai file."}]}, {"id": "figma", "heading": "Claude Code + Figma: round-trip design ↔ codice", "blocks": [{"kind": "p", "text": "Nel febbraio 2026 Anthropic e Figma hanno rilasciato un'integrazione bidirezionale di prima classe tramite il server Figma MCP. Funziona in entrambe le direzioni."}, {"kind": "steps", "items": [{"label": "Design → Codice", "body": "Seleziona un frame in Figma o incolla un link in Claude Code, recupera il contesto di design e chiedigli di implementarlo usando la tua libreria di componenti esistente. Code Connect mantiene l'output allineato ai tuoi componenti reali."}, {"label": "Codice → Design", "body": "Costruisci e visualizza in anteprima una funzionalità nel browser, poi di' \"Send this to Figma\" per catturare la UI in esecuzione come layer Figma modificabili — l'intera schermata o un elemento selezionato."}]}, {"kind": "p", "text": "Installalo una volta con claude plugin install figma@claude-plugins-official (la modalità Dev Mode MCP richiede un piano Figma a pagamento). Lo stesso Figma MCP è disponibile per Claude Code, Codex, Cursor e VS Code — esattamente il tipo di capacità portabile e multi-agente che Open Design è costruito per orchestrare."}]}, {"id": "vs", "heading": "Claude Code vs Codex vs Cursor per il design", "blocks": [{"kind": "p", "text": "Non c'è un unico vincitore per il lavoro di design — ogni agente ha un punto di forza diverso e i team esperti li combinano. Un riassunto equo:"}, {"kind": "table", "columns": ["Agente", "Punto di forza nel design", "Ideale per"], "rows": [["Claude Code", "Decisioni di design specifiche (hex, spaziatura, tipografia) e ragionamento UX consapevole della codebase", "Ragionamento frontend e refactoring a grande contesto"], ["Codex", "Forte rifinitura visiva e comprensione delle immagini; build asincrone in sandbox", "Build asincrone delegate e regole AGENTS.md portabili"], ["Cursor", "Ciclo visivo costruisci-e-osserva con anteprima live e modifiche inline", "Lavoro di UI iterativo e a vista all'interno di un IDE"]]}, {"kind": "p", "text": "Il verdetto ricorrente della community è che il gusto viene dagli esseri umani: tutti e tre, senza skill, riferimenti e vincoli, ripiegano su un'estetica generica. È questo il vero problema da risolvere — ed è di forma da strumento di design, non da modello."}]}, {"id": "pitfalls", "heading": "Insidie, e come evitare l'estetica da \"sbobba dell'IA\"", "blocks": [{"kind": "p", "text": "Anche con la reputazione di gusto di Claude Code, la lamentela più comune sul design generato dall'IA è che appare generico — font Inter, gradienti viola su bianco, ombre soft, angoli arrotondati esagerati, un'estetica che \"urla che l'ha fatto un'IA\". Anthropic stessa lo attribuisce alla convergenza distributiva: le scelte sicure dominano i dati di addestramento del web. Altri problemi segnalati includono layout mobile rotti e istruzioni che trapelano nel testo della UI."}, {"kind": "steps", "items": [{"label": "Installa la skill Frontend Design", "body": "Costringe Claude a impegnarsi su una vera direzione ed evita esplicitamente font e gradienti abusati dall'IA."}, {"label": "Abilita la verifica nel browser", "body": "Fai renderizzare Claude e auto-controllare sui vari breakpoint così i layout non si rompono in silenzio su mobile."}, {"label": "Fornisci tokens e riferimenti", "body": "Tokens di design reali e screenshot di riferimento sono la singola leva più grande sulla qualità dell'output."}, {"label": "Codifica le regole in CLAUDE.md", "body": "Metti regole in stile \"niente hero card, al massimo due caratteri, gerarchia brand-first\" dove l'agente le legge a ogni esecuzione."}]}, {"kind": "p", "text": "Nota che ogni mitigazione consiste nel dare all'agente un contesto di design curato. Mantenere quel contesto a mano, progetto per progetto, è la fatica che Open Design elimina."}]}, {"id": "open-design", "heading": "Progettare con Claude Code dentro Open Design", "blocks": [{"kind": "p", "text": "Open Design è il layer di design open-source che il flusso di lavoro qui sopra continua a richiedere. Tratta Claude Code come un adattatore di prima parte e lo avvolge in una libreria curata di skill e design system, una pipeline di rendering strutturata e una UI desktop locale — così il contesto di design che rende bravo Claude Code è presente fin dalla prima esecuzione, non assemblato a mano ogni volta."}, {"kind": "ol", "items": ["Installa Open Design e seleziona Claude Code come tuo agente.", "Autenticati con la tua chiave API Anthropic (BYOK) o il tuo abbonamento Claude — le credenziali restano sulla tua macchina e non vengono mai instradate tramite noi.", "Scegli un design system e una skill, poi genera deck, prototipi e landing page con un gusto coerente.", "Ogni artefatto e file DESIGN.md vive nella tua repo, non in un cloud ospitato."]}, {"kind": "p", "text": "Stesso agente Claude Code, stessa chiave — più un vero flusso di lavoro di design portabile e open-source tutt'intorno. È local-first e Apache-2.0, quindi nulla del tuo lavoro o delle tue credenziali lascia la tua macchina."}]}], "faqTitle": "Domande frequenti", "faq": [{"name": "Claude Code è adatto al lavoro di design?", "text": "Sì — è ampiamente considerato l'agente di coding con il miglior gusto per il frontend, capace di decisioni specifiche e consapevoli della codebase su valori hex, spaziatura e scale tipografiche. Con la skill Frontend Design, un design system e immagini di riferimento reali nel contesto produce UI responsive di qualità da produzione e può verificarla in un browser. Senza quel contesto tende a ripiegare su un look generico, ed è il divario che Open Design colma."}, {"name": "Mi serve un abbonamento Claude per progettare con Claude Code?", "text": "Puoi usare sia una chiave API Anthropic (BYOK, tramite la Console) sia un abbonamento Claude (Pro / Max). In ogni caso Open Design non instrada mai le tue credenziali — vengono usate direttamente dal tuo agente sulla tua macchina."}, {"name": "Claude Code o Codex per il design frontend?", "text": "Entrambi sono forti. Claude Code è noto per decisioni di design specifiche e consapevoli della codebase e per il ragionamento frontend; Codex ha una forte rifinitura visiva ed eccelle nelle build delegate e in sandbox. Molti team usano entrambi — Open Design ti permette di cambiare agente senza modificare il tuo flusso di lavoro di design."}, {"name": "Come collego Claude Code a Figma?", "text": "Installa il plugin Figma ufficiale con claude plugin install figma@claude-plugins-official. Potrai poi implementare i frame di Figma in codice usando il contesto di design, e riportare una UI in esecuzione verso frame Figma modificabili con \"Send this to Figma\". La modalità Dev Mode MCP richiede un piano Figma a pagamento."}, {"name": "Cosa sono le Skill e CLAUDE.md?", "text": "CLAUDE.md è un file markdown nella root del tuo progetto che Claude Code legge all'inizio di ogni sessione — il posto dove codificare le tue convenzioni di design. Le Skill impacchettano istruzioni e risorse riutilizzabili che Claude carica su richiesta, inclusa la skill ufficiale Frontend Design di Anthropic. Open Design include una libreria curata di entrambe, così salti la configurazione progetto per progetto."}, {"name": "Come evito l'estetica generica da \"sbobba dell'IA\"?", "text": "Installa la skill Frontend Design, fornisci tokens di design reali e screenshot di riferimento, codifica le regole del brand in CLAUDE.md e abilita la verifica nel browser. Open Design li include come libreria curata, così salti la configurazione progetto per progetto."}, {"name": "Open Design è affiliato ad Anthropic?", "text": "No. Claude Code è un prodotto di Anthropic; Open Design è un progetto open-source indipendente che lo supporta come adattatore di prima parte. Claude e Claude Code sono marchi di Anthropic."}, {"name": "I miei file e le mie credenziali sono al sicuro?", "text": "Sì — Open Design è local-first e Apache-2.0. I tuoi file, gli artefatti e DESIGN.md restano nella tua repo, e le tue credenziali Anthropic vengono usate direttamente dal tuo agente, mai instradate attraverso i server di Open Design."}], "ctaTitle": "Progetta con Claude Code, in modo aperto.", "ctaBody": "Porta la tua chiave Anthropic o il tuo abbonamento Claude, mantieni ogni file in locale e ottieni una libreria di design curata intorno all'agente che già usi.", "ctaActions": [{"label": "Usa Claude Code dentro Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Metti una stella su GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Scarica l'app desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Vedi tutti gli agenti supportati"},
      },
      'codex': {
        ...en['codex']!,
        title: "Codex per il design: crea UI con OpenAI Codex — Open Design",
        description: "La guida pratica per progettare UI e frontend con OpenAI Codex — setup, l’integrazione con Figma, skill e come evitare il look generico da «IA in serie». Open Design trasforma Codex in un agente di design gratuito, local-first e open-source.",
        breadcrumb: "Codex",
        label: "Agente · Codex",
        heading: "Codex per il design.",
        lead: "Codex è l'agente di coding di OpenAI. Con il suo plugin Product Design e l'integrazione con Figma è diventato un serio strumento di design. Open Design collega Codex a un flusso di lavoro di design open-source — la tua chiave OpenAI o il tuo abbonamento ChatGPT, i tuoi file, local-first.",
        rich: {"heroCtaLead": "Open Design trasforma Codex in un agente di design open-source e local-first — la tua chiave OpenAI, i tuoi file, una libreria curata di skill e design system tutt'intorno.", "heroCtaActions": [{"label": "Usa Codex dentro Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Metti una stella su GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Scarica l'app desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["OpenAI Codex è nato come generatore di codice, ma nel 2026 è diventato uno strumento credibile per progettare interfacce reali — una volta che gli fornisci i riferimenti giusti, le skill e un ciclo di verifica. Questa è una guida pratica ed end-to-end all'uso di Codex per UI, frontend e design system, e a come integrarlo in un flusso di lavoro di design strutturato con Open Design.", "Copre cos'è Codex oggi, perché è improvvisamente bravo nel frontend, come configurarlo da zero, il ciclo screenshot-to-UI, il round-trip ufficiale con Figma, come si confronta con Cursor e Claude Code, le insidie che fanno apparire generico l'output dell'IA e come Open Design colma il divario come layer di design aperto e local-first."], "heroImage": {"src": "/agents/codex-design/codex-design-workflow-loop.webp", "alt": "Il ciclo di feedback del design con Codex: l'agente da terminale, il browser che renderizza la UI e uno spazio di lavoro, con una freccia di feedback che ritorna", "caption": "Il ciclo centrale: Codex costruisce la UI nel terminale, la renderizza e la verifica in un browser reale e itera rispetto ai tuoi riferimenti."}, "tocLabel": "In questa pagina", "toc": [{"id": "what-is-codex", "label": "Cos'è realmente OpenAI Codex"}, {"id": "why-design", "label": "Perché ora Codex è bravo nel design"}, {"id": "setup", "label": "Configurare Codex per il design (da zero)"}, {"id": "screenshot-workflow", "label": "Il flusso di lavoro screenshot-to-UI"}, {"id": "figma", "label": "Round-trip Codex + Figma"}, {"id": "vs", "label": "Codex vs Cursor vs Claude Code"}, {"id": "pitfalls", "label": "Insidie e l'estetica da \"sbobba dell'IA\""}, {"id": "open-design", "label": "Progettare con Codex in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-codex", "heading": "Cos'è realmente OpenAI Codex (e cosa non è)", "blocks": [{"kind": "p", "text": "Prima, una disambiguazione che inganna quasi tutti quelli che cercano \"Codex\". L'originale OpenAI Codex era un modello di completamento del codice del 2021 che alimentava i primi GitHub Copilot ed è stato deprecato nel 2023. Non è di questo che parla questa pagina. Il Codex di oggi è lo strumento di coding agentico di OpenAI — pianifica, scrive, esegue e verifica codice a partire da compiti in linguaggio naturale."}, {"kind": "p", "text": "Il Codex moderno è disponibile su quattro superfici: una CLI da terminale (riscritta in Rust, con licenza Apache-2.0), un'estensione IDE per VS Code, Cursor e Windsurf, un'esperienza cloud/web per task asincroni delegati e un'app desktop con un browser integrato e Computer Use."}, {"kind": "steps", "items": [{"label": "Modello predefinito", "body": "A metà 2026 il modello raccomandato è gpt-5.5, con gpt-5.4 come modello che OpenAI ha addestrato esplicitamente per il frontend e il computer use."}, {"label": "File di istruzioni", "body": "Codex legge un file AGENTS.md nel tuo progetto (uno standard cross-tool) per le regole di progetto — il posto naturale dove codificare le tue convenzioni di design."}, {"label": "Sandbox", "body": "Gira in una sandbox a livello kernel (workspace-write di default), così un agente che modifica la tua UI non può vagare al di fuori del progetto."}]}, {"kind": "ul", "items": ["Fornitore: OpenAI", "Credenziale: chiave API OpenAI (BYOK) o abbonamento ChatGPT (Free / Go / Plus / Pro / Business / Enterprise)", "Licenza della CLI: Apache-2.0, open source"]}]}, {"id": "why-design", "heading": "Perché ora Codex è bravo nel design", "blocks": [{"kind": "p", "text": "Tre cose sono convergute all'inizio del 2026 per rendere Codex un vero strumento di design anziché un generatore di codice generico."}, {"kind": "steps", "items": [{"label": "Un modello addestrato per il frontend", "body": "OpenAI ha rilasciato GPT-5.4, il suo primo modello mainline addestrato per il frontend e il computer use, con una comprensione delle immagini molto migliore lungo tutto il flusso di design e un'auto-verifica più solida. Può persino generare mood board e opzioni visive prima di impegnarsi sugli asset finali."}, {"label": "Una skill frontend ufficiale", "body": "Il catalogo openai/skills include una skill frontend curata che impone vero gusto: layout senza card, hero a tutto schermo, gerarchia brand-first, movimento contenuto, al massimo due caratteri e un colore d'accento — e fa scrivere a Codex una tesi visiva prima di costruire."}, {"label": "Verifica nel browser", "body": "Con la skill Playwright Codex apre un browser reale, ridimensiona ai breakpoint e confronta il proprio output con il riferimento invece di limitarsi a controllare che la build passi."}]}, {"kind": "image", "src": "/agents/codex-design/codex-design-taste-triangle.webp", "alt": "Diagramma che mostra design system, skill e immagine di riferimento che convergono in un buon output di design", "caption": "Il gusto nasce da tre input che fornisci tu: un design system, una skill e immagini di riferimento reali."}, {"kind": "p", "text": "La lezione dietro tutte e tre: Codex non ha gusto di default. Produce buon design quando gli dai dei vincoli — un design system, una skill estetica e riferimenti concreti. Open Design impacchetta esattamente quegli input, ed è per questo che i due si combinano bene (più sotto)."}]}, {"id": "setup", "heading": "Configurare Codex per il lavoro di design, da zero", "blocks": [{"kind": "p", "text": "Ecco il percorso completo, da una macchina pulita a un Codex in grado di costruire e verificare la UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install the Codex CLI\nnpm install -g @openai/codex\n# or: brew install --cask codex\n# or: curl -fsSL https://chatgpt.com/codex/install.sh | sh\n\n# 2. Authenticate (ChatGPT sign-in recommended for higher limits)\ncodex            # then choose “Sign in with ChatGPT”\n\n# 3. Generate project context\ncodex            # inside your project, run /init to create AGENTS.md\n\n# 4. Add the official frontend skill, then restart Codex\n# (in the Codex app) $skill-installer frontend-skill\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\ncodex mcp add figma --url https://mcp.figma.com/mcp"}, {"kind": "image", "src": "/agents/codex-design/codex-design-setup-flow.webp", "alt": "Flusso di configurazione in cinque passi: installa, autentica, configura, installa la skill, verifica", "caption": "La sequenza di configurazione: installa → autentica → configura AGENTS.md → installa la skill frontend → abilita la verifica nel browser."}, {"kind": "steps", "items": [{"label": "Codifica le tue regole di design", "body": "Inserisci i tuoi tokens, le primitive e le convenzioni in AGENTS.md o in un DESIGN.md e indirizza Codex verso di essi, così l'output rispetta un brand invece di ripiegare su un look generico."}, {"label": "Scegli il giusto livello di ragionamento", "body": "OpenAI osserva che livelli di ragionamento da basso a medio spesso producono risultati frontend migliori rispetto all'impostazione più alta."}]}]}, {"id": "screenshot-workflow", "heading": "Il flusso di lavoro screenshot-to-UI", "blocks": [{"kind": "p", "text": "Il ciclo di design a maggior leva con Codex consiste nel trasformare un'immagine di riferimento in una UI funzionante e responsive e iterare finché non corrisponde. Le linee guida di OpenAI si distillano in cinque passi."}, {"kind": "ol", "items": ["Parti dai riferimenti visivi più chiari di cui disponi — e includi più stati (desktop e mobile, hover, vuoto, caricamento), non solo un'unica immagine hero.", "Sii specifico nel prompt; prompt vaghi producono UI generiche.", "Prepara un design system e indica a Codex dove si trovano i tokens e le primitive canoniche.", "Abilita la skill interattiva Playwright così Codex renderizza in un browser reale e ridimensiona ai breakpoint.", "Itera facendo confrontare a Codex la propria implementazione con gli screenshot — non limitarti a confermare che la build funziona."]}, {"kind": "p", "text": "Fornisci le immagini trascinando uno screenshot nel terminale o con il flag image, poi formula il prompt con vincoli concreti:"}, {"kind": "code", "lang": "bash", "code": "codex -i reference-desktop.png -i reference-mobile.png \\\n  \"Implement this design in React + Vite + Tailwind + TypeScript.\n   Reuse my existing design-system components and tokens.\n   Match spacing, layout, and hierarchy; make it responsive.\n   Use the Playwright skill to verify the UI matches the\n   references and iterate until it does.\""}, {"kind": "p", "text": "Esegui un dev server in un secondo terminale, mantieni i prompt piccoli e mirati e fai commit delle buone iterazioni / revert di quelle cattive (avvisando Codex quando fai revert) così ogni passaggio si costruisce su una base pulita."}]}, {"id": "figma", "heading": "Codex + Figma: round-trip design ↔ codice", "blocks": [{"kind": "p", "text": "Nel febbraio 2026 OpenAI e Figma hanno annunciato una partnership ufficiale, trasformando la precedente beta del Figma MCP in un'integrazione bidirezionale di prima classe. Funziona in entrambe le direzioni."}, {"kind": "steps", "items": [{"label": "Design → Codice", "body": "Copia il \"link to selection\" di un frame in Figma, incollalo in Codex con get_design_context e chiedigli di implementare il design usando la tua libreria di componenti esistente."}, {"label": "Codice → Design", "body": "Lo strumento generate_figma_design (\"Code to Canvas\") trasforma una UI live, in esecuzione, in frame Figma modificabili — l'intera schermata, un elemento selezionato o un intero file."}]}, {"kind": "p", "text": "Il Figma MCP gira come server remoto ed è esente dai rate limit. Aggiungilo una volta ed è disponibile per Codex, Claude Code, Cursor, VS Code e altri — esattamente il tipo di capacità portabile e multi-agente che Open Design è costruito per orchestrare."}]}, {"id": "vs", "heading": "Codex vs Cursor vs Claude Code per il design", "blocks": [{"kind": "p", "text": "Non c'è un unico vincitore per il lavoro di design — ogni agente ha un punto di forza diverso e i team esperti li combinano. Un riassunto equo:"}, {"kind": "table", "columns": ["Agente", "Punto di forza nel design", "Ideale per"], "rows": [["Codex", "Forte rifinitura visiva dopo GPT-5.4 + skill frontend; comprensione delle immagini", "Build asincrone delegate, esecuzioni in sandbox, regole AGENTS.md portabili"], ["Cursor", "Ciclo visivo costruisci-e-osserva con anteprima live e modifiche inline", "Lavoro di UI iterativo e a vista all'interno di un IDE"], ["Claude Code", "Decisioni di design specifiche (hex, spaziatura, tipografia) e UX consapevole della codebase", "Ragionamento frontend e refactoring a grande contesto"]]}, {"kind": "p", "text": "Il verdetto ricorrente della community è che il gusto viene dagli esseri umani: tutti e tre, senza skill, riferimenti e vincoli, ripiegano su un'estetica generica. È questo il vero problema da risolvere — ed è di forma da strumento di design, non da modello."}]}, {"id": "pitfalls", "heading": "Insidie, e come evitare l'estetica da \"sbobba dell'IA\"", "blocks": [{"kind": "p", "text": "La lamentela più comune sul design generato da Codex è che appare generico — gradienti soft, pannelli fluttuanti, angoli arrotondati esagerati, ombre drammatiche, un'aria da Inter-e-viola che \"urla che l'ha fatto un'IA\". Altri problemi segnalati includono layout mobile rotti, istruzioni che trapelano nel testo della UI e il raggiungimento rapido dei limiti d'uso."}, {"kind": "steps", "items": [{"label": "Installa una skill frontend", "body": "Una skill estetica curata costringe Codex a impegnarsi su una vera direzione invece del look predefinito."}, {"label": "Abilita la verifica con Playwright", "body": "Fai renderizzare Codex e auto-controllare sui vari breakpoint così i layout non si rompono in silenzio su mobile."}, {"label": "Fornisci tokens e riferimenti", "body": "Tokens di design reali e screenshot di riferimento sono la singola leva più grande sulla qualità dell'output."}, {"label": "Codifica le regole in AGENTS.md", "body": "Metti regole in stile \"niente hero card, al massimo due caratteri, gerarchia brand-first\" dove l'agente le legge a ogni esecuzione."}]}, {"kind": "p", "text": "Nota che ogni mitigazione consiste nel dare all'agente un contesto di design curato. Mantenere quel contesto a mano, progetto per progetto, è la fatica che Open Design elimina."}]}, {"id": "open-design", "heading": "Progettare con Codex dentro Open Design", "blocks": [{"kind": "p", "text": "Open Design è il layer di design open-source che il flusso di lavoro qui sopra continua a richiedere. Tratta Codex come un adattatore di prima parte e lo avvolge in una libreria curata di skill e design system, una pipeline di rendering strutturata e una UI desktop locale — così il contesto di design che rende bravo Codex è presente fin dalla prima esecuzione, non assemblato a mano ogni volta."}, {"kind": "ol", "items": ["Installa Open Design e seleziona Codex come tuo agente.", "Autenticati con la tua chiave API OpenAI (BYOK) o il tuo abbonamento ChatGPT — le credenziali restano sulla tua macchina e non vengono mai instradate tramite noi.", "Scegli un design system e una skill, poi genera deck, prototipi e landing page con un gusto coerente.", "Ogni artefatto e file DESIGN.md vive nella tua repo, non in un cloud ospitato."]}, {"kind": "p", "text": "Stesso agente Codex, stessa chiave — più un vero flusso di lavoro di design portabile e open-source tutt'intorno. È local-first e Apache-2.0, quindi nulla del tuo lavoro o delle tue credenziali lascia la tua macchina."}]}], "faqTitle": "Domande frequenti", "faq": [{"name": "OpenAI Codex può davvero fare lavoro di design?", "text": "Sì — con una skill frontend, un design system e immagini di riferimento reali nel contesto, Codex (specialmente su GPT-5.4) produce UI responsive di qualità da produzione e può verificarla in un browser. Senza quel contesto tende a ripiegare su un look generico, ed è il divario che Open Design colma."}, {"name": "Questo è il plugin Product Design di OpenAI Codex?", "text": "No. Open Design è un progetto open-source indipendente che integra Codex come agente. Completa gli strumenti di OpenAI con una libreria di skill e design system aperta e local-first."}, {"name": "Mi serve un abbonamento ChatGPT per progettare con Codex?", "text": "Puoi usare sia una chiave API OpenAI (BYOK) sia il tuo abbonamento ChatGPT. L'accesso con ChatGPT in genere offre limiti più generosi; in ogni caso Open Design non instrada mai le tue credenziali."}, {"name": "Codex o Claude Code per il design frontend?", "text": "Entrambi sono forti. Claude Code è noto per decisioni di design specifiche e consapevoli della codebase; Codex ha una forte rifinitura visiva dopo GPT-5.4 ed eccelle nelle build delegate e in sandbox. Molti team usano entrambi — Open Design ti permette di cambiare agente senza modificare il tuo flusso di lavoro di design."}, {"name": "Come collego Codex a Figma?", "text": "Aggiungi il server Figma MCP ufficiale (codex mcp add figma --url https://mcp.figma.com/mcp). Potrai poi implementare i frame di Figma in codice con get_design_context e riportare una UI in esecuzione verso frame Figma modificabili con generate_figma_design."}, {"name": "Come evito l'estetica generica da \"sbobba dell'IA\"?", "text": "Installa una skill frontend, fornisci tokens di design reali e screenshot di riferimento, codifica le regole del brand in AGENTS.md e abilita la verifica con Playwright. Open Design li include come libreria curata, così salti la configurazione progetto per progetto."}, {"name": "Open Design è affiliato a OpenAI?", "text": "No. Codex è un prodotto di OpenAI; Open Design è un progetto open-source indipendente che lo supporta come adattatore di prima parte. OpenAI e Codex sono marchi di OpenAI."}, {"name": "I miei file e le mie credenziali sono al sicuro?", "text": "Sì — Open Design è local-first. I tuoi file, gli artefatti e DESIGN.md restano nella tua repo, e le tue credenziali OpenAI vengono usate direttamente dal tuo agente, mai instradate attraverso i server di Open Design."}], "ctaTitle": "Progetta con Codex, in modo aperto.", "ctaBody": "Porta la tua chiave OpenAI, mantieni ogni file in locale e ottieni una libreria di design curata intorno all'agente che già usi.", "ctaActions": [{"label": "Usa Codex dentro Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Metti una stella su GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Scarica l'app desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Vedi tutti gli agenti supportati"},
      },
      'cursor': {
        ...en['cursor']!,
        title: "Cursor per i designer — Open Design",
        description: "Come i designer usano Cursor per il design di UI e web — Design Mode, da Figma a codice, il Figma MCP — e come Open Design trasforma Cursor in un agente di design open-source e local-first.",
        breadcrumb: "Cursor Agent",
        label: "Agente · Cursor",
        heading: "Cursor per i designer.",
        lead: "Cursor è l'editor di codice IA, ora con una Design Mode visiva. I designer lo usano per modificare la UI puntando e disegnando, e per trasformare Figma in codice. Open Design collega Cursor Agent a un flusso di lavoro di design open-source che mantiene i tuoi file in locale.",
        rich: {"heroCtaLead": "Open Design trasforma Cursor in un agente di design open-source e local-first — il tuo account Cursor o le tue chiavi di modello, i tuoi file, una libreria curata di skill e design system tutt'intorno.", "heroCtaActions": [{"label": "Usa Cursor dentro Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Metti una stella su GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Scarica l'app desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Cursor è l'editor di codice AI-first che ha reso \"costruiscilo e guardalo renderizzare\" il modo predefinito di rilasciare UI. Con la modalità Agent, le modifiche inline, un'anteprima nell'editor e Figma tramite MCP, è diventato un vero strumento di design — una volta che gli fornisci i riferimenti giusti, le regole e un ciclo di verifica. Questa è una guida pratica ed end-to-end all'uso di Cursor per UI, frontend e design system, e a come integrarlo in un flusso di lavoro di design strutturato con Open Design.", "Copre cos'è realmente Cursor, perché il suo stretto ciclo itera-e-osserva è adatto al design, come configurarlo da zero, il ciclo screenshot-e-anteprima-to-UI, il round-trip con Figma tramite MCP, come si confronta con Codex e Claude Code, le insidie che fanno apparire generico l'output dell'IA e come Open Design colma il divario come layer di design aperto e local-first."], "heroImage": {"src": "/agents/cursor-design/cursor-design-hero.webp", "alt": "La convergenza del design con Cursor: l'editor a sinistra, un hub curato di skill e design system al centro con il marchio Cursor al centro, e una UI renderizzata a destra", "caption": "L'idea centrale: Cursor modifica e renderizza la UI nell'editor, mentre un hub di design curato gli fornisce il sistema, le skill e i riferimenti che fanno apparire intenzionale l'output."}, "tocLabel": "In questa pagina", "toc": [{"id": "what-is-cursor", "label": "Cos'è realmente Cursor"}, {"id": "why-design", "label": "Perché Cursor è bravo nel design"}, {"id": "setup", "label": "Configurare Cursor per il design (da zero)"}, {"id": "preview-workflow", "label": "Il flusso di lavoro anteprima-to-UI"}, {"id": "figma", "label": "Cursor + Figma tramite MCP"}, {"id": "vs", "label": "Cursor vs Codex vs Claude Code"}, {"id": "pitfalls", "label": "Insidie e l'estetica da \"sbobba dell'IA\""}, {"id": "open-design", "label": "Progettare con Cursor in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-cursor", "heading": "Cos'è realmente Cursor", "blocks": [{"kind": "p", "text": "Cursor è un editor di codice AI-first costruito da Anysphere. È un fork di VS Code, quindi conserva l'editor, le estensioni e le scorciatoie da tastiera familiari, ma ricostruisce il flusso di lavoro attorno a un agente IA capace di leggere l'intero progetto, modificare più file, eseguire comandi e iterare con te nel ciclo."}, {"kind": "p", "text": "Per il lavoro di design le superfici importanti sono la modalità Agent (descrivi un risultato e Cursor pianifica e modifica attraverso i file), le modifiche inline e i completamenti Tab per aggiustamenti rapidi, un'anteprima / browser nell'editor così puoi vedere la UI in esecuzione senza lasciare la finestra, e il supporto MCP che gli permette di attingere a contesto esterno come un file Figma live."}, {"kind": "steps", "items": [{"label": "Regole di progetto", "body": "Cursor legge file di istruzioni di progetto — regole `.mdc` versionate sotto `.cursor/rules`, e un semplice `AGENTS.md` — così puoi codificare le tue convenzioni di design dove l'agente le legge a ogni esecuzione."}, {"label": "Modelli", "body": "Cursor è flessibile sui modelli: include modelli di frontiera tramite il tuo abbonamento e supporta anche l'uso delle tue chiavi di modello, così scegli il motore dietro lo stesso flusso di lavoro dell'editor."}, {"label": "MCP", "body": "Parla il Model Context Protocol, così i server esterni — il più rilevante è il server Figma MCP — diventano contesto di prima classe per l'agente."}]}, {"kind": "ul", "items": ["Fornitore: Anysphere", "Credenziale: account / abbonamento Cursor (Hobby / Pro / Business) o le tue chiavi di modello (BYOK)", "Forma: editor di codice AI-first (fork di VS Code) con agente e anteprima nell'editor"]}]}, {"id": "why-design", "heading": "Perché Cursor è bravo nel design", "blocks": [{"kind": "p", "text": "Il vantaggio di Cursor nel design non è una singola funzionalità — è la strettezza del ciclo costruisci-e-osserva. Tre cose lo fanno sembrare uno strumento di design anziché un generatore di codice generico."}, {"kind": "steps", "items": [{"label": "Uno stretto ciclo itera-e-osserva", "body": "Tu dai il prompt, Cursor modifica attraverso i file e l'anteprima nell'editor renderizza il risultato immediatamente — così aggiusti spaziatura, gerarchia e movimento in secondi invece di fare avanti e indietro tra un terminale e un browser separati."}, {"label": "Editing visivo diretto", "body": "Oltre alla chat, Cursor ti permette di selezionare elementi nell'anteprima e ritoccare gli stili, così le piccole correzioni visive sembrano modifiche di design piuttosto che archeologia del codice."}, {"label": "Regole di progetto e contesto MCP", "body": "Con `.cursor/rules` (o `AGENTS.md`) e il server Figma MCP, l'agente lavora rispetto ai tuoi tokens, componenti e specifiche di design reali invece di tirare a indovinare."}]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-taste-triangle.webp", "alt": "Diagramma che mostra design system, skill e immagine di riferimento che convergono in un buon output di design", "caption": "Il gusto nasce da tre input che fornisci tu: un design system, una skill e immagini di riferimento reali."}, {"kind": "p", "text": "La lezione è la stessa che insegna ogni agente: Cursor non ha gusto di default. Produce buon design quando gli dai dei vincoli — un design system, una skill estetica e riferimenti concreti. Open Design impacchetta esattamente quegli input, ed è per questo che i due si combinano bene (più sotto)."}]}, {"id": "setup", "heading": "Configurare Cursor per il lavoro di design, da zero", "blocks": [{"kind": "p", "text": "Ecco il percorso completo, da una macchina pulita a un Cursor in grado di costruire, visualizzare in anteprima e verificare la UI rispetto al tuo design system."}, {"kind": "ol", "items": ["Installa Cursor da cursor.com e accedi con il tuo account Cursor, oppure configura le tue chiavi di modello (BYOK) nelle Impostazioni.", "Apri il tuo progetto e scegli un modello nel pannello chat / Agent.", "Aggiungi regole di progetto: crea `.cursor/rules/*.mdc` per convenzioni strutturate e con ambito glob, oppure un semplice `AGENTS.md` per istruzioni semplici e leggibili.", "Connetti il server Figma MCP (opzionale) così l'agente può leggere il contesto di design live.", "Esegui il tuo dev server e usa l'anteprima nell'editor per vedere e verificare la UI mentre iteri."]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-setup-flow.webp", "alt": "Flusso di configurazione in cinque passi: installa, autentica, configura le regole, aggiungi la skill, verifica", "caption": "La sequenza di configurazione: installa → autentica → configura le regole di progetto → aggiungi una skill → abilita la verifica in anteprima."}, {"kind": "p", "text": "Un file di regole di progetto minimale fa progettare l'agente verso un brand invece di ripiegare su un look generico. Mettilo dove Cursor lo legge a ogni esecuzione:"}, {"kind": "code", "lang": "markdown", "code": "# .cursor/rules/design.mdc\n---\ndescription: Project design conventions\nalwaysApply: true\n---\n\n- Reuse existing design-system tokens and components; never hardcode hex or spacing.\n- At most two typefaces and one accent color.\n- Brand-first hierarchy; restrained motion. No hero cards, no oversized rounded corners.\n- Build responsive by default; verify desktop and mobile in the preview before finishing."}, {"kind": "steps", "items": [{"label": "Codifica le tue regole di design", "body": "Inserisci i tuoi tokens, le primitive e le convenzioni in `.cursor/rules` o `AGENTS.md` e indirizza Cursor verso di essi, così l'output rispetta un brand invece di ripiegare su un look generico."}, {"label": "Mantieni i prompt piccoli", "body": "Lo stretto ciclo di Cursor premia le richieste mirate — itera un componente o uno stato alla volta e osserva l'anteprima tra un passaggio e l'altro."}]}]}, {"id": "preview-workflow", "heading": "Il flusso di lavoro anteprima-to-UI", "blocks": [{"kind": "p", "text": "Il ciclo di design a maggior leva con Cursor consiste nel trasformare un riferimento in una UI funzionante e responsive e iterare nell'editor finché non corrisponde — guardando l'anteprima live per tutto il tempo invece di tirare a indovinare."}, {"kind": "ol", "items": ["Parti dai riferimenti visivi più chiari di cui disponi — e includi più stati (desktop e mobile, hover, vuoto, caricamento), non solo un'unica immagine hero.", "Sii specifico nel prompt; prompt vaghi producono UI generiche.", "Prepara un design system e indica a Cursor dove si trovano i tokens e le primitive canoniche.", "Tieni aperta l'anteprima nell'editor e in esecuzione il tuo dev server così ogni modifica renderizza immediatamente ai breakpoint che ti interessano.", "Itera confrontando la UI renderizzata con i riferimenti — e usa la selezione diretta degli elementi nell'anteprima per piccole correzioni visive."]}, {"kind": "p", "text": "Fornisci i riferimenti allegando un'immagine alla chat, poi formula il prompt con vincoli concreti:"}, {"kind": "code", "lang": "text", "code": "Implement this design in React + Vite + Tailwind + TypeScript.\nReuse my existing design-system components and tokens.\nMatch spacing, layout, and hierarchy; make it responsive.\nKeep the preview open — verify desktop and mobile match the\nreferences and iterate until they do."}, {"kind": "p", "text": "Fai commit delle buone iterazioni e revert di quelle cattive (avvisando Cursor quando fai revert) così ogni passaggio si costruisce su una base pulita — la stessa disciplina che impedisce a qualsiasi ciclo di agente di andare alla deriva."}]}, {"id": "figma", "heading": "Cursor + Figma: design ↔ codice tramite MCP", "blocks": [{"kind": "p", "text": "Cursor si connette a Figma attraverso il server Figma MCP ufficiale, che dà all'agente accesso strutturato a un file Figma live invece di uno screenshot piatto. Questo elimina le congetture dall'handoff."}, {"kind": "steps", "items": [{"label": "Design → Codice", "body": "Copia il link di un frame in Figma, incollalo in Cursor e chiedigli di implementare il design. Il server MCP espone contesto di design reale — componenti, variabili, dati di layout, tokens — così il codice generato corrisponde alla sorgente invece di approssimarla."}, {"label": "Resta allineato", "body": "Con tokens di design, stili e componenti usati in modo coerente in Figma (e Code Connect dove disponibile), l'output di Cursor resta mappato sul tuo design system reale anziché reinventare le primitive."}]}, {"kind": "p", "text": "Configura il server Figma MCP remoto una volta ed è disponibile per Cursor come contesto di prima classe. Poiché MCP è uno standard aperto, lo stesso server è riutilizzabile su Cursor, Claude Code, Codex e VS Code — esattamente il tipo di capacità portabile e multi-agente che Open Design è costruito per orchestrare."}]}, {"id": "vs", "heading": "Cursor vs Codex vs Claude Code per il design", "blocks": [{"kind": "p", "text": "Non c'è un unico vincitore per il lavoro di design — ogni agente ha un punto di forza diverso e i team esperti li combinano. Un riassunto equo:"}, {"kind": "table", "columns": ["Agente", "Punto di forza nel design", "Ideale per"], "rows": [["Cursor", "Ciclo visivo costruisci-e-osserva con anteprima live nell'editor e editing diretto degli elementi", "Lavoro di UI iterativo e a vista all'interno di un IDE"], ["Codex", "Forte rifinitura visiva con una skill frontend; comprensione delle immagini ed esecuzioni in sandbox", "Build asincrone delegate e regole AGENTS.md portabili"], ["Claude Code", "Decisioni di design specifiche (hex, spaziatura, tipografia) e UX consapevole della codebase", "Ragionamento frontend e refactoring a grande contesto"]]}, {"kind": "p", "text": "Il verdetto ricorrente della community è che il gusto viene dagli esseri umani: tutti e tre, senza skill, riferimenti e vincoli, ripiegano su un'estetica generica. È questo il vero problema da risolvere — ed è di forma da strumento di design, non da modello."}]}, {"id": "pitfalls", "heading": "Insidie, e come evitare l'estetica da \"sbobba dell'IA\"", "blocks": [{"kind": "p", "text": "La lamentela più comune sul design generato da Cursor è che appare generico — gradienti soft, pannelli fluttuanti, angoli arrotondati esagerati, ombre drammatiche, un'aria da Inter-e-viola che \"urla che l'ha fatto un'IA\". Altri problemi segnalati includono layout che si rompono su mobile e istruzioni che trapelano nel testo della UI."}, {"kind": "steps", "items": [{"label": "Aggiungi una skill di design", "body": "Una skill estetica curata costringe Cursor a impegnarsi su una vera direzione invece del look predefinito."}, {"label": "Usa l'anteprima per verificare", "body": "Renderizza e auto-controlla sui vari breakpoint nell'anteprima nell'editor così i layout non si rompono in silenzio su mobile."}, {"label": "Fornisci tokens e riferimenti", "body": "Tokens di design reali e screenshot di riferimento sono la singola leva più grande sulla qualità dell'output."}, {"label": "Codifica le regole in `.cursor/rules`", "body": "Metti regole in stile \"niente hero card, al massimo due caratteri, gerarchia brand-first\" dove l'agente le legge a ogni esecuzione."}]}, {"kind": "p", "text": "Nota che ogni mitigazione consiste nel dare all'agente un contesto di design curato. Mantenere quel contesto a mano, progetto per progetto, è la fatica che Open Design elimina."}]}, {"id": "open-design", "heading": "Progettare con Cursor dentro Open Design", "blocks": [{"kind": "p", "text": "Open Design è il layer di design open-source che il flusso di lavoro qui sopra continua a richiedere. Tratta Cursor come un adattatore di prima parte e lo avvolge in una libreria curata di skill e design system, una pipeline di rendering strutturata e una UI desktop locale — così il contesto di design che rende bravo Cursor è presente fin dalla prima esecuzione, non assemblato a mano ogni volta."}, {"kind": "ol", "items": ["Installa Open Design e seleziona Cursor come tuo agente.", "Autenticati con il tuo account Cursor o le tue chiavi di modello (BYOK) — le credenziali restano sulla tua macchina e non vengono mai instradate tramite noi.", "Scegli un design system e una skill, poi genera deck, prototipi e landing page con un gusto coerente.", "Ogni artefatto e file DESIGN.md vive nella tua repo, non in un cloud ospitato."]}, {"kind": "p", "text": "Stesso agente Cursor, stessa chiave — più un vero flusso di lavoro di design portabile e open-source tutt'intorno. È local-first e Apache-2.0, quindi nulla del tuo lavoro o delle tue credenziali lascia la tua macchina."}]}], "faqTitle": "Domande frequenti", "faq": [{"name": "Cursor può davvero fare lavoro di design?", "text": "Sì — con una skill di design, un design system e immagini di riferimento reali nel contesto, Cursor produce UI responsive di qualità da produzione, e la sua anteprima nell'editor ti permette di verificarla e rifinirla visivamente. Senza quel contesto tende a ripiegare su un look generico, ed è il divario che Open Design colma."}, {"name": "Questo è un prodotto Cursor ufficiale?", "text": "No. Open Design è un progetto open-source indipendente che integra Cursor come agente. Completa Cursor con una libreria di skill e design system aperta e local-first."}, {"name": "Mi serve un abbonamento Cursor per progettare con Cursor?", "text": "Puoi usare un account / abbonamento Cursor oppure portare le tue chiavi di modello (BYOK). In ogni caso Open Design non instrada mai le tue credenziali — vengono usate direttamente dal tuo agente."}, {"name": "Cursor o Claude Code per il design frontend?", "text": "Entrambi sono forti. Claude Code è noto per decisioni di design specifiche e consapevoli della codebase; il vantaggio di Cursor è il suo stretto ciclo costruisci-e-osserva con un'anteprima live dentro l'editor. Molti team usano entrambi — Open Design ti permette di cambiare agente senza modificare il tuo flusso di lavoro di design."}, {"name": "Come collego Cursor a Figma?", "text": "Aggiungi il server Figma MCP ufficiale in Cursor, poi incolla il link di un frame Figma nella chat e chiedi a Cursor di implementarlo. Il server espone componenti, variabili e dati di layout reali così il codice generato corrisponde al design sorgente."}, {"name": "Come evito l'estetica generica da \"sbobba dell'IA\"?", "text": "Aggiungi una skill di design, fornisci tokens di design reali e screenshot di riferimento, codifica le regole del brand in `.cursor/rules` o `AGENTS.md`, e verifica sui vari breakpoint nell'anteprima. Open Design li include come libreria curata, così salti la configurazione progetto per progetto."}, {"name": "Open Design è affiliato a Cursor o Anysphere?", "text": "No. Cursor è un prodotto di Anysphere; Open Design è un progetto open-source indipendente che lo supporta come adattatore di prima parte. Cursor e Anysphere sono marchi di Anysphere, Inc."}, {"name": "I miei file e le mie credenziali sono al sicuro?", "text": "Sì — Open Design è local-first. I tuoi file, gli artefatti e DESIGN.md restano nella tua repo, e le tue credenziali Cursor o di modello vengono usate direttamente dal tuo agente, mai instradate attraverso i server di Open Design."}], "ctaTitle": "Progetta con Cursor, in modo aperto.", "ctaBody": "Porta il tuo account Cursor o le tue chiavi di modello, mantieni ogni file in locale e ottieni una libreria di design curata intorno all'agente che già usi.", "ctaActions": [{"label": "Usa Cursor dentro Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Metti una stella su GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Scarica l'app desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Vedi tutti gli agenti supportati"},
      },
      'opencode': {
        ...en['opencode']!,
        title: "OpenCode per il design — crea UI con l’agente open-source",
        description: "Come progettare UI e frontend con OpenCode — file design.md, skill UI/UX, il Figma MCP — e come Open Design trasforma OpenCode in un agente di design gratuito, local-first e open-source.",
        breadcrumb: "OpenCode",
        label: "Agente · OpenCode",
        heading: "OpenCode per il design.",
        lead: "OpenCode è l'agente di coding IA da terminale open-source. I designer vi aggiungono skill di design e file DESIGN.md per generare UI reali. Open Design ne fa un flusso di lavoro strutturato e open-source — porta le chiavi dei tuoi provider, mantieni tutto in locale.",
        rich: {"heroCtaLead": "Open Design trasforma OpenCode in un agente di design open-source e local-first — qualsiasi modello tu scelga con la tua chiave di provider, i tuoi file, una libreria curata di skill e design system tutt'intorno.", "heroCtaActions": [{"label": "Usa OpenCode dentro Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Metti una stella su GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Scarica l'app desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["OpenCode è un agente di coding IA open-source e terminal-first deliberatamente agnostico rispetto al modello: porti la tua chiave di provider ed esegui qualunque modello vuoi dietro lo stesso flusso di lavoro. Questa apertura ne fa una base naturale per il lavoro di design — ma, come ogni agente, produce buona UI solo quando gli fornisci i riferimenti giusti, le skill e un ciclo di verifica. Questa è una guida pratica ed end-to-end all'uso di OpenCode per UI, frontend e design system, e a come integrarlo in un flusso di lavoro di design strutturato con Open Design.", "Copre cos'è realmente OpenCode, perché un agente aperto e agnostico rispetto al modello è adatto al design, come configurarlo da zero, il ciclo screenshot-to-UI, come AGENTS.md e MCP lo estendono, come si confronta con Codex, Claude Code e Cursor, le insidie che fanno apparire generico l'output dell'IA e come Open Design colma il divario come layer di design aperto e local-first — un abbinamento naturale, dato che entrambi i progetti sono open-source e girano sulla tua macchina."], "heroImage": {"src": "/agents/opencode-design/opencode-design-hero.webp", "alt": "Il ciclo di feedback del design con OpenCode: un agente TUI da terminale, un browser che renderizza la UI e uno spazio di lavoro, con una freccia di feedback che ritorna", "caption": "Il ciclo centrale: OpenCode costruisce la UI nel terminale, la renderizza e la verifica in un browser reale e itera rispetto ai tuoi riferimenti — su qualsiasi modello tu scelga."}, "tocLabel": "In questa pagina", "toc": [{"id": "what-is-opencode", "label": "Cos'è realmente OpenCode"}, {"id": "why-design", "label": "Perché un agente aperto e con qualsiasi modello è adatto al design"}, {"id": "setup", "label": "Configurare OpenCode per il design (da zero)"}, {"id": "screenshot-workflow", "label": "Il flusso di lavoro screenshot-to-UI"}, {"id": "extend", "label": "AGENTS.md, MCP e sessioni condivisibili"}, {"id": "vs", "label": "OpenCode vs Codex vs Claude Code vs Cursor"}, {"id": "pitfalls", "label": "Insidie e l'estetica da \"sbobba dell'IA\""}, {"id": "open-design", "label": "Progettare con OpenCode in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-opencode", "heading": "Cos'è realmente OpenCode", "blocks": [{"kind": "p", "text": "OpenCode è un agente di coding IA open-source costruito per il terminale, mantenuto dal team dietro SST (Anomaly Innovations). Legge la tua repository, esegue comandi, modifica file e parla con un modello linguistico di grandi dimensioni — ma, a differenza degli agenti legati a un fornitore, non include un proprio modello. Lo punti verso qualunque provider e modello vuoi e porti la tua chiave."}, {"kind": "p", "text": "Gira come UI da terminale (TUI), con un'app desktop ed estensioni IDE sopra lo stesso motore. Sotto il cofano usa un'architettura client/server, così l'agente che fa il lavoro è disaccoppiato dalla superficie da cui lo guidi. Due agenti integrati — build e plan — si alternano con il tasto Tab."}, {"kind": "steps", "items": [{"label": "Agnostico rispetto al modello", "body": "Modelli e provider provengono da models.dev, un catalogo aperto. Li configuri in opencode.json con una stringa provider/model-id e puoi disabilitare i provider che non vuoi caricare — così lo stesso flusso di lavoro di design gira su Anthropic, OpenAI, Google, OpenRouter, modelli locali e altro."}, {"label": "File di istruzioni", "body": "OpenCode legge un file AGENTS.md nel tuo progetto (lo standard cross-tool, compatibile anche con CLAUDE.md) per le regole di progetto — il posto naturale dove codificare le tue convenzioni di design. Esegui /init per generarne uno."}, {"label": "Estendibile", "body": "Supporta l'integrazione LSP, i server MCP, i temi, le scorciatoie da tastiera e i comandi personalizzati, oltre a link di sessione condivisibili per la collaborazione."}]}, {"kind": "ul", "items": ["Manutentore: SST / Anomaly Innovations (progetto open-source)", "Credenziale: la/le tua/e chiave/i API di provider di modello — BYOK, senza vincoli di fornitore", "Licenza: MIT, open source"]}]}, {"id": "why-design", "heading": "Perché un agente aperto e con qualsiasi modello è adatto al lavoro di design", "blocks": [{"kind": "p", "text": "OpenCode non ha un singolo \"modello di design\" come ce l'ha un agente di fornitore — ed è proprio il punto. Poiché è agnostico rispetto al modello e aperto, puoi eseguire lo stesso flusso di lavoro di design su qualsiasi modello sia attualmente il migliore nel frontend, cambiarlo in seguito o ripiegare su un modello locale, tutto senza modificare la tua configurazione."}, {"kind": "p", "text": "Ma la scelta del modello da sola non compra il gusto. Come ogni agente di coding, OpenCode produce UI generiche a meno che non gli dia dei vincoli. Un buon output di design nasce da tre input che fornisci tu."}, {"kind": "steps", "items": [{"label": "Un design system", "body": "Tokens, primitive e convenzioni reali che l'agente riutilizza, così l'output rispetta un brand invece di ripiegare su un look generico."}, {"label": "Una skill estetica", "body": "Una skill curata che impone vero gusto — movimento contenuto, gerarchia brand-first, al massimo due caratteri e un colore d'accento — e fa impegnare l'agente su una direzione prima di costruire."}, {"label": "Riferimenti concreti", "body": "Immagini di riferimento reali e più stati (desktop e mobile, hover, vuoto, caricamento), non una singola immagine hero."}]}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-taste-triangle.webp", "alt": "Diagramma che mostra design system, skill e immagine di riferimento che convergono in un buon output di design", "caption": "Il gusto nasce da tre input che fornisci tu: un design system, una skill e immagini di riferimento reali — indipendentemente da quale modello esegui."}, {"kind": "p", "text": "La lezione: OpenCode ti dà libertà di modello, ma il gusto continua a nascere da un contesto di design curato. Open Design impacchetta esattamente quegli input, ed è per questo che i due si combinano bene — entrambi sono open-source e local-first (più sotto)."}]}, {"id": "setup", "heading": "Configurare OpenCode per il lavoro di design, da zero", "blocks": [{"kind": "p", "text": "Ecco il percorso completo, da una macchina pulita a un OpenCode in grado di costruire e verificare la UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install OpenCode\ncurl -fsSL https://opencode.ai/install | bash\n# or: npm i -g opencode-ai@latest\n# or: brew install sst/tap/opencode\n\n# 2. Start the TUI in your project, then authenticate your provider\nopencode          # then run /login and pick your provider + paste your key\n\n# 3. Generate project context\nopencode          # inside your project, run /init to create AGENTS.md\n\n# 4. Pick your model (any provider, via models.dev)\n#    set \"provider/model-id\" in opencode.json or switch in the TUI\n\n# 5. Add an MCP server (optional, e.g. for design handoff)\n#    configure it under the \"mcp\" key in opencode.json"}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-setup-flow.webp", "alt": "Flusso di configurazione in cinque passi: installa, autentica con la tua chiave di provider, configura AGENTS.md, aggiungi una skill, verifica", "caption": "La sequenza di configurazione: installa → autentica (la tua chiave di provider) → configura AGENTS.md → aggiungi una skill → verifica in un browser reale."}, {"kind": "steps", "items": [{"label": "Codifica le tue regole di design", "body": "Inserisci i tuoi tokens, le primitive e le convenzioni in AGENTS.md (o in un DESIGN.md richiamato da esso) così l'output rispetta un brand invece di ripiegare su un look generico. L'opzione instructions in opencode.json può puntare a file di regole aggiuntivi tramite glob."}, {"label": "Scegli un modello capace", "body": "Poiché OpenCode è agnostico rispetto al modello, scegli quale provider/modello sia attualmente il più forte nel frontend per il passaggio di design — e mantieni invariato il resto del tuo flusso di lavoro."}]}]}, {"id": "screenshot-workflow", "heading": "Il flusso di lavoro screenshot-to-UI", "blocks": [{"kind": "p", "text": "Il ciclo di design a maggior leva con qualsiasi agente consiste nel trasformare un'immagine di riferimento in una UI funzionante e responsive e iterare finché non corrisponde. La stessa struttura in cinque passi vale in OpenCode."}, {"kind": "ol", "items": ["Parti dai riferimenti visivi più chiari di cui disponi — e includi più stati (desktop e mobile, hover, vuoto, caricamento), non solo un'unica immagine hero.", "Sii specifico nel prompt; prompt vaghi producono UI generiche.", "Prepara un design system e indica a OpenCode dove si trovano i tokens e le primitive canoniche (in AGENTS.md).", "Esegui un dev server e fai renderizzare l'agente in un browser reale, ridimensionando ai breakpoint per controllare il risultato.", "Itera facendo confrontare a OpenCode la propria implementazione con gli screenshot — non limitarti a confermare che la build funziona."]}, {"kind": "p", "text": "Richiama i file con @ nella TUI per una ricerca fuzzy della tua directory di lavoro, esegui comandi shell inline con un ! iniziale e guida le azioni con i comandi /. Poi formula il prompt con vincoli concreti:"}, {"kind": "code", "lang": "bash", "code": "opencode\n# in the TUI:\n> @reference-desktop.png @reference-mobile.png\n  Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from AGENTS.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Run the dev server, open it in a browser, and iterate until the\n  UI matches the references across breakpoints."}, {"kind": "p", "text": "Mantieni i prompt piccoli e mirati, fai commit delle buone iterazioni e revert di quelle cattive (avvisando OpenCode quando fai revert), così ogni passaggio si costruisce su una base pulita."}]}, {"id": "extend", "heading": "AGENTS.md, MCP e sessioni condivisibili", "blocks": [{"kind": "p", "text": "Tre punti di estensione rendono OpenCode pratico per il lavoro di design prolungato, e tutti e tre si mappano in modo pulito su un flusso di lavoro di design aperto."}, {"kind": "steps", "items": [{"label": "Regole AGENTS.md", "body": "Le regole di progetto vivono in un AGENTS.md nella root della repo (o regole globali in ~/.config/opencode/AGENTS.md). È la casa duratura per le tue convenzioni di design, letta a ogni esecuzione, ed è compatibile con i file CLAUDE.md usati da altri agenti."}, {"label": "Server MCP", "body": "OpenCode supporta server MCP sia locali (command) sia remoti (URL), configurati sotto la chiave mcp — il modo portabile per portare contesto di design e strumenti esterni che funzionano su più agenti, non solo OpenCode."}, {"label": "Sessioni condivisibili", "body": "Il comando /share crea un link pubblico a una conversazione per collaborazione o revisione, e /unshare lo revoca — utile per ottenere feedback su un passaggio di design."}]}, {"kind": "p", "text": "Queste sono capacità portabili e multi-agente — esattamente il tipo di cosa che Open Design è costruito per orchestrare, invece di ricrearla progetto per progetto."}]}, {"id": "vs", "heading": "OpenCode vs Codex vs Claude Code vs Cursor per il design", "blocks": [{"kind": "p", "text": "Non c'è un unico vincitore per il lavoro di design — ogni agente ha un punto di forza diverso e i team esperti li combinano. Un riassunto equo:"}, {"kind": "table", "columns": ["Agente", "Punto di forza nel design", "Ideale per"], "rows": [["OpenCode", "Open-source e agnostico rispetto al modello; esegui qualsiasi provider dietro un unico flusso di lavoro da terminale", "Libertà BYOK, cambio di modello, configurazioni completamente aperte e local-first"], ["Codex", "Forte rifinitura visiva con una skill frontend; comprensione delle immagini", "Asincrono delegato, build in sandbox, regole AGENTS.md portabili"], ["Claude Code", "Decisioni di design specifiche (hex, spaziatura, tipografia) e UX consapevole della codebase", "Ragionamento frontend e refactoring a grande contesto"], ["Cursor", "Ciclo visivo costruisci-e-osserva con anteprima live e modifiche inline", "Lavoro di UI iterativo e a vista all'interno di un IDE"]]}, {"kind": "p", "text": "Il verdetto ricorrente della community è che il gusto viene dagli esseri umani: tutti, senza skill, riferimenti e vincoli, ripiegano su un'estetica generica. È questo il vero problema da risolvere — ed è di forma da strumento di design, non da modello, ed è precisamente per questo che un agente aperto come OpenCode si abbina così bene a un layer di design aperto."}]}, {"id": "pitfalls", "heading": "Insidie, e come evitare l'estetica da \"sbobba dell'IA\"", "blocks": [{"kind": "p", "text": "La lamentela più comune sul design generato dall'IA è che appare generico — gradienti soft, pannelli fluttuanti, angoli arrotondati esagerati, ombre drammatiche, un'aria da Inter-e-viola che \"urla che l'ha fatto un'IA\". Altri problemi segnalati includono layout mobile rotti e istruzioni che trapelano nel testo della UI. Nessuno di questi è esclusivo di OpenCode; sono ciò che accade quando qualsiasi agente gira senza un contesto di design curato."}, {"kind": "steps", "items": [{"label": "Aggiungi una skill estetica", "body": "Una skill di design curata costringe l'agente a impegnarsi su una vera direzione invece del look predefinito."}, {"label": "Verifica in un browser reale", "body": "Renderizza e auto-controlla sui vari breakpoint così i layout non si rompono in silenzio su mobile."}, {"label": "Fornisci tokens e riferimenti", "body": "Tokens di design reali e screenshot di riferimento sono la singola leva più grande sulla qualità dell'output."}, {"label": "Codifica le regole in AGENTS.md", "body": "Metti regole in stile \"niente hero card, al massimo due caratteri, gerarchia brand-first\" dove l'agente le legge a ogni esecuzione."}]}, {"kind": "p", "text": "Nota che ogni mitigazione consiste nel dare all'agente un contesto di design curato — indipendentemente da quale modello esegui. Mantenere quel contesto a mano, progetto per progetto, è la fatica che Open Design elimina."}]}, {"id": "open-design", "heading": "Progettare con OpenCode dentro Open Design", "blocks": [{"kind": "p", "text": "Open Design è il layer di design open-source che il flusso di lavoro qui sopra continua a richiedere. Tratta OpenCode come un adattatore di prima parte e lo avvolge in una libreria curata di skill e design system, una pipeline di rendering strutturata e una UI desktop locale — così il contesto di design che rende bravo qualsiasi agente è presente fin dalla prima esecuzione, non assemblato a mano ogni volta. Entrambi i progetti sono open-source e local-first, il che rende l'abbinamento un'unione naturale."}, {"kind": "ol", "items": ["Installa Open Design e seleziona OpenCode come tuo agente.", "Autenticati con la tua chiave API di provider di modello (BYOK) — le credenziali restano sulla tua macchina e non vengono mai instradate tramite noi.", "Scegli qualsiasi provider e modello, più un design system e una skill, poi genera deck, prototipi e landing page con un gusto coerente.", "Ogni artefatto e file DESIGN.md vive nella tua repo, non in un cloud ospitato."]}, {"kind": "p", "text": "Stesso agente OpenCode, stessa libertà di modello — più un vero flusso di lavoro di design portabile e open-source tutt'intorno. È local-first e Apache-2.0, quindi nulla del tuo lavoro o delle tue credenziali lascia la tua macchina."}]}], "faqTitle": "Domande frequenti", "faq": [{"name": "OpenCode può davvero fare lavoro di design?", "text": "Sì — con una skill estetica, un design system e immagini di riferimento reali nel contesto, OpenCode produce UI responsive di qualità da produzione e può verificarla in un browser. Poiché è agnostico rispetto al modello, esegui qualsiasi modello sia attualmente il migliore nel frontend. Senza quel contesto curato tende a ripiegare su un look generico, ed è il divario che Open Design colma."}, {"name": "Quale modello dovrei usare con OpenCode per il design?", "text": "Quello che preferisci — OpenCode è agnostico rispetto al provider tramite models.dev, così puoi eseguire Anthropic, OpenAI, Google, OpenRouter o modelli locali dietro lo stesso flusso di lavoro e cambiarli in qualsiasi momento. La qualità dell'output di design dipende molto più dalla tua skill, dal tuo design system e dai tuoi riferimenti che dal modello da solo."}, {"name": "Open Design è realizzato dal team di OpenCode (SST)?", "text": "No. Open Design è un progetto open-source indipendente che integra OpenCode come agente. Completa OpenCode con una libreria di skill e design system aperta e local-first."}, {"name": "Mi serve un abbonamento speciale per progettare con OpenCode?", "text": "No — OpenCode è BYOK. Porti la tua chiave API di provider di modello, e Open Design non instrada mai le tue credenziali. Non c'è alcun vincolo di fornitore."}, {"name": "OpenCode o Codex o Claude Code per il design frontend?", "text": "Sono tutti forti, e molti team li combinano. Il vantaggio di OpenCode è essere completamente open-source e agnostico rispetto al modello; Codex eccelle nelle build delegate e in sandbox; Claude Code è noto per decisioni di design specifiche e consapevoli della codebase. Open Design ti permette di cambiare agente senza modificare il tuo flusso di lavoro di design."}, {"name": "Come estendo OpenCode per il contesto di design?", "text": "Codifica le regole in AGENTS.md, aggiungi server MCP sotto la chiave mcp per strumenti e contesto di design portabili, e usa le sessioni condivisibili per la revisione. Open Design include una libreria curata di skill e design system, così salti la configurazione progetto per progetto."}, {"name": "Open Design è affiliato a OpenCode o SST?", "text": "No. OpenCode è un progetto open-source mantenuto da SST (Anomaly Innovations); Open Design è un progetto open-source indipendente che lo supporta come adattatore di prima parte."}, {"name": "I miei file e le mie credenziali sono al sicuro?", "text": "Sì — Open Design è local-first. I tuoi file, gli artefatti e DESIGN.md restano nella tua repo, e le tue credenziali di provider di modello vengono usate direttamente dal tuo agente, mai instradate attraverso i server di Open Design."}], "ctaTitle": "Progetta con OpenCode, in modo aperto.", "ctaBody": "Porta la tua chiave di provider di modello, mantieni ogni file in locale e ottieni una libreria di design curata intorno all'agente aperto che già usi.", "ctaActions": [{"label": "Usa OpenCode dentro Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Metti una stella su GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Scarica l'app desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Vedi tutti gli agenti supportati"},
      },
      'gemini': {
        ...en['gemini']!,
        title: "Gemini CLI per il design — Open Design",
        description: "Come si usa la Gemini CLI di Google per il design di UI e web — la sua comprensione multimodale delle immagini, il contesto da 1M di token, GEMINI.md e MCP — e come Open Design trasforma Gemini CLI in un agente di design open-source e local-first.",
        breadcrumb: "Gemini CLI",
        label: "Agente · Gemini CLI",
        heading: "Gemini CLI per il design.",
        lead: "Gemini CLI è l'agente da terminale open-source di Google. I suoi modelli multimodali leggono gli screenshot e il suo contesto da 1M di token contiene un intero design system, il che ne fa un vero strumento di design — una volta che gli fornisci riferimenti, convenzioni e un ciclo di verifica. Open Design lo integra in un flusso di lavoro di design open-source: il tuo account Google o la tua API key, i tuoi file, local-first.",
        rich: {"heroCtaLead": "Open Design trasforma Gemini CLI in un agente di design open-source e local-first — il tuo account Google o la tua API key di Gemini, i tuoi file, una libreria curata di skill e design system tutto intorno.", "heroCtaActions": [{"label": "Usa Gemini CLI dentro Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Metti una stella su GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Scarica l'app desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Gemini CLI è l'agente IA open-source di Google per il terminale. Due aspetti lo rendono interessante in particolare per il design: i suoi modelli sono fortemente multimodali, quindi legge uno screenshot e ragiona su layout, spaziatura e gerarchia; e la sua finestra di contesto da 1M di token può contenere un intero design system e codebase in una sola volta. Abbinato ai giusti riferimenti, convenzioni e a un ciclo di verifica, costruisce UI reali e responsive — ed è gratuito per iniziare con un account Google. Questa è una guida pratica ed end-to-end all'uso di Gemini CLI per il lavoro su UI, frontend e design system, e alla sua integrazione in un flusso di lavoro di design strutturato con Open Design.", "Copre cos'è davvero Gemini CLI, perché i suoi modelli multimodali e il suo enorme contesto si adattano al design, come configurarlo da zero, il ciclo dallo screenshot alla UI, come GEMINI.md e MCP lo estendono, come si confronta con Codex, Claude Code e Cursor, le insidie che fanno apparire generico l'output dell'IA, e come Open Design colma il divario come livello di design aperto e local-first — un abbinamento naturale, dato che entrambi sono open-source e girano sulla tua macchina."], "heroImage": {"src": "/agents/gemini-design/gemini-design-hero.webp", "alt": "Ciclo di feedback del design con Gemini CLI: un agente da terminale che legge un'immagine di riferimento, un browser che renderizza la UI e un workspace, con una freccia di feedback che ritorna", "caption": "Il ciclo fondamentale: Gemini CLI legge i tuoi riferimenti nel terminale, costruisce e verifica la UI in un browser reale e itera rispetto ad essi — con un intero design system nel contesto."}, "tocLabel": "In questa pagina", "toc": [{"id": "what-is-gemini-cli", "label": "Cos'è davvero Gemini CLI"}, {"id": "why-design", "label": "Perché multimodalità + enorme contesto si adattano al design"}, {"id": "setup", "label": "Configura Gemini CLI per il design (da zero)"}, {"id": "screenshot-workflow", "label": "Il flusso di lavoro dallo screenshot alla UI"}, {"id": "extend", "label": "GEMINI.md, MCP ed estensioni"}, {"id": "vs", "label": "Gemini CLI vs Codex vs Claude Code vs Cursor"}, {"id": "pitfalls", "label": "Insidie e l'aspetto da \"sbobba IA\""}, {"id": "open-design", "label": "Fare design con Gemini CLI in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-gemini-cli", "heading": "Cos'è davvero Gemini CLI", "blocks": [{"kind": "p", "text": "Gemini CLI è un agente IA open-source (Apache-2.0) che Google distribuisce per il terminale. Legge il tuo repository, modifica file, esegue comandi shell, recupera contenuti dal web e può fondare le risposte con Google Search — pianificando e verificando il lavoro a partire da compiti in linguaggio naturale, anziché limitarsi a completare righe. Lo stesso motore alimenta anche l'agente Gemini Code Assist all'interno di VS Code."}, {"kind": "p", "text": "Per il lavoro di design spiccano due proprietà. I suoi modelli sono nativamente multimodali, quindi puoi passargli uno screenshot e lui ragiona sul layout effettivo. E la sua finestra di contesto arriva fino a 1M di token, abbastanza ampia da contenere l'intero design system, la libreria di componenti e il set di riferimenti in una sola volta, anziché riassumerli e perderli."}, {"kind": "steps", "items": [{"label": "File di contesto", "body": "Gemini CLI legge un file GEMINI.md per il contesto persistente del progetto — il luogo naturale dove codificare le tue convenzioni di design, i token e le checklist di revisione. Le impostazioni personali e di team si sovrappongono."}, {"label": "Strumenti integrati + MCP", "body": "Offre da subito strumenti per file, shell, web-fetch e Google Search, e supporta i server MCP (configurati in ~/.gemini/settings.json) per aggiungere contesto esterno, come un file Figma dal vivo."}, {"label": "Gratuito per iniziare", "body": "L'accesso con un account Google personale offre un generoso tier gratuito di richieste a Gemini; puoi anche portare la tua API key di Gemini o usare Vertex AI."}]}, {"kind": "ul", "items": ["Fornitore: Google", "Credenziale: account Google (tier gratuito) o API key di Gemini da AI Studio (BYOK) o Vertex AI", "Licenza: Apache-2.0, open source"]}]}, {"id": "why-design", "heading": "Perché i modelli multimodali e un enorme contesto si adattano al design", "blocks": [{"kind": "p", "text": "Il vantaggio di Gemini CLI nel design deriva da due proprietà del modello — ma, come per ogni agente, il gusto va comunque fornito."}, {"kind": "steps", "items": [{"label": "Forte comprensione multimodale", "body": "Poiché i modelli Gemini sono nativamente multimodali, l'agente legge bene gli screenshot di riferimento — confrontando il proprio output renderizzato con un'immagine anziché tirare a indovinare da una descrizione testuale."}, {"label": "Una finestra di contesto da 1M di token", "body": "Un contesto ampio significa che l'intero design system, i token e molti stati di riferimento entrano tutti insieme, così l'agente riusa le tue primitive reali anziché inventare stili improvvisati."}, {"label": "Convenzioni in GEMINI.md", "body": "Un GEMINI.md (più il server Figma MCP) indirizza l'agente verso i tuoi token, componenti e specifiche reali, così lavora rispetto a un brand anziché a un aspetto di default."}]}, {"kind": "image", "src": "/agents/gemini-design/gemini-design-taste-triangle.webp", "alt": "Diagramma che mostra design system, skill e immagine di riferimento che convergono in un buon output di design", "caption": "Il gusto nasce da tre input che fornisci tu: un design system, una skill e immagini di riferimento reali."}, {"kind": "p", "text": "La lezione è la stessa che insegna ogni agente: Gemini CLI non ha gusto di default. Produce un buon design quando gli dai dei vincoli — un design system, una skill estetica e riferimenti concreti. Open Design impacchetta esattamente quegli input, ed è per questo che i due si combinano bene (altro più sotto)."}]}, {"id": "setup", "heading": "Configura Gemini CLI per il lavoro di design, da zero", "blocks": [{"kind": "p", "text": "Ecco il percorso completo da una macchina pulita a una Gemini CLI in grado di costruire e verificare UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Gemini CLI (Node 20+)\nnpm install -g @google/gemini-cli\n# or run without installing: npx https://github.com/google-gemini/gemini-cli\n\n# 2. Start it in your project and authenticate on first run\ncd your-project\ngemini            # sign in with your Google account, or set GEMINI_API_KEY\n\n# 3. Generate project context\n/init             # scaffolds a GEMINI.md for this project\n\n# 4. Wire the Figma MCP server (optional, for design handoff)\n#    add it under \"mcpServers\" in ~/.gemini/settings.json"}, {"kind": "image", "src": "/agents/gemini-design/gemini-design-setup-flow.webp", "alt": "Flusso di configurazione in cinque passaggi: installa, autentica, configura GEMINI.md, aggiungi una skill, verifica", "caption": "La sequenza di configurazione: installa → autentica → configura GEMINI.md → aggiungi una skill → abilita la verifica nel browser."}, {"kind": "steps", "items": [{"label": "Codifica le tue regole di design", "body": "Metti i tuoi token, le primitive e le convenzioni in GEMINI.md e indirizza Gemini verso di essi, così l'output corrisponde a un brand anziché ripiegare su un aspetto generico."}, {"label": "Aggiungi la verifica nel browser", "body": "Integra un MCP Playwright o di browser così che Gemini renderizzi in un browser reale e controlli il proprio output sui vari breakpoint, anziché limitarsi a confermare che la build passi."}]}]}, {"id": "screenshot-workflow", "heading": "Il flusso di lavoro dallo screenshot alla UI", "blocks": [{"kind": "p", "text": "Il ciclo di design a più alto rendimento con Gemini CLI è trasformare un'immagine di riferimento in una UI funzionante e responsive, iterando finché non corrisponde — appoggiandosi al modello multimodale per confrontare l'output con il riferimento."}, {"kind": "ol", "items": ["Parti dai riferimenti visivi più chiari che hai — e includi più stati (desktop e mobile, hover, vuoto, caricamento), non solo uno scatto principale.", "Sii specifico nel prompt; prompt vaghi producono UI generiche anche con un modello forte.", "Tieni il tuo design system e le tue convenzioni in GEMINI.md, e indica a Gemini dove si trovano i token e le primitive canoniche.", "Avvia un dev server e fai renderizzare Gemini in un browser reale, ridimensionando ai breakpoint per controllare il risultato.", "Itera facendo confrontare a Gemini la propria implementazione con gli screenshot — non limitarti a confermare che compili."]}, {"kind": "p", "text": "Fai riferimento a un'immagine con @ per allegarla al prompt, poi dai vincoli concreti:"}, {"kind": "code", "lang": "bash", "code": "gemini\n# in the prompt:\n> @reference-desktop.png @reference-mobile.png\n  Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from GEMINI.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the references\n  across breakpoints."}, {"kind": "p", "text": "Mantieni i prompt piccoli e mirati, fai il commit delle buone iterazioni e annulla quelle cattive (dicendo a Gemini quando esegui il revert), così ogni passaggio si costruisce su una base pulita."}]}, {"id": "extend", "heading": "GEMINI.md, MCP ed estensioni", "blocks": [{"kind": "p", "text": "Tre punti di estensione rendono Gemini CLI pratica per un lavoro di design prolungato, e tutti e tre si mappano in modo pulito su un flusso di lavoro di design aperto."}, {"kind": "steps", "items": [{"label": "Contesto GEMINI.md", "body": "Le regole di progetto vivono in un GEMINI.md alla radice del repo (con livelli globale e di team). È la casa duratura delle tue convenzioni di design, letta a ogni esecuzione."}, {"label": "Server MCP", "body": "Configura i server MCP in ~/.gemini/settings.json — il modo portabile per introdurre contesto di design e strumenti esterni, in particolare il server Figma MCP, che funzionano tra agenti diversi, non solo con Gemini."}, {"label": "Estensioni e strumenti integrati", "body": "Le estensioni di Gemini CLI e i suoi strumenti integrati di Google Search, file, shell e web-fetch gli consentono di raccogliere riferimenti ed eseguire il ciclo di verifica senza lasciare il terminale."}]}, {"kind": "p", "text": "Queste sono capacità portabili e multi-agente — esattamente il genere di cosa che Open Design è costruito per orchestrare, anziché ricreare per ogni progetto."}]}, {"id": "vs", "heading": "Gemini CLI vs Codex vs Claude Code vs Cursor per il design", "blocks": [{"kind": "p", "text": "Non c'è un unico vincitore per il lavoro di design — ogni agente ha un punto di forza diverso, e i team esperti li combinano. Un riepilogo onesto:"}, {"kind": "table", "columns": ["Agente", "Punto di forza nel design", "Ideale per"], "rows": [["Gemini CLI", "Forte comprensione multimodale delle immagini e un contesto da 1M di token; open-source con un tier gratuito", "Lavoro ricco di screenshot e contenere un intero design system nel contesto"], ["Codex", "Forte rifinitura visiva con una skill frontend; build asincrone in sandbox", "Build asincrone delegate e regole AGENTS.md portabili"], ["Claude Code", "Decisioni di design specifiche (hex, spaziatura, tipografia) e UX consapevole della codebase", "Ragionamento frontend e refactoring a grande contesto"], ["Cursor", "Ciclo visivo costruisci-e-osserva con anteprima dal vivo e modifiche inline", "Lavoro di UI serrato itera-e-osserva dentro un IDE"]]}, {"kind": "p", "text": "Il verdetto ricorrente della community è che il gusto viene dagli esseri umani: tutti ripiegano su un'estetica generica senza skill, riferimenti e vincoli. È quello il vero problema da risolvere — ed è a forma di strumento di design, non a forma di modello."}]}, {"id": "pitfalls", "heading": "Insidie, e come evitare l'aspetto da \"sbobba IA\"", "blocks": [{"kind": "p", "text": "La lamentela più comune sul design generato dall'IA è che appare generico — gradienti morbidi, pannelli fluttuanti, angoli arrotondati sovradimensionati, ombre drammatiche, un'atmosfera Inter-e-viola che \"grida che l'ha fatto un'IA\". Altri problemi segnalati includono layout mobile rotti e istruzioni che trapelano nei testi della UI. Nessuno di questi è esclusivo di Gemini CLI; è ciò che accade quando un qualsiasi agente gira senza un contesto di design curato."}, {"kind": "steps", "items": [{"label": "Aggiungi una skill estetica", "body": "Una skill di design curata costringe l'agente a impegnarsi su una direzione reale anziché sull'aspetto di default."}, {"label": "Verifica in un browser reale", "body": "Usa il modello multimodale per renderizzare e auto-verificare sui vari breakpoint, così i layout non si rompono silenziosamente su mobile."}, {"label": "Fornisci token e riferimenti", "body": "Token di design reali e screenshot di riferimento sono la singola leva più grande sulla qualità dell'output."}, {"label": "Codifica le regole in GEMINI.md", "body": "Metti regole in stile \"niente hero card, massimo due caratteri tipografici, gerarchia brand-first\" dove l'agente le legge a ogni esecuzione."}]}, {"kind": "p", "text": "Nota che ogni mitigazione consiste nel dare all'agente un contesto di design curato. Mantenere quel contesto a mano, progetto per progetto, è la fatica che Open Design elimina."}]}, {"id": "open-design", "heading": "Fare design con Gemini CLI dentro Open Design", "blocks": [{"kind": "p", "text": "Open Design è il livello di design open-source che il flusso di lavoro qui sopra continua a richiedere. Tratta Gemini CLI come un adapter di prima parte e lo avvolge in una libreria curata di skill e design system, in una pipeline di rendering strutturata e in una UI desktop locale — così il contesto di design che rende Gemini valido è già lì dalla prima esecuzione, anziché essere assemblato a mano ogni volta. Entrambi sono open-source e local-first, il che rende l'abbinamento naturale."}, {"kind": "ol", "items": ["Installa Open Design e seleziona Gemini CLI come tuo agente.", "Autenticati con il tuo account Google o la tua API key di Gemini (BYOK) — le credenziali restano sulla tua macchina e non vengono mai instradate tramite noi.", "Scegli un design system e una skill, poi genera deck, prototipi e landing page con un gusto coerente.", "Ogni artefatto e file DESIGN.md vive nel tuo repo, non in un cloud ospitato."]}, {"kind": "p", "text": "Stesso agente Gemini CLI, stessa key — più un vero flusso di lavoro di design portabile e open-source tutto intorno. È local-first e Apache-2.0, quindi nulla del tuo lavoro o delle tue credenziali lascia la tua macchina."}]}], "faqTitle": "Domande frequenti", "faq": [{"name": "Gemini CLI può davvero fare lavoro di design?", "text": "Sì — con una skill estetica, un design system e immagini di riferimento reali nel contesto, Gemini CLI produce UI responsive di qualità produttiva, e i suoi forti modelli multimodali verificano l'output rispetto ai riferimenti. Senza quel contesto tende a ripiegare su un aspetto generico, ed è il divario che Open Design colma."}, {"name": "Devo pagare per fare design con Gemini CLI?", "text": "No — l'accesso con un account Google offre un generoso tier gratuito, e puoi anche portare una API key di Gemini (BYOK) o usare Vertex AI. Open Design non instrada mai le tue credenziali in nessun caso."}, {"name": "Cosa rende Gemini CLI valida specificamente per il design?", "text": "Due cose: i suoi modelli sono fortemente multimodali, quindi legge bene gli screenshot di riferimento, e il suo contesto da 1M di token può contenere un intero design system e set di riferimenti in una sola volta. Entrambe aiutano — ma il gusto viene comunque dal design system, dalla skill e dai riferimenti che fornisci tu."}, {"name": "Gemini CLI o Claude Code per il design frontend?", "text": "Entrambi sono forti. Claude Code è noto per decisioni di design specifiche e consapevoli della codebase; il vantaggio di Gemini CLI è la comprensione multimodale più un enorme contesto e un tier gratuito. Molti team usano entrambi — Open Design ti permette di cambiare agente senza cambiare il tuo flusso di lavoro di design."}, {"name": "Come collego Gemini CLI a Figma?", "text": "Aggiungi il server Figma MCP sotto mcpServers in ~/.gemini/settings.json. Gemini può quindi attingere a contesto di design reale — componenti, variabili, dati di layout — così il codice generato corrisponde alla sorgente anziché approssimarla."}, {"name": "Open Design è affiliato a Google?", "text": "No. Gemini CLI è un prodotto di Google; Open Design è un progetto open-source indipendente che lo supporta come adapter di prima parte. Gemini è un marchio di Google."}, {"name": "I miei file e le mie credenziali sono al sicuro?", "text": "Sì — Open Design è local-first e Apache-2.0. I tuoi file, artefatti e DESIGN.md restano nel tuo repo, e le tue credenziali Google sono usate direttamente dal tuo agente, mai instradate attraverso i server di Open Design."}], "ctaTitle": "Fai design con Gemini CLI, in modo aperto.", "ctaBody": "Porta il tuo account Google o la tua API key di Gemini, tieni ogni file in locale e ottieni una libreria di design curata intorno all'agente che già usi.", "ctaActions": [{"label": "Usa Gemini CLI dentro Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Metti una stella su GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Scarica l'app desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Vedi tutti gli agenti supportati"},
      },
      'copilot': {
        ...en['copilot']!,
        title: "GitHub Copilot CLI per il design — Open Design",
        description: "Come si usa GitHub Copilot CLI per il design di UI e web — il suo agente di coding nativo del terminale, i file di istruzioni personalizzate, il supporto MCP e la scelta tra più modelli — e come Open Design trasforma Copilot CLI in un agente di design open-source e local-first.",
        breadcrumb: "GitHub Copilot CLI",
        label: "Agente · GitHub Copilot CLI",
        heading: "GitHub Copilot CLI per il design.",
        lead: "GitHub Copilot CLI è l'agente di coding nativo del terminale di GitHub. Pianifica e modifica l'intero repository, sceglie tra modelli di frontiera come Claude e GPT e legge le istruzioni del tuo repository — il che lo rende un vero strumento di design una volta che gli fornisci riferimenti, convenzioni e un ciclo di verifica. Open Design lo integra in un flusso di lavoro di design open-source: il tuo abbonamento GitHub Copilot, i tuoi file, in modalità local-first.",
        rich: {"heroCtaLead": "Open Design trasforma GitHub Copilot CLI in un agente di design open-source e local-first — il tuo abbonamento GitHub Copilot, i tuoi file, con intorno una libreria curata di skill e design system.", "heroCtaActions": [{"label": "Usa Copilot CLI dentro Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Metti una star su GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Scarica l'app desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["GitHub Copilot CLI è l'agente di coding nativo del terminale di GitHub — lo stesso harness agentico che alimenta il Copilot coding agent, portato sulla riga di comando. Due cose lo rendono interessante specificamente per il design: legge le istruzioni del tuo repository e AGENTS.md, così le tue convenzioni di design accompagnano l'agente a ogni esecuzione; e ti permette di scegliere tra modelli di frontiera di Anthropic, OpenAI e Google per ogni attività, così puoi scegliere quello che ragiona meglio su una determinata UI. Abbinato ai riferimenti, alle convenzioni e a un ciclo di verifica giusti, costruisce una UI reale e responsive — e gira sull'abbonamento Copilot che forse hai già. Questa è una guida pratica ed end-to-end all'uso di Copilot CLI per il lavoro su UI, frontend e design system, e a integrarlo in un flusso di lavoro di design strutturato con Open Design.", "Copre cos'è davvero Copilot CLI, perché le istruzioni del repository e la scelta del modello si adattano al design, come configurarlo da zero, il ciclo screenshot-to-UI, come le istruzioni personalizzate e MCP lo estendono, come si confronta con Codex, Claude Code, Cursor e Gemini CLI, le insidie che fanno sembrare generico l'output dell'IA, e come Open Design colma il divario come layer di design aperto e local-first — il tuo abbonamento e le tue credenziali restano sulla tua macchina, i tuoi artefatti restano nel tuo repository."], "heroImage": {"src": "/agents/copilot-design/copilot-design-hero.webp", "alt": "Ciclo di feedback del design con GitHub Copilot CLI: un agente nel terminale che legge un'immagine di riferimento, un browser che renderizza la UI e un workspace, con una freccia di feedback che torna indietro", "caption": "Il ciclo centrale: Copilot CLI legge i tuoi riferimenti nel terminale, costruisce e verifica la UI in un browser reale e itera su di essi — con le tue convenzioni di design nelle istruzioni del repository."}, "tocLabel": "In questa pagina", "toc": [{"id": "what-is-copilot", "label": "Cos'è davvero GitHub Copilot CLI"}, {"id": "why-design", "label": "Perché istruzioni + scelta del modello si adattano al design"}, {"id": "setup", "label": "Configurare Copilot CLI per il design (da zero)"}, {"id": "screenshot-workflow", "label": "Il flusso di lavoro screenshot-to-UI"}, {"id": "extend", "label": "Istruzioni personalizzate, MCP ed estensioni"}, {"id": "vs", "label": "Copilot CLI vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Insidie e l'estetica da “AI slop”"}, {"id": "open-design", "label": "Progettare con Copilot CLI in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-copilot", "heading": "Cos'è davvero GitHub Copilot CLI", "blocks": [{"kind": "p", "text": "GitHub Copilot CLI è l'agente di coding nativo del terminale di GitHub. Legge il tuo repository, modifica i file, esegue comandi shell e lavora direttamente con il tuo contesto GitHub — issue, pull request e repository — autenticandosi con il tuo account GitHub esistente. È alimentato dallo stesso harness agentico del Copilot coding agent di GitHub, quindi pianifica attività complesse e itera invece di limitarsi a completare righe. Ha raggiunto la disponibilità generale a febbraio 2026 dopo una preview pubblica aperta a settembre 2025."}, {"kind": "p", "text": "Per il lavoro di design spiccano due proprietà. Legge file di istruzioni personalizzate — regole valide per l'intero repository in .github/copilot-instructions.md più AGENTS.md — così le tue convenzioni di design vengono incluse automaticamente a ogni esecuzione. E supporta più provider di modelli di base, così puoi cambiare il modello per ogni attività con il comando /model scegliendo quello che ragiona meglio su una determinata UI."}, {"kind": "steps", "items": [{"label": "File di istruzioni", "body": "Copilot CLI legge le istruzioni del repository in .github/copilot-instructions.md, i file specifici per percorso sotto .github/instructions e AGENTS.md — il posto naturale dove codificare le tue convenzioni di design, i token e le checklist di revisione."}, {"label": "Strumenti integrati + MCP", "body": "Include integrato il server MCP di GitHub ed esegue strumenti per file e shell, e puoi aggiungere server MCP personalizzati con /mcp add (memorizzati in mcp-config.json sotto ~/.copilot) per contesto esterno come un file Figma live."}, {"label": "Scelta del modello", "body": "Usa il comando /model per scegliere tra modelli di frontiera di Anthropic, OpenAI e Google — cambiando per ogni attività, il tutto sul tuo abbonamento Copilot esistente."}]}, {"kind": "ul", "items": ["Fornitore: GitHub", "Credenziale: un abbonamento GitHub Copilot attivo (Pro, Pro+, Business o Enterprise)", "Installazione: npm install -g @github/copilot, poi esegui copilot"]}]}, {"id": "why-design", "heading": "Perché le istruzioni del repository e la scelta del modello si adattano al design", "blocks": [{"kind": "p", "text": "Il vantaggio di Copilot CLI nel design deriva da due proprietà — ma, come per ogni agente, il gusto va comunque fornito."}, {"kind": "steps", "items": [{"label": "Convenzioni che viaggiano con il repository", "body": "Poiché Copilot CLI legge automaticamente .github/copilot-instructions.md e AGENTS.md, i tuoi token, le primitive e le regole di revisione sono nel contesto a ogni esecuzione — l'agente lavora su un brand invece che su un aspetto di default."}, {"label": "Scegli il modello giusto per ogni attività", "body": "La scelta del modello tra Anthropic, OpenAI e Google significa che puoi ricorrere al modello che ragiona meglio su un determinato layout, poi cambiare per l'attività successiva — senza modificare il tuo flusso di lavoro."}, {"label": "Specifiche reali via MCP", "body": "Il server MCP integrato di GitHub più un server MCP Figma indirizzano l'agente verso i tuoi token, componenti e specifiche reali, così costruisce dalla fonte invece di approssimare."}]}, {"kind": "image", "src": "/agents/copilot-design/copilot-design-taste-triangle.webp", "alt": "Diagramma che mostra design system, skill e immagine di riferimento che convergono in un buon output di design", "caption": "Il gusto nasce da tre input che fornisci tu: un design system, una skill e immagini di riferimento reali."}, {"kind": "p", "text": "La lezione è la stessa che insegna ogni agente: Copilot CLI non ha gusto di default. Produce un buon design quando gli dai vincoli — un design system, una skill estetica e riferimenti concreti. Open Design impacchetta esattamente quegli input, ed è per questo che i due si combinano bene (più avanti)."}]}, {"id": "setup", "heading": "Configurare Copilot CLI per il lavoro di design, da zero", "blocks": [{"kind": "p", "text": "Ecco il percorso completo da una macchina pulita a un Copilot CLI capace di costruire e verificare UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Copilot CLI (Node.js required)\nnpm install -g @github/copilot\n\n# 2. Start it in your project and authenticate on first run\ncd your-project\ncopilot           # run /login and follow the prompts to sign in\n\n# 3. Choose a model for the task\n#    inside the session:\n/model            # pick a frontier model from Anthropic, OpenAI, or Google\n\n# 4. Add custom instructions and the Figma MCP server (optional)\n#    write .github/copilot-instructions.md or AGENTS.md\n/mcp add          # add the Figma MCP server for design handoff"}, {"kind": "image", "src": "/agents/copilot-design/copilot-design-setup-flow.webp", "alt": "Flusso di configurazione in cinque passaggi: installa, autentica, scegli un modello, configura le istruzioni, verifica", "caption": "La sequenza di configurazione: installa → autentica → scegli un modello → scrivi le istruzioni → abilita la verifica nel browser."}, {"kind": "steps", "items": [{"label": "Codifica le tue regole di design", "body": "Metti i tuoi token, le primitive e le convenzioni in .github/copilot-instructions.md o AGENTS.md, così l'output corrisponde a un brand invece di ricadere su un aspetto generico."}, {"label": "Aggiungi la verifica nel browser", "body": "Collega un MCP Playwright o un browser MCP così Copilot renderizza in un browser reale e controlla il suo output ai vari breakpoint invece di limitarsi a confermare che la build passa."}]}]}, {"id": "screenshot-workflow", "heading": "Il flusso di lavoro screenshot-to-UI", "blocks": [{"kind": "p", "text": "Il ciclo di design a maggiore leva con Copilot CLI consiste nel trasformare un'immagine di riferimento in una UI funzionante e responsive e iterare finché non corrisponde — appoggiandosi a un modello multimodale forte per confrontare l'output con il riferimento."}, {"kind": "ol", "items": ["Parti dai riferimenti visivi più chiari che hai — e includi più stati (desktop e mobile, hover, vuoto, caricamento), non solo uno scatto hero.", "Sii specifico nel prompt; i prompt vaghi producono UI generiche anche con un modello forte.", "Mantieni il tuo design system e le convenzioni in .github/copilot-instructions.md o AGENTS.md, e indica a Copilot dove vivono i token e le primitive canoniche.", "Avvia un dev server e fai renderizzare Copilot in un browser reale, ridimensionando ai breakpoint per controllare il risultato.", "Itera facendo confrontare a Copilot la sua implementazione con gli screenshot — non limitarti a confermare che fa la build."]}, {"kind": "p", "text": "Indirizza Copilot verso le tue immagini di riferimento e fornisci vincoli concreti; mostra in anteprima ogni modifica di file o comando per la tua approvazione prima di eseguirlo:"}, {"kind": "code", "lang": "bash", "code": "copilot\n# in the prompt:\n> Implement the design in reference-desktop.png and reference-mobile.png\n  in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens described in\n  .github/copilot-instructions.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the references\n  across breakpoints."}, {"kind": "p", "text": "Mantieni i prompt piccoli e mirati, fai commit delle buone iterazioni e ripristina quelle cattive (dicendo a Copilot quando fai un revert), così ogni passaggio parte da una base pulita."}]}, {"id": "extend", "heading": "Istruzioni personalizzate, MCP ed estensioni", "blocks": [{"kind": "p", "text": "Tre punti di estensione rendono Copilot CLI pratico per un lavoro di design continuativo, e tutti e tre si mappano in modo pulito su un flusso di lavoro di design aperto."}, {"kind": "steps", "items": [{"label": "Istruzioni personalizzate", "body": "Le regole del repository vivono in .github/copilot-instructions.md (con file specifici per percorso sotto .github/instructions e AGENTS.md). Sono la sede stabile per le tue convenzioni di design, incluse automaticamente a ogni esecuzione."}, {"label": "Server MCP", "body": "Copilot CLI include integrato il server MCP di GitHub e ti permette di aggiungere server personalizzati tramite /mcp add (memorizzati in mcp-config.json sotto ~/.copilot) — il modo portatile per portare contesto di design, in particolare il server MCP Figma, che funziona tra agenti diversi e non solo con Copilot."}, {"label": "Agenti specializzati e strumenti integrati", "body": "Le modalità specializzate di Copilot CLI — per l'esplorazione del codebase, l'esecuzione di build e test, la revisione delle modifiche e la pianificazione — più i suoi strumenti per file e shell gli permettono di raccogliere riferimenti ed eseguire il ciclo di verifica senza lasciare il terminale."}]}, {"kind": "p", "text": "Sono capacità portatili e multi-agente — esattamente il tipo di cosa che Open Design è costruito per orchestrare, invece di ricrearle per ogni progetto."}]}, {"id": "vs", "heading": "Copilot CLI vs Codex vs Claude Code vs Cursor vs Gemini CLI per il design", "blocks": [{"kind": "p", "text": "Non c'è un unico vincitore per il lavoro di design — ogni agente ha un punto di forza diverso, e i team esperti li combinano. Un riepilogo onesto:"}, {"kind": "table", "columns": ["Agente", "Punto di forza nel design", "Ideale per"], "rows": [["Copilot CLI", "Scelta multi-modello (Anthropic, OpenAI, Google) e profonda integrazione con GitHub sul tuo abbonamento Copilot", "Scegliere il modello migliore per ogni attività e lavoro guidato dalle istruzioni legato al tuo repository GitHub"], ["Codex", "Forte rifinitura visiva con una skill frontend; build asincrone in sandbox", "Build asincrone delegate e regole AGENTS.md portatili"], ["Claude Code", "Decisioni di design specifiche (hex, spaziatura, tipografia) e UX consapevole del codebase", "Ragionamento sul frontend e refactoring a grande contesto"], ["Cursor", "Ciclo build-and-see visivo con anteprima live e modifiche inline", "Lavoro UI iterativo e a vista serrato dentro un IDE"], ["Gemini CLI", "Forte comprensione multimodale delle immagini e un contesto da 1M di token; open-source con un tier gratuito", "Lavoro ricco di screenshot e tenere un intero design system nel contesto"]]}, {"kind": "p", "text": "Il verdetto ricorrente della community è che il gusto viene dagli esseri umani: tutti ricadono su un'estetica generica senza skill, riferimenti e vincoli. Questo è il vero problema da risolvere — ed è a forma di strumento di design, non di modello."}]}, {"id": "pitfalls", "heading": "Insidie, e come evitare l'estetica da “AI slop”", "blocks": [{"kind": "p", "text": "La lamentela più comune sul design generato dall'IA è che sembra generico — gradienti morbidi, pannelli fluttuanti, angoli arrotondati sovradimensionati, ombre drammatiche, un'atmosfera Inter-e-viola che “grida che l'ha fatto un'IA”. Altri problemi segnalati includono layout mobile rotti e istruzioni che si infiltrano nei testi della UI. Nessuno di questi è esclusivo di Copilot CLI; sono ciò che accade quando un qualsiasi agente gira senza un contesto di design curato."}, {"kind": "steps", "items": [{"label": "Aggiungi una skill estetica", "body": "Una skill di design curata costringe l'agente a impegnarsi su una direzione reale invece dell'aspetto di default."}, {"label": "Verifica in un browser reale", "body": "Renderizza e auto-controlla ai vari breakpoint con un browser MCP così i layout non si rompono silenziosamente sul mobile."}, {"label": "Fornisci token e riferimenti", "body": "I token di design reali e gli screenshot di riferimento sono la singola leva più grande sulla qualità dell'output."}, {"label": "Codifica le regole nelle istruzioni personalizzate", "body": "Metti regole di stile come “niente hero card, massimo due caratteri tipografici, gerarchia brand-first” in .github/copilot-instructions.md o AGENTS.md, dove l'agente le legge a ogni esecuzione."}]}, {"kind": "p", "text": "Nota che ogni mitigazione consiste nel dare all'agente un contesto di design curato. Mantenere quel contesto a mano, per ogni progetto, è la fatica che Open Design elimina."}]}, {"id": "open-design", "heading": "Progettare con Copilot CLI dentro Open Design", "blocks": [{"kind": "p", "text": "Open Design è il layer di design open-source che il flusso di lavoro qui sopra continua a richiedere. Tratta GitHub Copilot CLI come un adattatore di prima parte e lo avvolge in una libreria curata di skill e design system, in una pipeline di rendering strutturata e in una UI desktop locale — così il contesto di design che rende Copilot bravo è presente dalla prima esecuzione, non assemblato a mano ogni volta. Open Design è indipendente, open-source (Apache-2.0) e local-first, ed è per questo che l'abbinamento funziona: l'agente fa il lavoro, i tuoi file e le tue credenziali restano tuoi."}, {"kind": "ol", "items": ["Installa Open Design e seleziona GitHub Copilot CLI come tuo agente.", "Autenticati con il tuo abbonamento GitHub Copilot — le credenziali restano sulla tua macchina e non transitano mai tramite di noi.", "Scegli un design system e una skill, poi genera deck, prototipi e landing page con un gusto coerente.", "Ogni artefatto e ogni file DESIGN.md vive nel tuo repository, non in un cloud ospitato."]}, {"kind": "p", "text": "Stesso agente Copilot CLI, stesso abbonamento — più un flusso di lavoro di design reale, portatile e open-source intorno a esso. Open Design è local-first e Apache-2.0, quindi nulla del tuo lavoro o delle tue credenziali lascia la tua macchina."}]}], "faqTitle": "Domande frequenti", "faq": [{"name": "GitHub Copilot CLI può davvero fare lavoro di design?", "text": "Sì — con una skill estetica, un design system e immagini di riferimento reali nel contesto, Copilot CLI produce UI responsive di qualità produttiva, e puoi scegliere il modello che verifica meglio l'output rispetto ai riferimenti. Senza quel contesto tende a ricadere su un aspetto generico, ed è il divario che colma Open Design."}, {"name": "Mi serve un abbonamento per progettare con Copilot CLI?", "text": "Sì — Copilot CLI gira su un abbonamento GitHub Copilot attivo (Pro, Pro+, Business o Enterprise); non è bring-your-own-key. Ti autentichi con il tuo account GitHub. Open Design non fa mai da proxy alle tue credenziali — il tuo abbonamento è usato direttamente dal tuo agente."}, {"name": "Cosa rende Copilot CLI adatto specificamente al design?", "text": "Due cose: legge automaticamente le istruzioni del repository e AGENTS.md, così le tue convenzioni di design viaggiano con il repository; e ti permette di passare tra modelli di frontiera di Anthropic, OpenAI e Google per ogni attività. Entrambe aiutano — ma il gusto viene comunque dal design system, dalla skill e dai riferimenti che fornisci tu."}, {"name": "Copilot CLI o Claude Code per il design frontend?", "text": "Entrambi sono forti. Claude Code è noto per decisioni di design specifiche e consapevoli del codebase; il vantaggio di Copilot CLI è la scelta del modello tra provider e la profonda integrazione con GitHub su un abbonamento che forse hai già. Molti team usano entrambi — Open Design ti permette di cambiare agente senza modificare il tuo flusso di lavoro di design."}, {"name": "Come collego Copilot CLI a Figma?", "text": "Aggiungi il server MCP Figma con il comando /mcp add; le impostazioni sono memorizzate in mcp-config.json sotto ~/.copilot. Copilot può quindi recuperare contesto di design reale — componenti, variabili, dati di layout — così il codice generato corrisponde alla fonte invece di approssimarla."}, {"name": "Open Design è affiliato a GitHub o Microsoft?", "text": "No. GitHub Copilot CLI è un prodotto di GitHub; Open Design è un progetto open-source indipendente che lo supporta come adattatore di prima parte. GitHub Copilot è un marchio di GitHub, Inc. e Microsoft."}, {"name": "I miei file e le mie credenziali sono al sicuro?", "text": "Sì — Open Design è local-first e Apache-2.0. I tuoi file, gli artefatti e DESIGN.md restano nel tuo repository, e le tue credenziali GitHub Copilot sono usate direttamente dal tuo agente, mai instradate attraverso i server di Open Design."}], "ctaTitle": "Progetta con GitHub Copilot CLI, in modo aperto.", "ctaBody": "Porta il tuo abbonamento GitHub Copilot, tieni ogni file in locale e ottieni una libreria di design curata intorno all'agente che già usi.", "ctaActions": [{"label": "Usa Copilot CLI dentro Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Metti una star su GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Scarica l'app desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Vedi tutti gli agenti supportati"},
      },
      'qwen': {
        ...en['qwen']!,
        title: "Qwen Code per il design — Open Design",
        description: "Come si usa la CLI open-source Qwen Code di Alibaba per il design di UI e web — i suoi modelli Qwen3-Coder, l'ampia finestra di contesto, QWEN.md e MCP — e come Open Design trasforma Qwen Code in un agente di design open-source e local-first.",
        breadcrumb: "Qwen Code",
        label: "Agente · Qwen Code",
        heading: "Qwen Code per il design.",
        lead: "Qwen Code è l'agente open-source per il terminale di Alibaba, adattato da Gemini CLI e ottimizzato per i modelli Qwen3-Coder. La sua ampia finestra di contesto tiene un intero design system in una sola volta, il che lo rende un vero strumento di design — una volta che gli fornisci riferimenti, convenzioni e un ciclo di verifica. Open Design lo integra in un flusso di lavoro di design open-source: la tua API key DashScope o Qwen, i tuoi file, in modalità local-first.",
        rich: {"heroCtaLead": "Open Design trasforma Qwen Code in un agente di design open-source e local-first — la tua API key DashScope o Qwen, i tuoi file, con intorno una libreria curata di skill e design system.", "heroCtaActions": [{"label": "Usa Qwen Code dentro Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Metti una star su GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Scarica l'app desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Qwen Code è l'agente IA open-source per il terminale di Alibaba. È adattato da Gemini CLI di Google, con adattamenti a livello di parser e di prompt che gli permettono di sfruttare al massimo i modelli Qwen3-Coder. Due cose lo rendono interessante specificamente per il design: è un modello di coding agentico forte, quindi pianifica, modifica i file ed esegue il ciclo di build e verifica a partire da un'attività in linguaggio naturale; e la sua ampia finestra di contesto può tenere un intero design system e codebase in una sola volta. Abbinato ai riferimenti, alle convenzioni e a un ciclo di verifica giusti, costruisce una UI reale e responsive — ed è open-source e BYOK, quindi porti la tua chiave. Questa è una guida pratica ed end-to-end all'uso di Qwen Code per il lavoro su UI, frontend e design system, e a integrarlo in un flusso di lavoro di design strutturato con Open Design.", "Copre cos'è davvero Qwen Code, perché un modello coder forte più un grande contesto si adattano al design, come configurarlo da zero, il ciclo reference-to-UI, come QWEN.md e MCP lo estendono, come si confronta con Codex, Claude Code, Cursor e Gemini CLI, le insidie che fanno sembrare generico l'output dell'IA, e come Open Design colma il divario come layer di design aperto e local-first — un abbinamento naturale, poiché entrambi sono open-source e girano sulla tua macchina."], "heroImage": {"src": "/agents/qwen-design/qwen-design-hero.webp", "alt": "Ciclo di feedback del design con Qwen Code: un agente nel terminale che legge un'immagine di riferimento, un browser che renderizza la UI e un workspace, con una freccia di feedback che torna indietro", "caption": "Il ciclo centrale: Qwen Code legge i tuoi riferimenti nel terminale, costruisce e verifica la UI in un browser reale e itera su di essi — con un intero design system nel contesto."}, "tocLabel": "In questa pagina", "toc": [{"id": "what-is-qwen", "label": "Cos'è davvero Qwen Code"}, {"id": "why-design", "label": "Perché un modello coder forte + grande contesto si adattano al design"}, {"id": "setup", "label": "Configurare Qwen Code per il design (da zero)"}, {"id": "screenshot-workflow", "label": "Il flusso di lavoro reference-to-UI"}, {"id": "extend", "label": "QWEN.md, MCP ed estensioni"}, {"id": "vs", "label": "Qwen Code vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Insidie e l'estetica da “AI slop”"}, {"id": "open-design", "label": "Progettare con Qwen Code in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-qwen", "heading": "Cos'è davvero Qwen Code", "blocks": [{"kind": "p", "text": "Qwen Code è un agente IA open-source (Apache-2.0) che Alibaba distribuisce per il terminale. Legge il tuo repository, modifica i file, esegue comandi shell e lavora sul web — pianificando e verificando il lavoro a partire da attività in linguaggio naturale invece di limitarsi a completare righe. È adattato da Gemini CLI di Google, con adattamenti a livello di parser e di prompt calibrati per sbloccare i modelli Qwen3-Coder sui compiti di coding agentico."}, {"kind": "p", "text": "Per il lavoro di design spiccano due proprietà. È un coder agentico capace, quindi può prendere un riferimento e un brief chiaro e costruire, eseguire e auto-correggere una UI responsive. E i modelli Qwen3-Coder hanno un'ampia finestra di contesto, abbastanza grande da tenere in una sola volta l'intero design system, la libreria di componenti e il set di riferimenti invece di riassumerli via."}, {"kind": "steps", "items": [{"label": "File di contesto", "body": "Qwen Code legge un file QWEN.md per un contesto di progetto persistente — il posto naturale dove codificare le tue convenzioni di design, i token e le checklist di revisione. Le impostazioni personali e di progetto si sovrappongono sopra."}, {"label": "Strumenti integrati + MCP", "body": "Include pronti all'uso strumenti per file, shell e web, e supporta server MCP (configurati sotto mcpServers in ~/.qwen/settings.json) per aggiungere contesto esterno come un file Figma live."}, {"label": "BYOK per iniziare", "body": "Porti la tua chiave — un'API key DashScope (Alibaba Cloud Model Studio), o un qualsiasi endpoint compatibile con OpenAI o ModelScope — e la configuri in settings.json."}]}, {"kind": "ul", "items": ["Fornitore: Alibaba", "Credenziale: API key DashScope / Qwen (BYOK), o endpoint compatibile con OpenAI / ModelScope", "Licenza: Apache-2.0, open source (adattato da Gemini CLI)"]}]}, {"id": "why-design", "heading": "Perché un modello coder forte e un grande contesto si adattano al design", "blocks": [{"kind": "p", "text": "Il vantaggio di Qwen Code nel design deriva da due proprietà — ma, come per ogni agente, il gusto va comunque fornito."}, {"kind": "steps", "items": [{"label": "Coding agentico forte", "body": "I modelli Qwen3-Coder sono calibrati per compiti agentici, quindi l'agente pianifica, modifica, esegue la build e si auto-corregge — trasformando un riferimento e un brief chiari in markup responsive invece di un'ipotesi one-shot."}, {"label": "Un'ampia finestra di contesto", "body": "Il grande contesto di Qwen3-Coder significa che l'intero design system, i token e molti stati di riferimento entrano in una sola volta, così l'agente riutilizza le tue primitive reali invece di inventare stili una tantum."}, {"label": "Convenzioni in QWEN.md", "body": "Un QWEN.md (più il server MCP Figma) indirizza l'agente verso i tuoi token, componenti e specifiche reali, così lavora su un brand invece che su un aspetto di default."}]}, {"kind": "image", "src": "/agents/qwen-design/qwen-design-taste-triangle.webp", "alt": "Diagramma che mostra design system, skill e immagine di riferimento che convergono in un buon output di design", "caption": "Il gusto nasce da tre input che fornisci tu: un design system, una skill e immagini di riferimento reali."}, {"kind": "p", "text": "La lezione è la stessa che insegna ogni agente: Qwen Code non ha gusto di default. Produce un buon design quando gli dai vincoli — un design system, una skill estetica e riferimenti concreti. Open Design impacchetta esattamente quegli input, ed è per questo che i due si combinano bene (più avanti)."}]}, {"id": "setup", "heading": "Configurare Qwen Code per il lavoro di design, da zero", "blocks": [{"kind": "p", "text": "Ecco il percorso completo da una macchina pulita a un Qwen Code capace di costruire e verificare UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Qwen Code (Node 22+)\nnpm install -g @qwen-code/qwen-code@latest\n# or: brew install qwen-code\n\n# 2. Start it in your project and authenticate on first run\ncd your-project\nqwen              # run /auth, or set a key in ~/.qwen/settings.json\n\n# 3. Configure a DashScope (OpenAI-compatible) key in settings.json\n#    baseUrl: https://dashscope.aliyuncs.com/compatible-mode/v1\n#    model:   qwen3-coder-plus   (set DASHSCOPE_API_KEY)\n\n# 4. Add a QWEN.md and wire the Figma MCP server (optional)\n#    add MCP under \"mcpServers\" in ~/.qwen/settings.json"}, {"kind": "image", "src": "/agents/qwen-design/qwen-design-setup-flow.webp", "alt": "Flusso di configurazione in cinque passaggi: installa, autentica, configura QWEN.md, aggiungi una skill, verifica", "caption": "La sequenza di configurazione: installa → autentica → configura QWEN.md → aggiungi una skill → abilita la verifica nel browser."}, {"kind": "steps", "items": [{"label": "Codifica le tue regole di design", "body": "Metti i tuoi token, le primitive e le convenzioni in QWEN.md e indirizza Qwen Code verso di essi, così l'output corrisponde a un brand invece di ricadere su un aspetto generico."}, {"label": "Aggiungi la verifica nel browser", "body": "Collega un MCP Playwright o un browser MCP così Qwen Code renderizza in un browser reale e controlla il suo output ai vari breakpoint invece di limitarsi a confermare che la build passa."}]}]}, {"id": "screenshot-workflow", "heading": "Il flusso di lavoro reference-to-UI", "blocks": [{"kind": "p", "text": "Il ciclo di design a maggiore leva con Qwen Code consiste nel trasformare un riferimento in una UI funzionante e responsive e iterare finché non corrisponde — appoggiandosi all'agente per costruire, renderizzare e confrontare il suo output con il riferimento."}, {"kind": "ol", "items": ["Parti dai riferimenti visivi più chiari che hai — e descrivi più stati (desktop e mobile, hover, vuoto, caricamento), non solo uno scatto hero.", "Sii specifico nel prompt; i prompt vaghi producono UI generiche anche con un modello forte.", "Mantieni il tuo design system e le convenzioni in QWEN.md, e indica a Qwen Code dove vivono i token e le primitive canoniche.", "Avvia un dev server e fai renderizzare Qwen Code in un browser reale, ridimensionando ai breakpoint per controllare il risultato.", "Itera facendo confrontare a Qwen Code la sua implementazione con i riferimenti — non limitarti a confermare che fa la build."]}, {"kind": "p", "text": "Riferisci un file con @ per allegarlo al prompt, poi fornisci vincoli concreti:"}, {"kind": "code", "lang": "bash", "code": "qwen\n# in the prompt:\n> @reference-desktop.png @reference-mobile.png\n  Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from QWEN.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the references\n  across breakpoints."}, {"kind": "p", "text": "Mantieni i prompt piccoli e mirati, fai commit delle buone iterazioni e ripristina quelle cattive (dicendo a Qwen Code quando fai un revert), così ogni passaggio parte da una base pulita."}]}, {"id": "extend", "heading": "QWEN.md, MCP ed estensioni", "blocks": [{"kind": "p", "text": "Tre punti di estensione rendono Qwen Code pratico per un lavoro di design continuativo, e tutti e tre si mappano in modo pulito su un flusso di lavoro di design aperto."}, {"kind": "steps", "items": [{"label": "Contesto QWEN.md", "body": "Le regole del progetto vivono in un QWEN.md alla radice del repository (con livelli globale e di progetto). È la sede stabile per le tue convenzioni di design, letta a ogni esecuzione."}, {"label": "Server MCP", "body": "Configura i server MCP sotto mcpServers in ~/.qwen/settings.json — il modo portatile per portare contesto di design e strumenti esterni, in particolare il server MCP Figma, che funzionano tra agenti diversi e non solo con Qwen Code."}, {"label": "Skill e strumenti integrati", "body": "Le skill di Qwen Code e i suoi strumenti integrati per file, shell e web gli permettono di raccogliere riferimenti ed eseguire il ciclo di verifica senza lasciare il terminale."}]}, {"kind": "p", "text": "Sono capacità portatili e multi-agente — esattamente il tipo di cosa che Open Design è costruito per orchestrare, invece di ricrearle per ogni progetto."}]}, {"id": "vs", "heading": "Qwen Code vs Codex vs Claude Code vs Cursor vs Gemini CLI per il design", "blocks": [{"kind": "p", "text": "Non c'è un unico vincitore per il lavoro di design — ogni agente ha un punto di forza diverso, e i team esperti li combinano. Un riepilogo onesto:"}, {"kind": "table", "columns": ["Agente", "Punto di forza nel design", "Ideale per"], "rows": [["Qwen Code", "Coding agentico forte sui modelli aperti Qwen3-Coder con un grande contesto; open-source e BYOK", "Build open-source e flessibili sulla chiave che tengono un intero design system nel contesto"], ["Codex", "Forte rifinitura visiva con una skill frontend; build asincrone in sandbox", "Build asincrone delegate e regole AGENTS.md portatili"], ["Claude Code", "Decisioni di design specifiche (hex, spaziatura, tipografia) e UX consapevole del codebase", "Ragionamento sul frontend e refactoring a grande contesto"], ["Cursor", "Ciclo build-and-see visivo con anteprima live e modifiche inline", "Lavoro UI iterativo e a vista serrato dentro un IDE"], ["Gemini CLI", "Forte comprensione multimodale delle immagini e un contesto da 1M di token; l'agente da cui Qwen Code è adattato", "Lavoro ricco di screenshot e contesto molto ampio"]]}, {"kind": "p", "text": "Il verdetto ricorrente della community è che il gusto viene dagli esseri umani: tutti ricadono su un'estetica generica senza skill, riferimenti e vincoli. Questo è il vero problema da risolvere — ed è a forma di strumento di design, non di modello."}]}, {"id": "pitfalls", "heading": "Insidie, e come evitare l'estetica da “AI slop”", "blocks": [{"kind": "p", "text": "La lamentela più comune sul design generato dall'IA è che sembra generico — gradienti morbidi, pannelli fluttuanti, angoli arrotondati sovradimensionati, ombre drammatiche, un'atmosfera Inter-e-viola che “grida che l'ha fatto un'IA”. Altri problemi segnalati includono layout mobile rotti e istruzioni che si infiltrano nei testi della UI. Nessuno di questi è esclusivo di Qwen Code; sono ciò che accade quando un qualsiasi agente gira senza un contesto di design curato."}, {"kind": "steps", "items": [{"label": "Aggiungi una skill estetica", "body": "Una skill di design curata costringe l'agente a impegnarsi su una direzione reale invece dell'aspetto di default."}, {"label": "Verifica in un browser reale", "body": "Fai renderizzare e auto-controllare all'agente ai vari breakpoint così i layout non si rompono silenziosamente sul mobile."}, {"label": "Fornisci token e riferimenti", "body": "I token di design reali e gli screenshot di riferimento sono la singola leva più grande sulla qualità dell'output."}, {"label": "Codifica le regole in QWEN.md", "body": "Metti regole di stile come “niente hero card, massimo due caratteri tipografici, gerarchia brand-first” dove l'agente le legge a ogni esecuzione."}]}, {"kind": "p", "text": "Nota che ogni mitigazione consiste nel dare all'agente un contesto di design curato. Mantenere quel contesto a mano, per ogni progetto, è la fatica che Open Design elimina."}]}, {"id": "open-design", "heading": "Progettare con Qwen Code dentro Open Design", "blocks": [{"kind": "p", "text": "Open Design è il layer di design open-source che il flusso di lavoro qui sopra continua a richiedere. Tratta Qwen Code come un adattatore di prima parte e lo avvolge in una libreria curata di skill e design system, in una pipeline di rendering strutturata e in una UI desktop locale — così il contesto di design che rende bravo Qwen Code è presente dalla prima esecuzione, non assemblato a mano ogni volta. Entrambi sono open-source e local-first, il che rende l'abbinamento un connubio naturale."}, {"kind": "ol", "items": ["Installa Open Design e seleziona Qwen Code come tuo agente.", "Autenticati con la tua API key DashScope o Qwen (BYOK) — le credenziali restano sulla tua macchina e non transitano mai tramite di noi.", "Scegli un design system e una skill, poi genera deck, prototipi e landing page con un gusto coerente.", "Ogni artefatto e ogni file DESIGN.md vive nel tuo repository, non in un cloud ospitato."]}, {"kind": "p", "text": "Stesso agente Qwen Code, stessa chiave — più un flusso di lavoro di design reale, portatile e open-source intorno a esso. È local-first e Apache-2.0, quindi nulla del tuo lavoro o delle tue credenziali lascia la tua macchina."}]}], "faqTitle": "Domande frequenti", "faq": [{"name": "Qwen Code può davvero fare lavoro di design?", "text": "Sì — con una skill estetica, un design system e immagini di riferimento reali nel contesto, Qwen Code produce UI responsive di qualità produttiva, e il suo ciclo agentico costruisce, renderizza e verifica l'output rispetto ai riferimenti. Senza quel contesto tende a ricadere su un aspetto generico, ed è il divario che colma Open Design."}, {"name": "Devo pagare per progettare con Qwen Code?", "text": "Qwen Code è gratuito e open-source, ma è BYOK — porti un'API key DashScope (Alibaba Cloud Model Studio), un endpoint compatibile con OpenAI o ModelScope. Alibaba offre anche un piano di coding a tariffa fissa. Open Design non fa mai da proxy alle tue credenziali in entrambi i casi."}, {"name": "Cosa rende Qwen Code adatto specificamente al design?", "text": "Due cose: i modelli Qwen3-Coder sono calibrati per il coding agentico, quindi l'agente costruisce e auto-corregge una UI responsive, e il loro ampio contesto può tenere in una sola volta un intero design system e set di riferimenti. Entrambe aiutano — ma il gusto viene comunque dal design system, dalla skill e dai riferimenti che fornisci tu."}, {"name": "Qwen Code è lo stesso di Gemini CLI?", "text": "No. Qwen Code è adattato da Gemini CLI di Google — stessa discendenza open-source — con adattamenti a livello di parser e di prompt che lo calibrano per i modelli Qwen3-Coder. Open Design supporta entrambi, così puoi cambiare agente senza modificare il tuo flusso di lavoro di design."}, {"name": "Come collego Qwen Code a Figma?", "text": "Aggiungi il server MCP Figma sotto mcpServers in ~/.qwen/settings.json. Qwen Code può quindi recuperare contesto di design reale — componenti, variabili, dati di layout — così il codice generato corrisponde alla fonte invece di approssimarla."}, {"name": "Open Design è affiliato ad Alibaba o Qwen?", "text": "No. Qwen Code è un prodotto di Alibaba; Open Design è un progetto open-source indipendente che lo supporta come adattatore di prima parte. Qwen è un marchio di Alibaba."}, {"name": "I miei file e le mie credenziali sono al sicuro?", "text": "Sì — Open Design è local-first e Apache-2.0. I tuoi file, gli artefatti e DESIGN.md restano nel tuo repository, e le tue credenziali DashScope o Qwen sono usate direttamente dal tuo agente, mai instradate attraverso i server di Open Design."}], "ctaTitle": "Progetta con Qwen Code, in modo aperto.", "ctaBody": "Porta la tua API key DashScope o Qwen, tieni ogni file in locale e ottieni una libreria di design curata intorno all'agente che già usi.", "ctaActions": [{"label": "Usa Qwen Code dentro Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Metti una star su GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Scarica l'app desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Vedi tutti gli agenti supportati"},
      },
      'grok': {
        ...en['grok']!,
        title: "Grok Build per il design — Open Design",
        description: "Come si usa Grok Build di xAI (Grok Build) per il design di UI e web — la sua modalità di pianificazione, AGENTS.md e MCP, i modelli Grok capaci di leggere immagini e l'ampio contesto — e come Open Design trasforma Grok Build in un agente di design open-source e local-first.",
        breadcrumb: "Grok Build",
        label: "Agente · Grok Build",
        heading: "Grok Build per il design.",
        lead: "Grok Build è l'agente di coding per il terminale di xAI. Pianifica il lavoro multi-passo prima di toccare i tuoi file, legge immagini accanto al codice ed esegue il ciclo build-and-verify nel tuo repository — il che lo rende un vero strumento di design una volta che gli fornisci riferimenti, convenzioni e un passaggio di verifica. Open Design lo integra in un flusso di lavoro di design open-source: il tuo login SuperGrok o la tua API key xAI, i tuoi file, in modalità local-first.",
        rich: {"heroCtaLead": "Open Design trasforma Grok Build in un agente di design open-source e local-first — il tuo login SuperGrok o la tua API key xAI, i tuoi file, con intorno una libreria curata di skill e design system.", "heroCtaActions": [{"label": "Usa Grok Build dentro Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Metti una star su GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Scarica l'app desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Grok Build — l'agente di coding per il terminale di xAI, distribuito come Grok Build — è uno strumento agentico che vive nel tuo terminale. Due cose lo rendono interessante specificamente per il design: pianifica il lavoro rischioso prima di agire, così puoi rivedere un approccio proposto prima che cambi qualsiasi file; e i suoi modelli Grok accettano input di immagini, quindi può ragionare su uno screenshot di riferimento accanto al codice che scrive. Abbinato ai riferimenti, alle convenzioni e a un ciclo di verifica giusti, costruisce una UI reale e responsive — autenticato direttamente tramite il tuo account SuperGrok o X Premium+, senza giochi di prestigio con le API key. Questa è una guida pratica ed end-to-end all'uso di Grok Build per il lavoro su UI, frontend e design system, e a integrarlo in un flusso di lavoro di design strutturato con Open Design.", "Copre cos'è davvero Grok Build, perché la modalità di pianificazione e i modelli capaci di leggere immagini si adattano al design, come configurarlo da zero, il ciclo screenshot-to-UI, come AGENTS.md e MCP lo estendono, come si confronta con Codex, Claude Code, Cursor e Gemini CLI, le insidie che fanno sembrare generico l'output dell'IA, e come Open Design colma il divario come layer di design aperto e local-first — con le tue credenziali e i tuoi artefatti che non lasciano mai la tua macchina."], "heroImage": {"src": "/agents/grok-design/grok-design-hero.webp", "alt": "Ciclo di feedback del design con Grok Build: un agente nel terminale che pianifica a partire da un'immagine di riferimento, un browser che renderizza la UI e un workspace, con una freccia di feedback che torna indietro", "caption": "Il ciclo centrale: Grok Build pianifica a partire dai tuoi riferimenti nel terminale, costruisce e verifica la UI in un browser reale e itera su di essi — con le tue convenzioni in AGENTS.md."}, "tocLabel": "In questa pagina", "toc": [{"id": "what-is-grok", "label": "Cos'è davvero Grok Build"}, {"id": "why-design", "label": "Perché modalità di pianificazione + input immagini si adattano al design"}, {"id": "setup", "label": "Configurare Grok Build per il design (da zero)"}, {"id": "screenshot-workflow", "label": "Il flusso di lavoro screenshot-to-UI"}, {"id": "extend", "label": "AGENTS.md, MCP e subagent"}, {"id": "vs", "label": "Grok Build vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Insidie e l'estetica da “AI slop”"}, {"id": "open-design", "label": "Progettare con Grok Build in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-grok", "heading": "Cos'è davvero Grok Build", "blocks": [{"kind": "p", "text": "Grok Build è l'agente di coding per il terminale di xAI, distribuito con il nome Grok Build. Legge il tuo repository, modifica i file, esegue comandi shell e pianifica lavoro di ingegneria multi-passo a partire da attività in linguaggio naturale invece di limitarsi a completare righe. È costruito attorno ai modelli Grok di xAI — esposti sull'API xAI come la famiglia di modelli grok-build — e si autentica tramite il tuo account xAI, così l'agente e i modelli provengono dallo stesso fornitore."}, {"kind": "p", "text": "Per il lavoro di design spiccano due proprietà. Ha una modalità di pianificazione che redige un approccio strutturato che puoi approvare, commentare o riscrivere prima che venga applicata qualsiasi modifica — un cancello utile quando stai iterando su una UI. E i suoi modelli Grok accettano input di immagini, così puoi passargli uno screenshot di riferimento e ragiona sul layout reale invece di tirare a indovinare da una descrizione testuale."}, {"kind": "steps", "items": [{"label": "File di contesto", "body": "Grok Build legge un file AGENTS.md per un contesto di progetto persistente — il posto naturale dove codificare le tue convenzioni di design, i token e le checklist di revisione. Segue la stessa convenzione aperta AGENTS.md che usano Codex e altri agenti."}, {"label": "Strumenti, MCP + subagent", "body": "Modifica i file, esegue comandi shell e supporta server MCP per aggiungere contesto esterno come un file Figma live; per attività più grandi può delegare a subagent paralleli che ricercano, costruiscono e revisionano contemporaneamente."}, {"label": "Accedi con il tuo account", "body": "Ti autentichi accedendo tramite il browser con un abbonamento SuperGrok o X Premium+; puoi anche portare un'API key xAI per l'uso headless e in CI."}]}, {"kind": "ul", "items": ["Fornitore: xAI", "Credenziale: OAuth xAI SuperGrok (`grok login`), o un'API key xAI (BYOK) per l'uso headless", "Modelli: modelli Grok di xAI (la famiglia grok-build sull'API xAI), con input di immagini"]}]}, {"id": "why-design", "heading": "Perché la modalità di pianificazione e i modelli capaci di leggere immagini si adattano al design", "blocks": [{"kind": "p", "text": "Il vantaggio di Grok Build nel design deriva da due proprietà — ma, come per ogni agente, il gusto va comunque fornito."}, {"kind": "steps", "items": [{"label": "Ragionamento capace di leggere immagini", "body": "Poiché i modelli Grok accettano input di immagini, l'agente legge gli screenshot di riferimento — confrontando il suo output renderizzato con un'immagine invece di tirare a indovinare da una descrizione testuale."}, {"label": "Modalità di pianificazione prima che le modifiche vengano applicate", "body": "La modalità di pianificazione redige un approccio strutturato che approvi prima che i file cambino, così l'intento di design viene rivisto a monte invece di essere scoperto dopo il diff."}, {"label": "Convenzioni in AGENTS.md", "body": "Un AGENTS.md (più il server MCP Figma) indirizza l'agente verso i tuoi token, componenti e specifiche reali, così lavora su un brand invece che su un aspetto di default."}]}, {"kind": "image", "src": "/agents/grok-design/grok-design-taste-triangle.webp", "alt": "Diagramma che mostra design system, skill e immagine di riferimento che convergono in un buon output di design", "caption": "Il gusto nasce da tre input che fornisci tu: un design system, una skill e immagini di riferimento reali."}, {"kind": "p", "text": "La lezione è la stessa che insegna ogni agente: Grok Build non ha gusto di default. Produce un buon design quando gli dai vincoli — un design system, una skill estetica e riferimenti concreti. Open Design impacchetta esattamente quegli input, ed è per questo che i due si combinano bene (più avanti)."}]}, {"id": "setup", "heading": "Configurare Grok Build per il lavoro di design, da zero", "blocks": [{"kind": "p", "text": "Ecco il percorso completo da una macchina pulita a un Grok Build capace di costruire e verificare UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Grok Build (Grok Build) on macOS/Linux\ncurl -fsSL https://x.ai/cli/install.sh | bash\n\n# 2. Start it in your project and authenticate on first run\ncd your-project\ngrok login   # opens your browser; sign in with SuperGrok / X Premium+\n#   or, for headless / CI use, set an xAI API key:\n#   export XAI_API_KEY=xai-...\n\n# 3. Add project context\n#    create an AGENTS.md at the repo root with your design conventions\n\n# 4. Wire the Figma MCP server (optional, for design handoff)\n#    add it to your MCP server configuration"}, {"kind": "image", "src": "/agents/grok-design/grok-design-setup-flow.webp", "alt": "Flusso di configurazione in cinque passaggi: installa, autentica, configura AGENTS.md, aggiungi una skill, verifica", "caption": "La sequenza di configurazione: installa → autentica → configura AGENTS.md → aggiungi una skill → abilita la verifica nel browser."}, {"kind": "steps", "items": [{"label": "Codifica le tue regole di design", "body": "Metti i tuoi token, le primitive e le convenzioni in AGENTS.md e indirizza Grok verso di essi, così l'output corrisponde a un brand invece di ricadere su un aspetto generico."}, {"label": "Aggiungi la verifica nel browser", "body": "Collega un MCP Playwright o un browser MCP così Grok renderizza in un browser reale e controlla il suo output ai vari breakpoint invece di limitarsi a confermare che la build passa."}]}]}, {"id": "screenshot-workflow", "heading": "Il flusso di lavoro screenshot-to-UI", "blocks": [{"kind": "p", "text": "Il ciclo di design a maggiore leva con Grok Build consiste nel trasformare un'immagine di riferimento in una UI funzionante e responsive e iterare finché non corrisponde — appoggiandosi alla modalità di pianificazione per concordare l'approccio e al modello capace di leggere immagini per confrontare l'output con il riferimento."}, {"kind": "ol", "items": ["Parti dai riferimenti visivi più chiari che hai — e includi più stati (desktop e mobile, hover, vuoto, caricamento), non solo uno scatto hero.", "Sii specifico nel prompt; i prompt vaghi producono UI generiche anche con un modello forte.", "Mantieni il tuo design system e le convenzioni in AGENTS.md, e indica a Grok dove vivono i token e le primitive canoniche.", "Usa la modalità di pianificazione per rivedere l'approccio, poi avvia un dev server e fai renderizzare Grok in un browser reale, ridimensionando ai breakpoint per controllare il risultato.", "Itera facendo confrontare a Grok la sua implementazione con gli screenshot — non limitarti a confermare che fa la build."]}, {"kind": "p", "text": "Allega le tue immagini di riferimento e fornisci vincoli concreti:"}, {"kind": "code", "lang": "bash", "code": "grok\n# in the prompt (attach reference-desktop.png and reference-mobile.png):\n> Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from AGENTS.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Show me the plan first, then render it in the browser and iterate\n  until it matches the references across breakpoints."}, {"kind": "p", "text": "Mantieni i prompt piccoli e mirati, fai commit delle buone iterazioni e ripristina quelle cattive (dicendo a Grok quando fai un revert), così ogni passaggio parte da una base pulita."}]}, {"id": "extend", "heading": "AGENTS.md, MCP e subagent", "blocks": [{"kind": "p", "text": "Tre punti di estensione rendono Grok Build pratico per un lavoro di design continuativo, e tutti e tre si mappano in modo pulito su un flusso di lavoro di design aperto."}, {"kind": "steps", "items": [{"label": "Contesto AGENTS.md", "body": "Le regole del progetto vivono in un AGENTS.md alla radice del repository. È la sede stabile per le tue convenzioni di design, letta a ogni esecuzione — ed è lo stesso formato aperto che altri agenti comprendono, così le regole viaggiano con te."}, {"label": "Server MCP", "body": "Configura i server MCP per portare contesto di design e strumenti esterni, in particolare il server MCP Figma — il modo portatile per alimentare il codice con specifiche reali, che funziona tra agenti diversi e non solo con Grok."}, {"label": "Subagent e strumenti integrati", "body": "Grok Build può generare subagent paralleli per ricercare, costruire e revisionare contemporaneamente, e i suoi strumenti per file, shell e ricerca gli permettono di raccogliere riferimenti ed eseguire il ciclo di verifica senza lasciare il terminale."}]}, {"kind": "p", "text": "Sono capacità portatili e multi-agente — esattamente il tipo di cosa che Open Design è costruito per orchestrare, invece di ricrearle per ogni progetto."}]}, {"id": "vs", "heading": "Grok Build vs Codex vs Claude Code vs Cursor vs Gemini CLI per il design", "blocks": [{"kind": "p", "text": "Non c'è un unico vincitore per il lavoro di design — ogni agente ha un punto di forza diverso, e i team esperti li combinano. Un riepilogo onesto:"}, {"kind": "table", "columns": ["Agente", "Punto di forza nel design", "Ideale per"], "rows": [["Grok Build", "Revisione in modalità di pianificazione prima che le modifiche vengano applicate, modelli Grok capaci di leggere immagini e subagent paralleli; accede con il tuo account SuperGrok", "Build UI revisionate e plan-first con i modelli xAI nel ciclo"], ["Codex", "Forte rifinitura visiva con una skill frontend; build asincrone in sandbox", "Build asincrone delegate e regole AGENTS.md portatili"], ["Claude Code", "Decisioni di design specifiche (hex, spaziatura, tipografia) e UX consapevole del codebase", "Ragionamento sul frontend e refactoring a grande contesto"], ["Cursor", "Ciclo build-and-see visivo con anteprima live e modifiche inline", "Lavoro UI iterativo e a vista serrato dentro un IDE"], ["Gemini CLI", "Forte comprensione multimodale delle immagini e un contesto molto ampio; open-source con un tier gratuito", "Lavoro ricco di screenshot e tenere un intero design system nel contesto"]]}, {"kind": "p", "text": "Il verdetto ricorrente della community è che il gusto viene dagli esseri umani: tutti ricadono su un'estetica generica senza skill, riferimenti e vincoli. Questo è il vero problema da risolvere — ed è a forma di strumento di design, non di modello."}]}, {"id": "pitfalls", "heading": "Insidie, e come evitare l'estetica da “AI slop”", "blocks": [{"kind": "p", "text": "La lamentela più comune sul design generato dall'IA è che sembra generico — gradienti morbidi, pannelli fluttuanti, angoli arrotondati sovradimensionati, ombre drammatiche, un'atmosfera Inter-e-viola che “grida che l'ha fatto un'IA”. Altri problemi segnalati includono layout mobile rotti e istruzioni che si infiltrano nei testi della UI. Nessuno di questi è esclusivo di Grok Build; sono ciò che accade quando un qualsiasi agente gira senza un contesto di design curato."}, {"kind": "steps", "items": [{"label": "Aggiungi una skill estetica", "body": "Una skill di design curata costringe l'agente a impegnarsi su una direzione reale invece dell'aspetto di default."}, {"label": "Verifica in un browser reale", "body": "Renderizza e auto-controlla ai vari breakpoint così i layout non si rompono silenziosamente sul mobile."}, {"label": "Fornisci token e riferimenti", "body": "I token di design reali e gli screenshot di riferimento sono la singola leva più grande sulla qualità dell'output."}, {"label": "Codifica le regole in AGENTS.md", "body": "Metti regole di stile come “niente hero card, massimo due caratteri tipografici, gerarchia brand-first” dove l'agente le legge a ogni esecuzione."}]}, {"kind": "p", "text": "Nota che ogni mitigazione consiste nel dare all'agente un contesto di design curato. Mantenere quel contesto a mano, per ogni progetto, è la fatica che Open Design elimina."}]}, {"id": "open-design", "heading": "Progettare con Grok Build dentro Open Design", "blocks": [{"kind": "p", "text": "Open Design è il layer di design open-source che il flusso di lavoro qui sopra continua a richiedere. Tratta Grok Build come un adattatore di prima parte e lo avvolge in una libreria curata di skill e design system, in una pipeline di rendering strutturata e in una UI desktop locale — così il contesto di design che rende bravo Grok è presente dalla prima esecuzione, non assemblato a mano ogni volta. Open Design è indipendente e Apache-2.0, e gira sulla tua macchina, il che rende l'abbinamento un connubio naturale."}, {"kind": "ol", "items": ["Installa Open Design e seleziona Grok Build come tuo agente.", "Autenticati con il tuo account SuperGrok o un'API key xAI (BYOK) — le credenziali restano sulla tua macchina e non transitano mai tramite di noi.", "Scegli un design system e una skill, poi genera deck, prototipi e landing page con un gusto coerente.", "Ogni artefatto e ogni file DESIGN.md vive nel tuo repository, non in un cloud ospitato."]}, {"kind": "p", "text": "Stesso agente Grok Build, stesse credenziali — più un flusso di lavoro di design reale, portatile e open-source intorno a esso. È local-first e Apache-2.0, quindi nulla del tuo lavoro o delle tue credenziali lascia la tua macchina."}]}], "faqTitle": "Domande frequenti", "faq": [{"name": "Grok Build può davvero fare lavoro di design?", "text": "Sì — con una skill estetica, un design system e immagini di riferimento reali nel contesto, Grok Build produce UI responsive di qualità produttiva, e i suoi modelli Grok capaci di leggere immagini aiutano a verificare l'output rispetto ai riferimenti. Senza quel contesto tende a ricadere su un aspetto generico, ed è il divario che colma Open Design."}, {"name": "Come autentico Grok Build?", "text": "Accedi tramite il browser con un abbonamento SuperGrok o X Premium+ (`grok login`), così non c'è alcuna API key da gestire. Per l'uso headless o in CI puoi invece portare un'API key xAI. Open Design non fa mai da proxy alle tue credenziali in entrambi i casi."}, {"name": "Cosa rende Grok Build adatto specificamente al design?", "text": "Due cose: la sua modalità di pianificazione ti permette di rivedere l'approccio prima che venga applicata qualsiasi modifica, e i suoi modelli Grok accettano input di immagini, così legge bene gli screenshot di riferimento. Entrambe aiutano — ma il gusto viene comunque dal design system, dalla skill e dai riferimenti che fornisci tu."}, {"name": "Grok Build o Claude Code per il design frontend?", "text": "Entrambi sono forti. Claude Code è noto per decisioni di design specifiche e consapevoli del codebase; il vantaggio di Grok Build è la revisione in modalità di pianificazione e i modelli xAI capaci di leggere immagini. Molti team usano entrambi — Open Design ti permette di cambiare agente senza modificare il tuo flusso di lavoro di design."}, {"name": "Come collego Grok Build a Figma?", "text": "Aggiungi il server MCP Figma alla tua configurazione MCP. Grok può quindi recuperare contesto di design reale — componenti, variabili, dati di layout — così il codice generato corrisponde alla fonte invece di approssimarla."}, {"name": "Open Design è affiliato a xAI?", "text": "No. Grok Build è un prodotto di xAI; Open Design è un progetto open-source indipendente che lo supporta come adattatore di prima parte. Grok è un marchio di xAI."}, {"name": "I miei file e le mie credenziali sono al sicuro?", "text": "Sì — Open Design è local-first e Apache-2.0. I tuoi file, gli artefatti e DESIGN.md restano nel tuo repository, e le tue credenziali xAI sono usate direttamente dal tuo agente, mai instradate attraverso i server di Open Design."}], "ctaTitle": "Progetta con Grok Build, in modo aperto.", "ctaBody": "Porta il tuo account SuperGrok o la tua API key xAI, tieni ogni file in locale e ottieni una libreria di design curata intorno all'agente che già usi.", "ctaActions": [{"label": "Usa Grok Build dentro Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Metti una star su GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Scarica l'app desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Vedi tutti gli agenti supportati"},
      },
      'kimi': {
        ...en['kimi']!,
        title: "Kimi CLI per il design — Open Design",
        description: "Come si usa Kimi CLI di Moonshot AI per il design di UI e web — i suoi modelli agentici Kimi K2, l'ampio contesto, AGENTS.md e MCP — e come Open Design trasforma Kimi CLI in un agente di design open-source e local-first.",
        breadcrumb: "Kimi CLI",
        label: "Agente · Kimi CLI",
        heading: "Kimi CLI per il design.",
        lead: "Kimi CLI è l'agente open-source per il terminale di Moonshot AI, alimentato dalla serie di modelli Kimi K2. Il suo forte coding agentico e l'ampia finestra di contesto gli permettono di tenere un intero design system e iterare sui riferimenti — una volta che gli dai convenzioni e un ciclo di verifica, diventa un vero strumento di design. Open Design lo integra in un flusso di lavoro di design open-source: la tua API key Moonshot, i tuoi file, in modalità local-first.",
        rich: {"heroCtaLead": "Open Design trasforma Kimi CLI in un agente di design open-source e local-first — la tua API key Moonshot, i tuoi file, con intorno una libreria curata di skill e design system.", "heroCtaActions": [{"label": "Usa Kimi CLI dentro Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Metti una star su GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Scarica l'app desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Kimi CLI è l'agente IA open-source per il terminale di Moonshot AI. Due cose lo rendono interessante specificamente per il design: è alimentato dalla serie Kimi K2 — un modello mixture-of-experts da mille miliardi di parametri meticolosamente ottimizzato per il coding agentico e l'uso di strumenti; e quel modello ha un'ampia finestra di contesto (256k token nelle release recenti di K2), abbastanza grande da tenere in una sola volta un intero design system e codebase. Abbinato ai riferimenti, alle convenzioni e a un ciclo di verifica giusti, costruisce una UI reale e responsive — e puoi iniziare con un login OAuth o la tua API key Moonshot. Questa è una guida pratica ed end-to-end all'uso di Kimi CLI per il lavoro su UI, frontend e design system, e a integrarlo in un flusso di lavoro di design strutturato con Open Design.", "Copre cos'è davvero Kimi CLI, perché i suoi modelli agentici Kimi K2 e l'ampio contesto si adattano al design, come configurarlo da zero, il ciclo reference-to-UI, come AGENTS.md, MCP e i subagent lo estendono, come si confronta con Codex, Claude Code, Cursor e Gemini CLI, le insidie che fanno sembrare generico l'output dell'IA, e come Open Design colma il divario come layer di design aperto e local-first — un abbinamento naturale, poiché entrambi sono open-source e girano sulla tua macchina."], "heroImage": {"src": "/agents/kimi-design/kimi-design-hero.webp", "alt": "Ciclo di feedback del design con Kimi CLI: un agente nel terminale che legge un'immagine di riferimento, un browser che renderizza la UI e un workspace, con una freccia di feedback che torna indietro", "caption": "Il ciclo centrale: Kimi CLI legge i tuoi riferimenti nel terminale, costruisce e verifica la UI in un browser reale e itera su di essi — con un intero design system nel contesto."}, "tocLabel": "In questa pagina", "toc": [{"id": "what-is-kimi", "label": "Cos'è davvero Kimi CLI"}, {"id": "why-design", "label": "Perché K2 agentico + ampio contesto si adattano al design"}, {"id": "setup", "label": "Configurare Kimi CLI per il design (da zero)"}, {"id": "screenshot-workflow", "label": "Il flusso di lavoro reference-to-UI"}, {"id": "extend", "label": "AGENTS.md, MCP e subagent"}, {"id": "vs", "label": "Kimi CLI vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Insidie e l'estetica da “AI slop”"}, {"id": "open-design", "label": "Progettare con Kimi CLI in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-kimi", "heading": "Cos'è davvero Kimi CLI", "blocks": [{"kind": "p", "text": "Kimi CLI è un agente IA open-source (Apache-2.0) che Moonshot AI distribuisce per il terminale. Legge il tuo repository, modifica i file, esegue comandi shell, cerca file, recupera pagine web e sceglie il passo successivo dal feedback che riceve — pianificando e verificando il lavoro a partire da attività in linguaggio naturale invece di limitarsi a completare righe. È uno strumento Python, installato con uv, e guida dietro le quinte la famiglia di modelli Kimi K2."}, {"kind": "p", "text": "Per il lavoro di design spiccano due proprietà. I modelli Kimi K2 sono esplicitamente calibrati per il coding agentico a lungo orizzonte e l'uso di strumenti, così l'agente può portare a termine una build multi-passo fino a un risultato funzionante. E la finestra di contesto arriva fino a 256k token nelle release recenti di K2, abbastanza grande da tenere in una sola volta l'intero design system, la libreria di componenti e il set di riferimenti invece di riassumerli via."}, {"kind": "steps", "items": [{"label": "File di contesto", "body": "Kimi CLI legge un file AGENTS.md per un contesto di progetto persistente — il posto naturale dove codificare le tue convenzioni di design, i token e le checklist di revisione. Esegui /init per generarne uno per un progetto che ne è privo."}, {"label": "MCP, ACP + subagent", "body": "Gestisce i server MCP in modo conversazionale con /mcp-config, espone una sessione tramite l'Agent Client Protocol (kimi acp) a Zed e JetBrains, e può dispiegare subagent integrati coder, explore e plan in contesti isolati."}, {"label": "Login o BYOK", "body": "Al primo avvio, /login ti permette di autorizzare tramite OAuth (Kimi Code) o inserire la tua API key Moonshot; la piattaforma di Kimi espone anche endpoint compatibili con OpenAI e Anthropic."}]}, {"kind": "ul", "items": ["Fornitore: Moonshot AI", "Credenziale: API key Moonshot (BYOK), o login OAuth tramite Kimi Code", "Licenza: Apache-2.0, open source"]}]}, {"id": "why-design", "heading": "Perché i modelli agentici K2 e un ampio contesto si adattano al design", "blocks": [{"kind": "p", "text": "Il vantaggio di Kimi CLI nel design deriva da due proprietà del modello — ma, come per ogni agente, il gusto va comunque fornito."}, {"kind": "steps", "items": [{"label": "Coding agentico a lungo orizzonte", "body": "I modelli Kimi K2 sono ottimizzati per l'uso di strumenti e il lavoro multi-passo, così l'agente può prendere un riferimento e un brief e costruire, eseguire e rifinire davvero la UI invece di fermarsi a una prima bozza."}, {"label": "Un'ampia finestra di contesto", "body": "Fino a 256k token nelle release recenti di K2 significa che l'intero design system, i token e molti stati di riferimento entrano in una sola volta, così l'agente riutilizza le tue primitive reali invece di inventare stili una tantum."}, {"label": "Convenzioni in AGENTS.md", "body": "Un AGENTS.md (più un server MCP come Figma) indirizza l'agente verso i tuoi token, componenti e specifiche reali, così lavora su un brand invece che su un aspetto di default."}]}, {"kind": "image", "src": "/agents/kimi-design/kimi-design-taste-triangle.webp", "alt": "Diagramma che mostra design system, skill e immagine di riferimento che convergono in un buon output di design", "caption": "Il gusto nasce da tre input che fornisci tu: un design system, una skill e immagini di riferimento reali."}, {"kind": "p", "text": "La lezione è la stessa che insegna ogni agente: Kimi CLI non ha gusto di default. Produce un buon design quando gli dai vincoli — un design system, una skill estetica e riferimenti concreti. Open Design impacchetta esattamente quegli input, ed è per questo che i due si combinano bene (più avanti)."}]}, {"id": "setup", "heading": "Configurare Kimi CLI per il lavoro di design, da zero", "blocks": [{"kind": "p", "text": "Ecco il percorso completo da una macchina pulita a un Kimi CLI capace di costruire e verificare UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Kimi CLI (uses uv; Python 3.12–3.14, 3.13 recommended)\ncurl -LsSf https://code.kimi.com/install.sh | bash\n# or, if you already have uv:\nuv tool install --python 3.13 kimi-cli\n\n# 2. Start it in your project and authenticate on first run\ncd your-project\nkimi              # then run /login: OAuth via Kimi Code, or paste a Moonshot API key\n\n# 3. Generate project context\n/init             # scaffolds an AGENTS.md for this project\n\n# 4. Wire an MCP server (optional, e.g. Figma for design handoff)\n/mcp-config       # add, edit, and authenticate MCP servers conversationally"}, {"kind": "image", "src": "/agents/kimi-design/kimi-design-setup-flow.webp", "alt": "Flusso di configurazione in cinque passaggi: installa, autentica, configura AGENTS.md, aggiungi una skill, verifica", "caption": "La sequenza di configurazione: installa → autentica → configura AGENTS.md → aggiungi una skill → abilita la verifica nel browser."}, {"kind": "steps", "items": [{"label": "Codifica le tue regole di design", "body": "Metti i tuoi token, le primitive e le convenzioni in AGENTS.md e indirizza Kimi verso di essi, così l'output corrisponde a un brand invece di ricadere su un aspetto generico."}, {"label": "Aggiungi la verifica nel browser", "body": "Collega un MCP Playwright o un browser MCP così Kimi renderizza in un browser reale e controlla il suo output ai vari breakpoint invece di limitarsi a confermare che la build passa."}]}]}, {"id": "screenshot-workflow", "heading": "Il flusso di lavoro reference-to-UI", "blocks": [{"kind": "p", "text": "Il ciclo di design a maggiore leva con Kimi CLI consiste nel trasformare materiale di riferimento in una UI funzionante e responsive e iterare finché non corrisponde — alimentando l'agente con i tuoi riferimenti e facendogli confrontare il suo output renderizzato con essi in un browser reale."}, {"kind": "ol", "items": ["Parti dai riferimenti più chiari che hai — e includi più stati (desktop e mobile, hover, vuoto, caricamento), non solo uno scatto hero.", "Sii specifico nel prompt; i prompt vaghi producono UI generiche anche con un agente forte.", "Mantieni il tuo design system e le convenzioni in AGENTS.md, e indica a Kimi dove vivono i token e le primitive canoniche.", "Avvia un dev server e fai renderizzare Kimi in un browser reale, ridimensionando ai breakpoint per controllare il risultato.", "Itera facendo confrontare a Kimi la sua implementazione con i riferimenti — non limitarti a confermare che fa la build."]}, {"kind": "p", "text": "Indirizza Kimi verso i tuoi riferimenti e il dev server, poi fornisci vincoli concreti:"}, {"kind": "code", "lang": "bash", "code": "kimi\n# in the prompt:\n> Implement the design in ./references (reference-desktop.png,\n  reference-mobile.png) using React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from AGENTS.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Run the dev server, render it in the browser, and iterate until it\n  matches the references across breakpoints."}, {"kind": "p", "text": "Mantieni i prompt piccoli e mirati, fai commit delle buone iterazioni e ripristina quelle cattive (dicendo a Kimi quando fai un revert), così ogni passaggio parte da una base pulita. Kimi CLI può anche prendere una breve registrazione dello schermo o una clip dimostrativa quando un flusso è difficile da descrivere a parole."}]}, {"id": "extend", "heading": "AGENTS.md, MCP e subagent", "blocks": [{"kind": "p", "text": "Tre punti di estensione rendono Kimi CLI pratico per un lavoro di design continuativo, e tutti e tre si mappano in modo pulito su un flusso di lavoro di design aperto."}, {"kind": "steps", "items": [{"label": "Contesto AGENTS.md", "body": "Le regole del progetto vivono in un AGENTS.md alla radice del repository. È la sede stabile per le tue convenzioni di design, letta a ogni esecuzione — ed è lo stesso formato portatile che usano altri agenti."}, {"label": "Server MCP", "body": "Aggiungi server MCP in modo conversazionale con /mcp-config — il modo portatile per portare contesto di design e strumenti esterni, in particolare il server MCP Figma, che funzionano tra agenti diversi e non solo con Kimi."}, {"label": "Subagent e il marketplace di plugin", "body": "Dispiega subagent integrati coder, explore e plan in contesti isolati, e installa skill, server MCP e fonti di dati dal marketplace o da qualsiasi repository GitHub per raccogliere riferimenti ed eseguire il ciclo di verifica."}]}, {"kind": "p", "text": "Sono capacità portatili e multi-agente — esattamente il tipo di cosa che Open Design è costruito per orchestrare, invece di ricrearle per ogni progetto."}]}, {"id": "vs", "heading": "Kimi CLI vs Codex vs Claude Code vs Cursor vs Gemini CLI per il design", "blocks": [{"kind": "p", "text": "Non c'è un unico vincitore per il lavoro di design — ogni agente ha un punto di forza diverso, e i team esperti li combinano. Un riepilogo onesto:"}, {"kind": "table", "columns": ["Agente", "Punto di forza nel design", "Ideale per"], "rows": [["Kimi CLI", "Modelli agentici Kimi K2 calibrati per il coding a lungo orizzonte e l'uso di strumenti, con un grande contesto; open-source e BYOK", "Build multi-passo e tenere un intero design system nel contesto a costi contenuti"], ["Codex", "Forte rifinitura visiva con una skill frontend; build asincrone in sandbox", "Build asincrone delegate e regole AGENTS.md portatili"], ["Claude Code", "Decisioni di design specifiche (hex, spaziatura, tipografia) e UX consapevole del codebase", "Ragionamento sul frontend e refactoring a grande contesto"], ["Cursor", "Ciclo build-and-see visivo con anteprima live e modifiche inline", "Lavoro UI iterativo e a vista serrato dentro un IDE"], ["Gemini CLI", "Forte comprensione multimodale delle immagini e un contesto da 1M di token; tier gratuito", "Lavoro ricco di screenshot e contesto molto ampio"]]}, {"kind": "p", "text": "Il verdetto ricorrente della community è che il gusto viene dagli esseri umani: tutti ricadono su un'estetica generica senza skill, riferimenti e vincoli. Questo è il vero problema da risolvere — ed è a forma di strumento di design, non di modello."}]}, {"id": "pitfalls", "heading": "Insidie, e come evitare l'estetica da “AI slop”", "blocks": [{"kind": "p", "text": "La lamentela più comune sul design generato dall'IA è che sembra generico — gradienti morbidi, pannelli fluttuanti, angoli arrotondati sovradimensionati, ombre drammatiche, un'atmosfera Inter-e-viola che “grida che l'ha fatto un'IA”. Altri problemi segnalati includono layout mobile rotti e istruzioni che si infiltrano nei testi della UI. Nessuno di questi è esclusivo di Kimi CLI; sono ciò che accade quando un qualsiasi agente gira senza un contesto di design curato."}, {"kind": "steps", "items": [{"label": "Aggiungi una skill estetica", "body": "Una skill di design curata costringe l'agente a impegnarsi su una direzione reale invece dell'aspetto di default."}, {"label": "Verifica in un browser reale", "body": "Fai renderizzare e auto-controllare Kimi ai vari breakpoint così i layout non si rompono silenziosamente sul mobile."}, {"label": "Fornisci token e riferimenti", "body": "I token di design reali e gli screenshot di riferimento sono la singola leva più grande sulla qualità dell'output."}, {"label": "Codifica le regole in AGENTS.md", "body": "Metti regole di stile come “niente hero card, massimo due caratteri tipografici, gerarchia brand-first” dove l'agente le legge a ogni esecuzione."}]}, {"kind": "p", "text": "Nota che ogni mitigazione consiste nel dare all'agente un contesto di design curato. Mantenere quel contesto a mano, per ogni progetto, è la fatica che Open Design elimina."}]}, {"id": "open-design", "heading": "Progettare con Kimi CLI dentro Open Design", "blocks": [{"kind": "p", "text": "Open Design è il layer di design open-source che il flusso di lavoro qui sopra continua a richiedere. Tratta Kimi CLI come un adattatore di prima parte e lo avvolge in una libreria curata di skill e design system, in una pipeline di rendering strutturata e in una UI desktop locale — così il contesto di design che rende bravo Kimi è presente dalla prima esecuzione, non assemblato a mano ogni volta. Entrambi sono open-source e local-first, il che rende l'abbinamento un connubio naturale."}, {"kind": "ol", "items": ["Installa Open Design e seleziona Kimi CLI come tuo agente.", "Autenticati con la tua API key Moonshot (BYOK) — le credenziali restano sulla tua macchina e non transitano mai tramite di noi.", "Scegli un design system e una skill, poi genera deck, prototipi e landing page con un gusto coerente.", "Ogni artefatto e ogni file DESIGN.md vive nel tuo repository, non in un cloud ospitato."]}, {"kind": "p", "text": "Stesso agente Kimi CLI, stessa chiave — più un flusso di lavoro di design reale, portatile e open-source intorno a esso. È local-first e Apache-2.0, quindi nulla del tuo lavoro o delle tue credenziali lascia la tua macchina."}]}], "faqTitle": "Domande frequenti", "faq": [{"name": "Kimi CLI può davvero fare lavoro di design?", "text": "Sì — con una skill estetica, un design system e immagini di riferimento reali nel contesto, Kimi CLI produce UI responsive di qualità produttiva, e i suoi modelli agentici Kimi K2 possono renderizzare e verificare l'output rispetto ai riferimenti. Senza quel contesto tende a ricadere su un aspetto generico, ed è il divario che colma Open Design."}, {"name": "Devo pagare per progettare con Kimi CLI?", "text": "Porti le tue credenziali: autorizza tramite il login OAuth di Kimi Code o incolla un'API key Moonshot (BYOK), fatturata dalla piattaforma di Moonshot. Open Design non fa mai da proxy alle tue credenziali in entrambi i casi."}, {"name": "Cosa rende Kimi CLI adatto specificamente al design?", "text": "Due cose: i modelli Kimi K2 sono calibrati per il coding agentico a lungo orizzonte e l'uso di strumenti, così l'agente può costruire e rifinire fino a un risultato funzionante, e la finestra di contesto arriva fino a 256k token, abbastanza da tenere in una sola volta un intero design system e set di riferimenti. Entrambe aiutano — ma il gusto viene comunque dal design system, dalla skill e dai riferimenti che fornisci tu."}, {"name": "Kimi CLI o Claude Code per il design frontend?", "text": "Entrambi sono forti. Claude Code è noto per decisioni di design specifiche e consapevoli del codebase; il vantaggio di Kimi CLI sono i suoi modelli agentici Kimi K2 e un grande contesto con un'economia BYOK. Molti team usano entrambi — Open Design ti permette di cambiare agente senza modificare il tuo flusso di lavoro di design."}, {"name": "Come collego Kimi CLI a Figma?", "text": "Esegui /mcp-config dentro Kimi CLI per aggiungere e autenticare il server MCP Figma. Kimi può quindi recuperare contesto di design reale — componenti, variabili, dati di layout — così il codice generato corrisponde alla fonte invece di approssimarla."}, {"name": "Open Design è affiliato a Moonshot AI?", "text": "No. Kimi CLI è un prodotto di Moonshot AI; Open Design è un progetto open-source indipendente che lo supporta come adattatore di prima parte. Kimi è un marchio di Moonshot AI."}, {"name": "I miei file e le mie credenziali sono al sicuro?", "text": "Sì — Open Design è local-first e Apache-2.0. I tuoi file, gli artefatti e DESIGN.md restano nel tuo repository, e le tue credenziali Moonshot sono usate direttamente dal tuo agente, mai instradate attraverso i server di Open Design."}], "ctaTitle": "Progetta con Kimi CLI, in modo aperto.", "ctaBody": "Porta la tua API key Moonshot, tieni ogni file in locale e ottieni una libreria di design curata intorno all'agente che già usi.", "ctaActions": [{"label": "Usa Kimi CLI dentro Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Metti una star su GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Scarica l'app desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Vedi tutti gli agenti supportati"},
      },
      'deepseek': {
        ...en['deepseek']!,
        title: "DeepSeek TUI per il design — Open Design",
        description: "Come si usa un agente di coding da terminale basato su DeepSeek per il design di UI e web — i suoi forti modelli di coding, il contesto da 1M di token, l'efficienza sui costi, i file di contesto e MCP — e come Open Design trasforma la DeepSeek TUI in un agente di design open-source e local-first.",
        breadcrumb: "DeepSeek TUI",
        label: "Agente · DeepSeek TUI",
        heading: "DeepSeek TUI per il design.",
        lead: "DeepSeek TUI è un agente di coding da terminale guidato dai modelli di DeepSeek. I suoi forti modelli di coding a costi contenuti e il contesto da 1M di token possono tenere in una sola volta un intero design system e codebase, il che lo rende un vero strumento di design — una volta che gli fornisci riferimenti, convenzioni e un ciclo di verifica. Open Design lo integra in un flusso di lavoro di design open-source: la tua API key DeepSeek, i tuoi file, in modalità local-first.",
        rich: {"heroCtaLead": "Open Design trasforma la DeepSeek TUI in un agente di design open-source e local-first — la tua API key DeepSeek, i tuoi file, con intorno una libreria curata di skill e design system.", "heroCtaActions": [{"label": "Usa DeepSeek TUI dentro Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Metti una star su GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Scarica l'app desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["DeepSeek TUI è un agente di coding IA basato su terminale alimentato dai modelli di DeepSeek. Due cose lo rendono interessante specificamente per il design: i suoi modelli di coding sono forti e insolitamente efficienti sui costi, così puoi iterare in modo aggressivo senza tenere d'occhio un contatore; e la sua finestra di contesto arriva fino a 1M di token, abbastanza grande da tenere in una sola volta un intero design system e codebase invece di riassumerli via. Abbinato ai riferimenti, alle convenzioni e a un ciclo di verifica giusti, costruisce una UI reale e responsive. Questa è una guida pratica ed end-to-end all'uso di un agente da terminale basato su DeepSeek per il lavoro su UI, frontend e design system, e a integrarlo in un flusso di lavoro di design strutturato con Open Design.", "Copre cos'è davvero la DeepSeek TUI, perché forti modelli di coding, un contesto enorme e un basso costo si adattano al design, come configurarla da zero, il ciclo reference-to-UI, come i file di contesto e MCP la estendono, come si confronta con Codex, Claude Code, Cursor e Gemini CLI, le insidie che fanno sembrare generico l'output dell'IA, e come Open Design colma il divario come layer di design aperto e local-first — un abbinamento naturale, poiché entrambi sono aperti e girano sulla tua macchina."], "heroImage": {"src": "/agents/deepseek-design/deepseek-design-hero.webp", "alt": "Ciclo di feedback del design con DeepSeek TUI: un agente nel terminale che legge riferimenti e convenzioni, un browser che renderizza la UI e un workspace, con una freccia di feedback che torna indietro", "caption": "Il ciclo centrale: DeepSeek TUI legge i tuoi riferimenti e le convenzioni nel terminale, costruisce e verifica la UI in un browser reale e itera su di essi — con un intero design system nel contesto."}, "tocLabel": "In questa pagina", "toc": [{"id": "what-is-deepseek", "label": "Cos'è davvero DeepSeek TUI"}, {"id": "why-design", "label": "Perché forti modelli di coding + contesto enorme si adattano al design"}, {"id": "setup", "label": "Configurare DeepSeek TUI per il design (da zero)"}, {"id": "screenshot-workflow", "label": "Il flusso di lavoro reference-to-UI"}, {"id": "extend", "label": "File di contesto, MCP e strumenti"}, {"id": "vs", "label": "DeepSeek TUI vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Insidie e l'estetica da “AI slop”"}, {"id": "open-design", "label": "Progettare con DeepSeek TUI in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-deepseek", "heading": "Cos'è davvero DeepSeek TUI", "blocks": [{"kind": "p", "text": "Una DeepSeek TUI è un agente IA da terminale guidato da tastiera che esegue i modelli di DeepSeek. Legge il tuo repository, modifica i file, esegue comandi shell, gestisce git e può cercare sul web — pianificando e verificando il lavoro a partire da attività in linguaggio naturale invece di limitarsi a completare righe. DeepSeek stesso è il fornitore dei modelli: un'API compatibile con OpenAI (espone anche un endpoint in formato Anthropic), così un'ampia gamma di agenti da terminale della community può essere puntata su DeepSeek impostando una base URL e una chiave. Diverse TUI open-source distribuiscono DeepSeek come provider di prima classe."}, {"kind": "p", "text": "Per il lavoro di design spiccano tre proprietà. I modelli di coding di DeepSeek sono forti, così l'agente ragiona su layout, struttura e gerarchia dei componenti a partire da una descrizione chiara. La sua finestra di contesto arriva fino a 1M di token, abbastanza grande da tenere in una sola volta l'intero design system e la libreria di componenti. E i suoi prezzi sono molto bassi per token, con in più il context-caching dei prefissi — così iterare su un design costa poco."}, {"kind": "steps", "items": [{"label": "File di contesto", "body": "Gli agenti da terminale leggono un file di contesto di progetto (un file in stile AGENTS.md, o la convenzione propria dell'agente) per le regole persistenti — il posto naturale dove codificare le tue convenzioni di design, i token e le checklist di revisione."}, {"label": "Strumenti + MCP", "body": "La maggior parte delle DeepSeek TUI distribuisce strumenti per file, shell, git e web, e supporta server MCP per aggiungere contesto esterno come un file Figma live — l'API di DeepSeek supporta il tool calling, su cui questi agenti fanno affidamento."}, {"label": "Porta la tua chiave", "body": "Ti autentichi con un'API key DeepSeek dalla piattaforma DeepSeek. Poiché l'API è compatibile con OpenAI, puntare un agente su DeepSeek di solito sono due righe: base URL e chiave."}]}, {"kind": "ul", "items": ["Fornitore: DeepSeek (fornitore di modelli e API)", "Credenziale: API key DeepSeek (BYOK) dalla piattaforma DeepSeek", "Modelli: deepseek-v4-flash e deepseek-v4-pro (solo testo; nessun input nativo di immagini)"]}]}, {"id": "why-design", "heading": "Perché forti modelli di coding e un contesto enorme si adattano al design", "blocks": [{"kind": "p", "text": "Il vantaggio della DeepSeek TUI nel design deriva dal modello e dalla sua economia — ma, come per ogni agente, il gusto va comunque fornito."}, {"kind": "steps", "items": [{"label": "Coding forte ed efficiente sui costi", "body": "I modelli di coding di DeepSeek sono capaci ed economici, così l'agente ragiona bene su layout e struttura e puoi iterare molte volte senza che il costo sia il vincolo."}, {"label": "Una finestra di contesto da 1M di token", "body": "Un grande contesto significa che l'intero design system, i token e molti stati di riferimento entrano in una sola volta, così l'agente riutilizza le tue primitive reali invece di inventare stili una tantum — e il context caching mantiene economici i prompt ripetuti."}, {"label": "Convenzioni in un file di contesto", "body": "Un file di contesto di progetto (più il server MCP Figma) indirizza l'agente verso i tuoi token, componenti e specifiche reali, così lavora su un brand invece che su un aspetto di default."}]}, {"kind": "image", "src": "/agents/deepseek-design/deepseek-design-taste-triangle.webp", "alt": "Diagramma che mostra design system, skill e riferimento che convergono in un buon output di design", "caption": "Il gusto nasce da tre input che fornisci tu: un design system, una skill e riferimenti reali."}, {"kind": "p", "text": "La lezione è la stessa che insegna ogni agente: DeepSeek TUI non ha gusto di default. Produce un buon design quando gli dai vincoli — un design system, una skill estetica e riferimenti concreti. Open Design impacchetta esattamente quegli input, ed è per questo che i due si combinano bene (più avanti)."}]}, {"id": "setup", "heading": "Configurare DeepSeek TUI per il lavoro di design, da zero", "blocks": [{"kind": "p", "text": "Ecco il percorso completo da una macchina pulita a una DeepSeek TUI capace di costruire e verificare UI. I nomi esatti di installazione e dei comandi variano a seconda dell'agente da terminale che scegli, quindi i passaggi qui sotto restano al livello che vale per tutti."}, {"kind": "code", "lang": "bash", "code": "# 1. Get a DeepSeek API key from the DeepSeek platform\n#    https://platform.deepseek.com\nexport DEEPSEEK_API_KEY=sk-...\n\n# 2. Install a DeepSeek-capable terminal agent (follow its README),\n#    then point it at DeepSeek. The API is OpenAI-compatible:\n#      base URL: https://api.deepseek.com\n#      model:    deepseek-v4-flash (or deepseek-v4-pro)\n#    (an Anthropic-format endpoint also exists at /anthropic)\n\n# 3. Start it in your project and generate project context\ncd your-project\n#   create/scaffold a project context file with your design rules\n\n# 4. Wire the Figma MCP server (optional, for design handoff)\n#    add it to the agent's MCP server configuration"}, {"kind": "image", "src": "/agents/deepseek-design/deepseek-design-setup-flow.webp", "alt": "Flusso di configurazione in cinque passaggi: ottieni la chiave, installa l'agente, configura il file di contesto, aggiungi una skill, verifica", "caption": "La sequenza di configurazione: ottieni una chiave → punta l'agente su DeepSeek → configura un file di contesto → aggiungi una skill → abilita la verifica nel browser."}, {"kind": "steps", "items": [{"label": "Codifica le tue regole di design", "body": "Metti i tuoi token, le primitive e le convenzioni nel file di contesto dell'agente e indirizzalo verso di essi, così l'output corrisponde a un brand invece di ricadere su un aspetto generico."}, {"label": "Aggiungi la verifica nel browser", "body": "Collega un MCP Playwright o un browser MCP così l'agente renderizza in un browser reale e controlla il suo output ai vari breakpoint invece di limitarsi a confermare che la build passa."}]}]}, {"id": "screenshot-workflow", "heading": "Il flusso di lavoro reference-to-UI", "blocks": [{"kind": "p", "text": "I modelli di DeepSeek sono solo testo — non leggono immagini in modo nativo — quindi il ciclo di design a maggiore leva consiste nel trasformare riferimenti chiari e layout descritti in una UI funzionante e responsive, poi verificare il risultato in un browser reale invece di chiedere al modello di guardare uno screenshot."}, {"kind": "ol", "items": ["Parti dai riferimenti più chiari che hai — e descrivi più stati (desktop e mobile, hover, vuoto, caricamento), non solo uno scatto hero.", "Sii specifico nel prompt; i prompt vaghi producono UI generiche anche con un modello forte. Esplicita la spaziatura, la gerarchia e i componenti da riutilizzare.", "Mantieni il tuo design system e le convenzioni nel file di contesto, e indica all'agente dove vivono i token e le primitive canoniche.", "Avvia un dev server e fai renderizzare l'agente in un browser reale, ridimensionando ai breakpoint per controllare il risultato — è qui che avviene la verifica, dato che il modello non può vedere l'immagine stessa.", "Itera facendo confrontare all'agente il DOM renderizzato e gli stili computati con la tua specifica descritta — non limitarti a confermare che fa la build."]}, {"kind": "p", "text": "Descrivi il target con precisione e fornisci vincoli concreti:"}, {"kind": "code", "lang": "bash", "code": "# in the agent's prompt:\n> Implement this design in React + Vite + Tailwind + TypeScript.\n  Layout: two-column dashboard, 240px sidebar, 24px gutters,\n  card grid at 3/2/1 columns for desktop/tablet/mobile.\n  Reuse my existing design-system components and tokens from the\n  context file. Match spacing, layout, and hierarchy; make it responsive.\n  Run the dev server, render it in the browser, and iterate against the\n  spec across breakpoints until it matches."}, {"kind": "p", "text": "Mantieni i prompt piccoli e mirati, fai commit delle buone iterazioni e ripristina quelle cattive (dicendo all'agente quando fai un revert), così ogni passaggio parte da una base pulita."}]}, {"id": "extend", "heading": "File di contesto, MCP e strumenti", "blocks": [{"kind": "p", "text": "Tre punti di estensione rendono una DeepSeek TUI pratica per un lavoro di design continuativo, e tutti e tre si mappano in modo pulito su un flusso di lavoro di design aperto."}, {"kind": "steps", "items": [{"label": "File di contesto di progetto", "body": "Le regole del progetto vivono in un file di contesto alla radice del repository (con livelli globale e di team). È la sede stabile per le tue convenzioni di design, letta a ogni esecuzione."}, {"label": "Server MCP", "body": "Configura i server MCP nell'agente — il modo portatile per portare contesto di design e strumenti esterni, in particolare il server MCP Figma, che funzionano tra agenti diversi e non solo con uno. L'API di DeepSeek supporta il tool calling su cui questi server fanno affidamento."}, {"label": "Strumenti integrati", "body": "Le DeepSeek TUI distribuiscono strumenti per file, shell, git e web così l'agente può raccogliere riferimenti ed eseguire il ciclo di verifica senza lasciare il terminale."}]}, {"kind": "p", "text": "Sono capacità portatili e multi-agente — esattamente il tipo di cosa che Open Design è costruito per orchestrare, invece di ricrearle per ogni progetto."}]}, {"id": "vs", "heading": "DeepSeek TUI vs Codex vs Claude Code vs Cursor vs Gemini CLI per il design", "blocks": [{"kind": "p", "text": "Non c'è un unico vincitore per il lavoro di design — ogni agente ha un punto di forza diverso, e i team esperti li combinano. Un riepilogo onesto:"}, {"kind": "table", "columns": ["Agente", "Punto di forza nel design", "Ideale per"], "rows": [["DeepSeek TUI", "Modelli di coding forti e molto efficienti sui costi con pesi aperti e un contesto da 1M di token; solo testo (nessuna visione nativa)", "Iterazione ad alto volume con budget contenuto e tenere un intero design system nel contesto"], ["Codex", "Forte rifinitura visiva con una skill frontend; build asincrone in sandbox", "Build asincrone delegate e regole AGENTS.md portatili"], ["Claude Code", "Decisioni di design specifiche (hex, spaziatura, tipografia) e UX consapevole del codebase", "Ragionamento sul frontend e refactoring a grande contesto"], ["Cursor", "Ciclo build-and-see visivo con anteprima live e modifiche inline", "Lavoro UI iterativo e a vista serrato dentro un IDE"], ["Gemini CLI", "Comprensione multimodale nativa delle immagini e un contesto da 1M di token; open-source con un tier gratuito", "Lavoro ricco di screenshot dove l'agente legge direttamente i riferimenti"]]}, {"kind": "p", "text": "Il verdetto ricorrente della community è che il gusto viene dagli esseri umani: tutti ricadono su un'estetica generica senza skill, riferimenti e vincoli. Questo è il vero problema da risolvere — ed è a forma di strumento di design, non di modello."}]}, {"id": "pitfalls", "heading": "Insidie, e come evitare l'estetica da “AI slop”", "blocks": [{"kind": "p", "text": "La lamentela più comune sul design generato dall'IA è che sembra generico — gradienti morbidi, pannelli fluttuanti, angoli arrotondati sovradimensionati, ombre drammatiche, un'atmosfera Inter-e-viola che “grida che l'ha fatto un'IA”. Altri problemi segnalati includono layout mobile rotti e istruzioni che si infiltrano nei testi della UI. Nessuno di questi è esclusivo di DeepSeek TUI; sono ciò che accade quando un qualsiasi agente gira senza un contesto di design curato. Poiché DeepSeek è solo testo, è particolarmente importante verificare in un browser reale invece di fidarsi che il modello “guardi” il risultato."}, {"kind": "steps", "items": [{"label": "Aggiungi una skill estetica", "body": "Una skill di design curata costringe l'agente a impegnarsi su una direzione reale invece dell'aspetto di default."}, {"label": "Verifica in un browser reale", "body": "Renderizza e auto-controlla ai vari breakpoint con uno strumento browser — essenziale qui, dato che il modello non può leggere uno screenshot da solo — così i layout non si rompono silenziosamente sul mobile."}, {"label": "Fornisci token e riferimenti", "body": "I token di design reali e i riferimenti concreti e descritti sono la singola leva più grande sulla qualità dell'output."}, {"label": "Codifica le regole nel file di contesto", "body": "Metti regole di stile come “niente hero card, massimo due caratteri tipografici, gerarchia brand-first” dove l'agente le legge a ogni esecuzione."}]}, {"kind": "p", "text": "Nota che ogni mitigazione consiste nel dare all'agente un contesto di design curato. Mantenere quel contesto a mano, per ogni progetto, è la fatica che Open Design elimina."}]}, {"id": "open-design", "heading": "Progettare con DeepSeek TUI dentro Open Design", "blocks": [{"kind": "p", "text": "Open Design è il layer di design open-source che il flusso di lavoro qui sopra continua a richiedere. Tratta l'agente DeepSeek come un adattatore di prima parte e lo avvolge in una libreria curata di skill e design system, in una pipeline di rendering strutturata e in una UI desktop locale — così il contesto di design che rende bravo DeepSeek è presente dalla prima esecuzione, non assemblato a mano ogni volta. Entrambi sono aperti e local-first, il che rende l'abbinamento un connubio naturale."}, {"kind": "ol", "items": ["Installa Open Design e seleziona la DeepSeek TUI come tuo agente.", "Autenticati con la tua API key DeepSeek (BYOK) — le credenziali restano sulla tua macchina e non transitano mai tramite di noi.", "Scegli un design system e una skill, poi genera deck, prototipi e landing page con un gusto coerente.", "Ogni artefatto e ogni file DESIGN.md vive nel tuo repository, non in un cloud ospitato."]}, {"kind": "p", "text": "Stesso agente DeepSeek, stessa chiave — più un flusso di lavoro di design reale, portatile e open-source intorno a esso. È local-first e Apache-2.0, quindi nulla del tuo lavoro o delle tue credenziali lascia la tua macchina."}]}], "faqTitle": "Domande frequenti", "faq": [{"name": "DeepSeek TUI può davvero fare lavoro di design?", "text": "Sì — con una skill estetica, un design system e riferimenti concreti nel contesto, un agente da terminale basato su DeepSeek produce UI responsive di qualità produttiva, e verifichi l'output in un browser reale. I modelli di DeepSeek sono solo testo, quindi il ciclo di verifica sostituisce la lettura nativa delle immagini. Senza quel contesto tende a ricadere su un aspetto generico, ed è il divario che colma Open Design."}, {"name": "Quanto costa progettare con DeepSeek TUI?", "text": "Poco — l'API di DeepSeek è tra le più economiche per token, e il context-caching dei prefissi riduce ulteriormente il costo dei prompt ripetuti, così puoi iterare in modo aggressivo. Porti la tua API key DeepSeek (BYOK); Open Design non fa mai da proxy alle tue credenziali."}, {"name": "Cosa rende DeepSeek adatto specificamente al design?", "text": "Modelli di coding forti ed efficienti sui costi, pesi aperti e un contesto da 1M di token che tiene in una sola volta un intero design system e set di riferimenti. DeepSeek è solo testo — non legge immagini in modo nativo — quindi il gusto viene comunque dal design system, dalla skill e dai riferimenti descritti che fornisci tu, verificati in un browser."}, {"name": "DeepSeek TUI o Claude Code per il design frontend?", "text": "Entrambi sono forti. Claude Code è noto per decisioni di design specifiche e consapevoli del codebase; il vantaggio della DeepSeek TUI sono i pesi aperti, il costo molto basso e un contesto enorme per l'iterazione ad alto volume. Molti team usano entrambi — Open Design ti permette di cambiare agente senza modificare il tuo flusso di lavoro di design."}, {"name": "Come collego DeepSeek TUI a Figma?", "text": "Aggiungi il server MCP Figma nella configurazione MCP del tuo agente da terminale. L'agente può quindi recuperare contesto di design reale — componenti, variabili, dati di layout — così il codice generato corrisponde alla fonte invece di approssimarla. L'API di DeepSeek supporta il tool calling su cui MCP fa affidamento."}, {"name": "Open Design è affiliato a DeepSeek?", "text": "No. DeepSeek è il fornitore dei modelli e dell'API; Open Design è un progetto open-source indipendente che supporta gli agenti da terminale basati su DeepSeek come adattatore di prima parte. DeepSeek è un marchio di DeepSeek."}, {"name": "I miei file e le mie credenziali sono al sicuro?", "text": "Sì — Open Design è local-first e Apache-2.0. I tuoi file, gli artefatti e DESIGN.md restano nel tuo repository, e la tua API key DeepSeek è usata direttamente dal tuo agente, mai instradata attraverso i server di Open Design."}], "ctaTitle": "Progetta con DeepSeek TUI, in modo aperto.", "ctaBody": "Porta la tua API key DeepSeek, tieni ogni file in locale e ottieni una libreria di design curata intorno all'agente che già usi.", "ctaActions": [{"label": "Usa DeepSeek TUI dentro Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Metti una star su GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Scarica l'app desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Vedi tutti gli agenti supportati"},
      },
      'trae-cli': {
        ...en['trae-cli']!,
        title: "Trae CLI per il design — Open Design",
        description: "Come si usa il Trae CLI di ByteDance (trae-agent) per il design di UI e web — il suo agente CLI open source e indipendente dal modello, la possibilità di portare il proprio provider LLM e il flusso di lavoro guidato dalla configurazione — e come Open Design trasforma Trae CLI in un agente di design open source e local-first tramite ACP.",
        breadcrumb: "Trae CLI",
        label: "Agente · Trae CLI",
        heading: "Trae CLI per il design.",
        lead: "Trae CLI è l'agente da terminale open source di ByteDance (trae-agent). È indipendente dal modello — lo punti verso il provider LLM di cui ti fidi — e legge il tuo repository, modifica i file ed esegue comandi a partire da task in linguaggio naturale, il che lo rende un vero strumento di design una volta che gli fornisci riferimenti, convenzioni e un ciclo di verifica. Open Design lo collega a un flusso di lavoro di design open source tramite ACP: la tua chiave del provider, i tuoi file, local-first.",
        rich: {"heroCtaLead": "Open Design trasforma Trae CLI in un agente di design open source e local-first — la tua chiave del provider LLM, i tuoi file, una libreria curata di skill e design system attorno ad esso, pilotata tramite ACP.", "heroCtaActions": [{"label": "Usa Trae CLI dentro Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Metti una stella su GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Scarica l'app desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Trae CLI è l'agente AI open source di ByteDance per il terminale, distribuito come progetto trae-agent. Due caratteristiche lo rendono interessante per il design in particolare: è indipendente dal modello, quindi puoi portare il provider LLM di cui ti fidi invece di restare vincolato a un solo fornitore; ed è un agente trasparente, rilasciato con licenza MIT, che legge il tuo codebase, modifica i file ed esegue comandi shell a partire da task in linguaggio naturale. Abbinato ai riferimenti giusti, alle convenzioni e a un ciclo di verifica, costruisce UI reali e responsive — ed è gratuito e aperto per iniziare, devi solo fornire una chiave del provider. Questa è una guida pratica ed end-to-end all'uso di Trae CLI per il lavoro su UI, frontend e design system, e a come integrarlo in un flusso di lavoro di design strutturato con Open Design.", "Copre cos'è realmente Trae CLI, perché un agente aperto e indipendente dal modello si adatta al design, come configurarlo da zero, il ciclo dallo screenshot all'UI, come il suo file di configurazione e i suoi strumenti lo estendono, come si confronta con Codex, Claude Code, Cursor e Gemini CLI, le insidie che fanno sembrare generico l'output dell'AI, e come Open Design colma il divario come livello di design aperto e local-first — un abbinamento naturale, dato che entrambi sono open source e girano sulla tua macchina, con Open Design che pilota Trae CLI tramite l'Agent Client Protocol (ACP)."], "heroImage": {"src": "/agents/trae-cli-design/trae-cli-design-hero.webp", "alt": "Ciclo di feedback del design con Trae CLI: un agente da terminale che legge un'immagine di riferimento, un browser che renderizza l'UI e un workspace, con una freccia di feedback che ritorna", "caption": "Il ciclo centrale: Trae CLI legge i tuoi riferimenti e le tue convenzioni nel terminale, costruisce e verifica l'UI in un browser reale, e itera in base ad essi."}, "tocLabel": "In questa pagina", "toc": [{"id": "what-is-trae-cli", "label": "Cos'è realmente Trae CLI"}, {"id": "why-design", "label": "Perché un agente aperto e indipendente dal modello si adatta al design"}, {"id": "setup", "label": "Configura Trae CLI per il design (da zero)"}, {"id": "screenshot-workflow", "label": "Il flusso di lavoro dallo screenshot all'UI"}, {"id": "extend", "label": "Configurazione, strumenti e provider"}, {"id": "vs", "label": "Trae CLI vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Insidie e l'aspetto da “AI slop”"}, {"id": "open-design", "label": "Progettare con Trae CLI in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-trae-cli", "heading": "Cos'è realmente Trae CLI", "blocks": [{"kind": "p", "text": "Trae CLI è l'agente da riga di comando del progetto open source trae-agent di ByteDance. Legge il tuo repository, visualizza, crea e modifica i file, ed esegue comandi shell in un ambiente persistente — pianificando e verificando il lavoro a partire da task in linguaggio naturale anziché limitarsi a completare righe. È rilasciato con licenza MIT e costruito attorno a un'architettura trasparente e modulare, così è facile da ispezionare ed estendere. È distinto dal separato Trae IDE, l'editor AI di ByteDance basato su VS Code, anche se entrambi provengono dallo stesso fornitore."}, {"kind": "p", "text": "Per il lavoro di design spiccano due proprietà. È indipendente dal modello — scegli tu il provider LLM, quindi non sei mai legato ai punti di forza o ai limiti di un singolo modello. Ed è completamente aperto e guidato dalla configurazione, così il suo comportamento, i suoi strumenti e il suo provider possono essere fissati nel version control insieme al tuo progetto, anziché nascosti dietro un servizio ospitato."}, {"kind": "steps", "items": [{"label": "Modalità run e interattiva", "body": "Trae CLI esegue un singolo task con `trae-cli run \"...\"` oppure mantiene una sessione continua con `trae-cli interactive` — il luogo naturale per iterare su un'UI rispetto alle tue convenzioni di design."}, {"label": "Strumenti integrati", "body": "Include strumenti di editing dei file, esecuzione bash/shell e ragionamento strutturato di serie, così può costruire, avviare un dev server e ispezionare gli errori a runtime senza lasciare il terminale."}, {"label": "Porta il tuo provider", "body": "Fornisci una chiave API per il provider di cui ti fidi — OpenAI, Anthropic, Google, OpenRouter, Doubao, Azure o un modello Ollama locale — tramite variabili d'ambiente o un file di configurazione."}]}, {"kind": "ul", "items": ["Fornitore: ByteDance (progetto open source trae-agent)", "Credenziale: una chiave API di un provider LLM (BYOK) — ad es. OpenAI, Anthropic, Google, OpenRouter, Doubao, Azure o un modello Ollama locale", "Licenza: MIT, open source"]}]}, {"id": "why-design", "heading": "Perché un agente aperto e indipendente dal modello si adatta al design", "blocks": [{"kind": "p", "text": "Il vantaggio di Trae CLI nel design deriva dall'essere aperto e flessibile sul provider — ma, come con ogni agente, il gusto va comunque fornito."}, {"kind": "steps", "items": [{"label": "Indipendente dal modello per progettazione", "body": "Poiché scegli tu il provider, puoi indirizzare il lavoro di design al modello che oggi ragiona meglio su layout e codice frontend, e cambiarlo in seguito senza modificare il tuo flusso di lavoro."}, {"label": "Aperto e guidato dalla configurazione", "body": "L'agente, i suoi strumenti e il suo provider sono fissati in un file di configurazione che puoi committare, così un team ottiene lo stesso comportamento dell'agente su ogni macchina invece di derive per singolo sviluppatore."}, {"label": "Convenzioni nel tuo repo", "body": "Punta l'agente verso i tuoi token, componenti e specifiche reali — tenuti nel tuo progetto — così lavora rispetto a un brand invece di ripiegare su un aspetto generico."}]}, {"kind": "image", "src": "/agents/trae-cli-design/trae-cli-design-taste-triangle.webp", "alt": "Diagramma che mostra design system, skill e immagine di riferimento che convergono in un buon output di design", "caption": "Il gusto deriva da tre input che fornisci tu: un design system, una skill e immagini di riferimento reali."}, {"kind": "p", "text": "La lezione è la stessa che insegna ogni agente: Trae CLI non ha gusto per impostazione predefinita. Produce un buon design quando gli dai dei vincoli — un design system, una skill estetica e riferimenti concreti. Open Design impacchetta esattamente questi input e li fornisce a Trae CLI tramite ACP, ed è per questo che i due si integrano bene (più avanti il dettaglio)."}]}, {"id": "setup", "heading": "Configura Trae CLI per il lavoro di design, da zero", "blocks": [{"kind": "p", "text": "Ecco il percorso completo da una macchina pulita a un Trae CLI capace di costruire e verificare UI. Trae CLI viene installato dai sorgenti con uv, poi configurato con il provider LLM che vuoi usare."}, {"kind": "code", "lang": "bash", "code": "# 1. Get Trae CLI (trae-agent) from source — needs uv\ngit clone https://github.com/bytedance/trae-agent.git\ncd trae-agent\nuv sync --all-extras\nsource .venv/bin/activate\n\n# 2. Authenticate by pointing it at your LLM provider key\n#    set it in the environment (or a trae_config.yaml file)\nexport OPENAI_API_KEY=...        # or ANTHROPIC_API_KEY, GOOGLE_API_KEY, etc.\n\n# 3. Run a task in your project\ntrae-cli run \"Create a hello world page\"\n#    or hold a session:\ntrae-cli interactive\n\n# 4. Check the resolved configuration (keys are masked)\ntrae-cli show-config"}, {"kind": "image", "src": "/agents/trae-cli-design/trae-cli-design-setup-flow.webp", "alt": "Flusso di configurazione in cinque passi: installa, autentica, configura le convenzioni, aggiungi una skill, verifica", "caption": "La sequenza di configurazione: installa → autentica con una chiave del provider → configura le tue convenzioni di design → aggiungi una skill → abilita la verifica nel browser."}, {"kind": "steps", "items": [{"label": "Codifica le tue regole di design", "body": "Tieni i tuoi token, le primitive e le convenzioni nel repo e punta Trae CLI verso di essi, così l'output corrisponde a un brand invece di ripiegare su un aspetto generico."}, {"label": "Aggiungi la verifica nel browser", "body": "Fai avviare a Trae CLI un dev server e renderizzare in un browser reale, così controlla il suo output attraverso i breakpoint invece di limitarsi a confermare che la build passi."}]}]}, {"id": "screenshot-workflow", "heading": "Il flusso di lavoro dallo screenshot all'UI", "blocks": [{"kind": "p", "text": "Il ciclo di design a maggior leva con Trae CLI è trasformare un'immagine di riferimento in un'UI funzionante e responsive e iterare finché non corrisponde. Poiché Trae CLI è indipendente dal modello, puntalo verso un provider il cui modello gestisce bene i tuoi riferimenti, e appoggiati a un browser reale per controllare il risultato."}, {"kind": "ol", "items": ["Parti dai riferimenti visivi più chiari che hai — e descrivi più stati (desktop e mobile, hover, vuoto, caricamento), non solo un'unica schermata hero.", "Sii specifico nel prompt; i prompt vaghi producono UI generiche anche con un modello forte.", "Tieni il tuo design system e le tue convenzioni nel repo, e indica a Trae CLI dove si trovano i token e le primitive canoniche.", "Avvia un dev server e fai renderizzare a Trae CLI in un browser reale, ridimensionando ai breakpoint per controllare il risultato.", "Itera facendo confrontare a Trae CLI la sua implementazione con i riferimenti — non limitarti a confermare che si compili."]}, {"kind": "p", "text": "Avvia una sessione interattiva e dai vincoli concreti anziché una richiesta in una riga:"}, {"kind": "code", "lang": "bash", "code": "trae-cli interactive\n# in the session:\n> Implement the attached reference design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Run the dev server, render it in the browser, and iterate until it\n  matches the references across breakpoints."}, {"kind": "p", "text": "Tieni i prompt piccoli e mirati, committa le buone iterazioni e annulla quelle cattive (dicendolo a Trae CLI quando annulli), così ogni passaggio si costruisce su una base pulita."}]}, {"id": "extend", "heading": "Configurazione, strumenti e provider", "blocks": [{"kind": "p", "text": "Tre punti di estensione rendono Trae CLI pratico per un lavoro di design continuativo, e tutti e tre si mappano in modo pulito su un flusso di lavoro di design aperto."}, {"kind": "steps", "items": [{"label": "File di configurazione", "body": "Trae CLI legge un trae_config.yaml che fissa il tuo provider, il modello e le impostazioni — la sede durevole e versionabile di come l'agente gira su un progetto."}, {"label": "Scelta del provider", "body": "Poiché supporta molti provider (OpenAI, Anthropic, Google, OpenRouter, Doubao, Azure, Ollama), indirizzi il lavoro di design al modello di cui ti fidi e lo cambi senza rifare il cablaggio del tuo flusso di lavoro."}, {"label": "Strumenti integrati", "body": "I suoi strumenti di editing dei file, shell e ragionamento strutturato gli permettono di raccogliere contesto, costruire, avviare un dev server ed eseguire il ciclo di verifica senza lasciare il terminale."}]}, {"kind": "p", "text": "Sono capacità portabili a livello di agente — esattamente il tipo di cosa che Open Design è costruito per orchestrare tramite ACP, invece di ricrearle per ogni progetto."}]}, {"id": "vs", "heading": "Trae CLI vs Codex vs Claude Code vs Cursor vs Gemini CLI per il design", "blocks": [{"kind": "p", "text": "Non c'è un unico vincitore per il lavoro di design — ogni agente ha un punto di forza diverso, e i team esperti li combinano. Un riepilogo onesto:"}, {"kind": "table", "columns": ["Agente", "Punto di forza nel design", "Ideale per"], "rows": [["Trae CLI", "Open source (MIT) e indipendente dal modello; porti la tua chiave del provider, guidato dalla configurazione e trasparente", "Team che vogliono un agente gratuito e ispezionabile e la libertà di scegliere o cambiare provider LLM"], ["Codex", "Forte rifinitura visiva con una skill frontend; build asincrone in sandbox", "Build asincrone delegate e regole AGENTS.md portabili"], ["Claude Code", "Decisioni di design specifiche (hex, spaziatura, tipografia) e UX consapevole del codebase", "Ragionamento frontend e refactoring a grande contesto"], ["Cursor", "Ciclo visivo build-and-see con anteprima live e modifiche inline", "Lavoro su UI stretto, itera-e-osserva dentro un IDE"], ["Gemini CLI", "Forte comprensione multimodale delle immagini e contesto da 1M token; open source con tier gratuito", "Lavoro ricco di screenshot e mantenere un intero design system nel contesto"]]}, {"kind": "p", "text": "Il verdetto ricorrente della community è che il gusto viene dalle persone: tutti ripiegano su un'estetica generica senza skill, riferimenti e vincoli. Questo è il vero problema da risolvere — ed è di forma da strumento di design, non da modello."}]}, {"id": "pitfalls", "heading": "Insidie, e come evitare l'aspetto da “AI slop”", "blocks": [{"kind": "p", "text": "La lamentela più comune sul design generato dall'AI è che sembra generico — gradienti morbidi, pannelli fluttuanti, angoli arrotondati sovradimensionati, ombre drammatiche, un'atmosfera Inter-e-viola che “urla che l'ha fatto un'AI”. Altri problemi segnalati includono layout mobile rotti e istruzioni che finiscono nei testi dell'UI. Nessuno di questi è esclusivo di Trae CLI; sono ciò che accade quando un qualsiasi agente gira senza un contesto di design curato."}, {"kind": "steps", "items": [{"label": "Aggiungi una skill estetica", "body": "Una skill di design curata costringe l'agente a impegnarsi su una direzione reale invece dell'aspetto predefinito."}, {"label": "Verifica in un browser reale", "body": "Fai renderizzare e autocontrollare a Trae CLI attraverso i breakpoint, così i layout non si rompono silenziosamente su mobile."}, {"label": "Fornisci token e riferimenti", "body": "Token di design reali e screenshot di riferimento sono la leva singola più grande sulla qualità dell'output."}, {"label": "Codifica le regole nel tuo repo", "body": "Metti regole in stile “niente hero card, massimo due font, gerarchia brand-first” dove l'agente le legge a ogni esecuzione."}]}, {"kind": "p", "text": "Nota che ogni mitigazione riguarda il fornire all'agente un contesto di design curato. Mantenere quel contesto a mano, progetto per progetto, è la fatica che Open Design elimina."}]}, {"id": "open-design", "heading": "Progettare con Trae CLI dentro Open Design", "blocks": [{"kind": "p", "text": "Open Design è il livello di design open source che il flusso di lavoro qui sopra continua a richiedere. Tratta Trae CLI come un adattatore di prima parte — pilotandolo tramite l'Agent Client Protocol (ACP) attraverso il suo binario trae-cli — e lo avvolge in una libreria curata di skill e design system, una pipeline di rendering strutturata e un'UI desktop locale, così il contesto di design che rende Trae CLI valido è presente dalla prima esecuzione, non assemblato a mano ogni volta. Entrambi sono open source e local-first, il che rende l'abbinamento naturale."}, {"kind": "ol", "items": ["Installa Open Design e seleziona Trae CLI come tuo agente.", "Autentica con la tua chiave del provider LLM (BYOK) — le credenziali restano sulla tua macchina e non passano mai attraverso di noi tramite proxy.", "Scegli un design system e una skill, poi genera deck, prototipi e landing page con un gusto coerente.", "Ogni artefatto e file DESIGN.md vive nel tuo repo, non in un cloud ospitato."]}, {"kind": "p", "text": "Stesso agente Trae CLI, stessa chiave del provider — più un flusso di lavoro di design reale, portabile e open source attorno ad esso. È local-first e open source, quindi nulla del tuo lavoro o delle tue credenziali lascia la tua macchina."}]}], "faqTitle": "Domande frequenti", "faq": [{"name": "Trae CLI può davvero fare lavoro di design?", "text": "Sì — con una skill estetica, un design system e un contesto di riferimento reale, Trae CLI produce UI responsive di qualità da produzione, e poiché è indipendente dal modello puoi indirizzare il lavoro al provider che ragiona meglio sul tuo frontend. Senza quel contesto tende a ripiegare su un aspetto generico, che è il divario che Open Design colma."}, {"name": "Devo pagare per progettare con Trae CLI?", "text": "Trae CLI in sé è gratuito e open source (MIT). Porti la tua chiave del provider LLM, quindi il tuo unico costo è quello che addebita quel provider — o nulla se esegui un modello locale tramite Ollama. Open Design non fa comunque mai da proxy alle tue credenziali."}, {"name": "Cosa rende Trae CLI buono per il design in particolare?", "text": "Due cose: è indipendente dal modello, così scegli il provider LLM più adatto al lavoro frontend, ed è completamente aperto e guidato dalla configurazione, così il suo comportamento è trasparente e riproducibile in tutto un team. Ma il gusto viene comunque dal design system, dalla skill e dai riferimenti che fornisci."}, {"name": "Trae CLI o Claude Code per il design frontend?", "text": "Entrambi sono capaci. Claude Code è noto per decisioni di design specifiche e consapevoli del codebase; il vantaggio di Trae CLI è l'essere open source e flessibile sul provider, così non sei mai legato a un solo modello. Molti team usano entrambi — Open Design ti permette di cambiare agente senza cambiare il tuo flusso di lavoro di design."}, {"name": "Cosa serve a Open Design per eseguire Trae CLI?", "text": "Open Design pilota il binario trae-cli di Trae CLI tramite l'Agent Client Protocol (ACP) e usa la chiave del provider LLM che hai configurato. Selezioni Trae CLI come tuo agente, lo punti verso un provider, e Open Design fornisce il contesto di design curato attorno ad esso."}, {"name": "Open Design è affiliato a ByteDance o Trae?", "text": "No. Trae CLI (trae-agent) è un prodotto di ByteDance; Open Design è un progetto open source indipendente che lo supporta come adattatore di prima parte. Trae è un marchio di ByteDance."}, {"name": "I miei file e le mie credenziali sono al sicuro?", "text": "Sì — Open Design è local-first e open source. I tuoi file, gli artefatti e DESIGN.md restano nel tuo repo, e le credenziali del tuo provider LLM vengono usate direttamente dal tuo agente, mai instradate attraverso i server di Open Design."}], "ctaTitle": "Progetta con Trae CLI, alla maniera aperta.", "ctaBody": "Porta la tua chiave del provider LLM, tieni ogni file in locale e ottieni una libreria di design curata attorno all'agente che già usi.", "ctaActions": [{"label": "Usa Trae CLI dentro Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Metti una stella su GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Scarica l'app desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Vedi tutti gli agenti supportati"},
      },
      'aider': {
        ...en['aider']!,
        title: "Aider per il design — Open Design",
        description: "Come si usa Aider — il programmatore in coppia AI open source e indipendente dal modello nel tuo terminale — per il design di UI e web, con modifiche git-native, un file CONVENTIONS.md, supporto alle immagini e BYOK, e come Open Design trasforma Aider in un agente di design open source e local-first.",
        breadcrumb: "Aider",
        label: "Agente · Aider",
        heading: "Aider per il design.",
        lead: "Aider è il programmatore in coppia AI open source che vive nel tuo terminale e lavora direttamente sul tuo repo git. È indipendente dal modello — lo punti verso Claude, GPT-4o, DeepSeek o Gemini con la tua chiave — e modifica i file, fa commit automatici e legge le immagini sui modelli con capacità di visione. Questo lo rende un vero strumento di design una volta che gli fornisci riferimenti, convenzioni e un ciclo di verifica. Open Design lo collega a un flusso di lavoro di design open source: le tue chiavi del provider, i tuoi file, local-first.",
        rich: {"heroCtaLead": "Open Design trasforma Aider in un agente di design open source e local-first — le tue chiavi API del provider, i tuoi file, una libreria curata di skill e design system attorno ad esso.", "heroCtaActions": [{"label": "Usa Aider dentro Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Metti una stella su GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Scarica l'app desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Aider è uno strumento open source di programmazione in coppia con l'AI che gira nel tuo terminale e lavora sul codice nel tuo repository git. Due caratteristiche lo rendono interessante per il design in particolare: è indipendente dal modello, quindi porti la tua chiave per quasi ogni LLM — Claude, GPT-4o, DeepSeek, Gemini o un modello locale — ed è git-native, modificando i file sul posto e facendo il commit di ogni cambiamento con un messaggio sensato, così ogni iterazione è revisionabile e reversibile. Sui modelli con capacità di visione può anche leggere le immagini, così uno screenshot diventa parte del prompt. Abbinato ai riferimenti giusti, alle convenzioni e a un ciclo di verifica, costruisce UI reali e responsive. Questa è una guida pratica ed end-to-end all'uso di Aider per il lavoro su UI, frontend e design system, e a come integrarlo in un flusso di lavoro di design strutturato con Open Design.", "Copre cos'è realmente Aider, perché uno strumento indipendente dal modello e git-native si adatta al design, come configurarlo da zero, il ciclo dallo screenshot all'UI, come CONVENTIONS.md e i comandi di Aider lo estendono, come si confronta con Codex, Claude Code, Cursor e Gemini CLI, le insidie che fanno sembrare generico l'output dell'AI, e come Open Design colma il divario come livello di design aperto e local-first — un abbinamento naturale, dato che entrambi sono open source e girano sulla tua macchina."], "heroImage": {"src": "/agents/aider-design/aider-design-hero.webp", "alt": "Ciclo di feedback del design con Aider: un agente da terminale che legge un'immagine di riferimento, un repo git con commit, un browser che renderizza l'UI, con una freccia di feedback che ritorna", "caption": "Il ciclo centrale: Aider legge i tuoi riferimenti nel terminale, modifica e committa l'UI nel tuo repo git, e itera in base ad essi — con qualsiasi modello tu porti."}, "tocLabel": "In questa pagina", "toc": [{"id": "what-is-aider", "label": "Cos'è realmente Aider"}, {"id": "why-design", "label": "Perché indipendente dal modello + git-native si adattano al design"}, {"id": "setup", "label": "Configura Aider per il design (da zero)"}, {"id": "screenshot-workflow", "label": "Il flusso di lavoro dallo screenshot all'UI"}, {"id": "extend", "label": "CONVENTIONS.md, immagini e comandi"}, {"id": "vs", "label": "Aider vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Insidie e l'aspetto da “AI slop”"}, {"id": "open-design", "label": "Progettare con Aider in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-aider", "heading": "Cos'è realmente Aider", "blocks": [{"kind": "p", "text": "Aider è uno strumento open source (Apache-2.0) di programmazione in coppia con l'AI che gira nel tuo terminale. Legge il tuo codebase esistente, mappa l'intero repository per il contesto, modifica i file sul posto e committa automaticamente ogni cambiamento con un messaggio sensato — così puoi fare diff, gestire e annullare il lavoro dell'AI con gli strumenti git che già usi. Funziona con oltre 100 linguaggi di programmazione e avvia nuovi progetti o costruisce su quelli esistenti."}, {"kind": "p", "text": "Per il lavoro di design spiccano due proprietà. Aider è indipendente dal modello: porti la tua chiave e la colleghi a quasi ogni LLM — Claude, GPT-4o, DeepSeek, Gemini o un modello locale — così non sei mai legato a un solo provider. E sui modelli con capacità di visione come GPT-4o e Claude può leggere file immagine, trasformando uno screenshot di riferimento in parte del prompt."}, {"kind": "steps", "items": [{"label": "File delle convenzioni", "body": "Aider legge un file CONVENTIONS.md che carichi con /read CONVENTIONS.md (o aider --read CONVENTIONS.md) — il luogo naturale per codificare le tue convenzioni di design, i token e le checklist di revisione come contesto in sola lettura."}, {"label": "Modifiche git-native", "body": "Ogni cambiamento viene applicato ai file nel tuo repo e committato automaticamente, così ogni iterazione di design è revisionabile e reversibile con i familiari strumenti git."}, {"label": "Porta il tuo modello", "body": "Collega OpenAI, Anthropic, DeepSeek, Gemini o un modello locale con la tua chiave API; Aider non è legato a un singolo fornitore né a un backend ospitato."}]}, {"kind": "ul", "items": ["Fornitore: Aider (Aider-AI, open source) — indipendente dal modello", "Credenziale: la tua chiave API del provider — BYOK (OpenAI, Anthropic, DeepSeek, Gemini o un modello locale)", "Licenza: Apache-2.0, open source"]}]}, {"id": "why-design", "heading": "Perché uno strumento indipendente dal modello e git-native si adatta al design", "blocks": [{"kind": "p", "text": "Il vantaggio di Aider nel design deriva da come lavora con il tuo repo e con la tua scelta di modello — ma, come con ogni agente, il gusto va comunque fornito."}, {"kind": "steps", "items": [{"label": "Indipendente dal modello, BYOK", "body": "Scegli il modello che progetta meglio per il tuo task e il tuo budget — Claude, GPT-4o, DeepSeek, Gemini — e cambialo liberamente senza modificare il tuo flusso di lavoro, tutto con la tua chiave."}, {"label": "Iterazione git-native", "body": "I commit automatici rendono ogni passaggio di design un diff revisionabile che puoi annullare, così iteri su una base pulita invece che su un mucchio di modifiche non tracciate."}, {"label": "Convenzioni in CONVENTIONS.md", "body": "Un CONVENTIONS.md (caricato in sola lettura) punta l'agente verso i tuoi token, componenti e regole, così lavora rispetto a un brand invece che su un aspetto predefinito."}]}, {"kind": "image", "src": "/agents/aider-design/aider-design-taste-triangle.webp", "alt": "Diagramma che mostra design system, skill e immagine di riferimento che convergono in un buon output di design", "caption": "Il gusto deriva da tre input che fornisci tu: un design system, una skill e immagini di riferimento reali."}, {"kind": "p", "text": "La lezione è la stessa che insegna ogni agente: Aider non ha gusto per impostazione predefinita. Produce un buon design quando gli dai dei vincoli — un design system, una skill estetica e riferimenti concreti. Open Design impacchetta esattamente questi input, ed è per questo che i due si integrano bene (più avanti il dettaglio)."}]}, {"id": "setup", "heading": "Configura Aider per il lavoro di design, da zero", "blocks": [{"kind": "p", "text": "Ecco il percorso completo da una macchina pulita a un Aider capace di costruire e verificare UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Aider (recommended installer; Python 3.8–3.13)\npython -m pip install aider-install\naider-install\n# or with pipx: pipx install aider-chat\n\n# 2. Start it in your git project and bring your own key\ncd your-project\naider --model sonnet --api-key anthropic=<your-key>\n# or: aider --api-key openai=<your-key>   (also deepseek=, gemini=)\n\n# 3. Load your design conventions as read-only context\naider --read CONVENTIONS.md\n\n# 4. Add a reference image (on a vision-capable model)\n#    inside the chat: /add reference-desktop.png"}, {"kind": "image", "src": "/agents/aider-design/aider-design-setup-flow.webp", "alt": "Flusso di configurazione in cinque passi: installa, porta la tua chiave, carica CONVENTIONS.md, aggiungi un riferimento, verifica", "caption": "La sequenza di configurazione: installa → porta la tua chiave → carica CONVENTIONS.md → aggiungi un riferimento → abilita la verifica nel browser."}, {"kind": "steps", "items": [{"label": "Codifica le tue regole di design", "body": "Metti i tuoi token, le primitive e le convenzioni in CONVENTIONS.md e caricalo in sola lettura, così l'output corrisponde a un brand invece di ripiegare su un aspetto generico."}, {"label": "Aggiungi la verifica nel browser", "body": "Avvia un dev server e fai renderizzare ad Aider in un browser reale, controllando il suo output attraverso i breakpoint invece di limitarsi a confermare che la build passi."}]}]}, {"id": "screenshot-workflow", "heading": "Il flusso di lavoro dallo screenshot all'UI", "blocks": [{"kind": "p", "text": "Il ciclo di design a maggior leva con Aider è trasformare un'immagine di riferimento in un'UI funzionante e responsive e iterare finché non corrisponde — usando un modello con capacità di visione per confrontare l'output con il riferimento, con ogni passaggio committato su git."}, {"kind": "ol", "items": ["Parti dai riferimenti visivi più chiari che hai — e includi più stati (desktop e mobile, hover, vuoto, caricamento), non solo un'unica schermata hero.", "Sii specifico nel prompt; i prompt vaghi producono UI generiche anche con un modello forte.", "Tieni il tuo design system e le tue convenzioni in CONVENTIONS.md, e indica ad Aider dove si trovano i token e le primitive canoniche.", "Avvia un dev server e controlla il risultato renderizzato in un browser reale, ridimensionando ai breakpoint.", "Itera facendo confrontare ad Aider la sua implementazione con gli screenshot — non limitarti a confermare che si compili."]}, {"kind": "p", "text": "Aggiungi un'immagine con /add (o /paste dagli appunti) su un modello con capacità di visione, poi dai vincoli concreti:"}, {"kind": "code", "lang": "bash", "code": "aider --model gpt-4o --read CONVENTIONS.md\n# in the chat:\n> /add reference-desktop.png\n> /add reference-mobile.png\n> Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from CONVENTIONS.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  I'll render it in the browser and tell you what to fix until it matches\n  the references across breakpoints."}, {"kind": "p", "text": "Tieni i prompt piccoli e mirati. Poiché Aider committa ogni cambiamento, mantieni le buone iterazioni e usi git (o /undo) per annullare quelle cattive — così ogni passaggio si costruisce su una base pulita."}]}, {"id": "extend", "heading": "CONVENTIONS.md, immagini e comandi", "blocks": [{"kind": "p", "text": "Tre capacità rendono Aider pratico per un lavoro di design continuativo, e tutte e tre si mappano in modo pulito su un flusso di lavoro di design aperto."}, {"kind": "steps", "items": [{"label": "Contesto CONVENTIONS.md", "body": "Carica le convenzioni di codice e di design con /read CONVENTIONS.md o aider --read CONVENTIONS.md, oppure imposta read: CONVENTIONS.md in .aider.conf.yml per caricarlo a ogni esecuzione. È la sede durevole per i tuoi token, le primitive e le regole."}, {"label": "Immagini e pagine web", "body": "Sui modelli con capacità di visione, fai /add di un file immagine o /paste dagli appunti per dare ad Aider un riferimento reale; /web <url> estrae il testo di una pagina nella chat per contesto aggiuntivo."}, {"label": "Comandi in-chat", "body": "Comandi come /add per portare i file nel contesto, /read per riferimenti in sola lettura e /undo per annullare l'ultimo commit gli permettono di raccogliere riferimenti ed eseguire il ciclo di verifica senza lasciare il terminale."}]}, {"kind": "p", "text": "Sono capacità portabili e native del repo — esattamente il tipo di cosa che Open Design è costruito per orchestrare, invece di ricrearle per ogni progetto."}]}, {"id": "vs", "heading": "Aider vs Codex vs Claude Code vs Cursor vs Gemini CLI per il design", "blocks": [{"kind": "p", "text": "Non c'è un unico vincitore per il lavoro di design — ogni agente ha un punto di forza diverso, e i team esperti li combinano. Un riepilogo onesto:"}, {"kind": "table", "columns": ["Agente", "Punto di forza nel design", "Ideale per"], "rows": [["Aider", "Open source, indipendente dal modello (BYOK) e git-native; i commit automatici rendono ogni iterazione revisionabile e reversibile", "Iterazione native sul repo sul tuo codebase esistente con qualsiasi modello progetti meglio"], ["Codex", "Forte rifinitura visiva con una skill frontend; build asincrone in sandbox", "Build asincrone delegate e regole AGENTS.md portabili"], ["Claude Code", "Decisioni di design specifiche (hex, spaziatura, tipografia) e UX consapevole del codebase", "Ragionamento frontend e refactoring a grande contesto"], ["Cursor", "Ciclo visivo build-and-see con anteprima live e modifiche inline", "Lavoro su UI stretto, itera-e-osserva dentro un IDE"], ["Gemini CLI", "Forte comprensione multimodale delle immagini e contesto da 1M token; open source con tier gratuito", "Lavoro ricco di screenshot e mantenere un intero design system nel contesto"]]}, {"kind": "p", "text": "Il verdetto ricorrente della community è che il gusto viene dalle persone: tutti ripiegano su un'estetica generica senza skill, riferimenti e vincoli. Questo è il vero problema da risolvere — ed è di forma da strumento di design, non da modello."}]}, {"id": "pitfalls", "heading": "Insidie, e come evitare l'aspetto da “AI slop”", "blocks": [{"kind": "p", "text": "La lamentela più comune sul design generato dall'AI è che sembra generico — gradienti morbidi, pannelli fluttuanti, angoli arrotondati sovradimensionati, ombre drammatiche, un'atmosfera Inter-e-viola che “urla che l'ha fatto un'AI”. Altri problemi segnalati includono layout mobile rotti e istruzioni che finiscono nei testi dell'UI. Nessuno di questi è esclusivo di Aider; sono ciò che accade quando un qualsiasi agente gira senza un contesto di design curato."}, {"kind": "steps", "items": [{"label": "Aggiungi una skill estetica", "body": "Una skill di design curata costringe l'agente a impegnarsi su una direzione reale invece dell'aspetto predefinito."}, {"label": "Verifica in un browser reale", "body": "Renderizza e autocontrolla attraverso i breakpoint così i layout non si rompono silenziosamente su mobile — su un modello con capacità di visione, riproponi gli screenshot in input."}, {"label": "Fornisci token e riferimenti", "body": "Token di design reali e screenshot di riferimento sono la leva singola più grande sulla qualità dell'output."}, {"label": "Codifica le regole in CONVENTIONS.md", "body": "Metti regole in stile “niente hero card, massimo due font, gerarchia brand-first” dove l'agente le legge a ogni esecuzione."}]}, {"kind": "p", "text": "Nota che ogni mitigazione riguarda il fornire all'agente un contesto di design curato. Mantenere quel contesto a mano, progetto per progetto, è la fatica che Open Design elimina."}]}, {"id": "open-design", "heading": "Progettare con Aider dentro Open Design", "blocks": [{"kind": "p", "text": "Open Design è il livello di design open source che il flusso di lavoro qui sopra continua a richiedere. Tratta Aider come un adattatore di prima parte e lo avvolge in una libreria curata di skill e design system, una pipeline di rendering strutturata e un'UI desktop locale — così il contesto di design che rende Aider valido è presente dalla prima esecuzione, non assemblato a mano ogni volta. Entrambi sono open source e local-first, il che rende l'abbinamento naturale."}, {"kind": "ol", "items": ["Installa Open Design e seleziona Aider come tuo agente.", "Autentica con la tua chiave API del provider (BYOK) — OpenAI, Anthropic, DeepSeek o Gemini; le credenziali restano sulla tua macchina e non passano mai attraverso di noi tramite proxy.", "Scegli un design system e una skill, poi genera deck, prototipi e landing page con un gusto coerente.", "Ogni artefatto e file DESIGN.md vive nel tuo repo git, non in un cloud ospitato."]}, {"kind": "p", "text": "Stesso agente Aider, stessa chiave — più un flusso di lavoro di design reale, portabile e open source attorno ad esso. È local-first e open source, quindi nulla del tuo lavoro o delle tue credenziali lascia la tua macchina."}]}], "faqTitle": "Domande frequenti", "faq": [{"name": "Aider può davvero fare lavoro di design?", "text": "Sì — con una skill estetica, un design system e immagini di riferimento reali nel contesto, Aider produce UI responsive di qualità da produzione, e sui modelli con capacità di visione legge gli screenshot per verificare l'output rispetto ai riferimenti. Senza quel contesto tende a ripiegare su un aspetto generico, che è il divario che Open Design colma."}, {"name": "Quali modelli posso usare con Aider per il design?", "text": "Aider è indipendente dal modello. Porti la tua chiave API e colleghi quasi ogni LLM — Claude, GPT-4o, DeepSeek, Gemini o un modello locale. Per il lavoro di design basato su immagini, usa un modello con capacità di visione come GPT-4o o Claude. Open Design non fa mai da proxy alle tue credenziali."}, {"name": "Cosa rende Aider buono per il design in particolare?", "text": "Due cose: è indipendente dal modello, così scegli il modello che progetta meglio per il tuo task, ed è git-native, committando ogni cambiamento così che ogni iterazione di design sia revisionabile e reversibile. Entrambe aiutano — ma il gusto viene comunque dal design system, dalla skill e dai riferimenti che fornisci."}, {"name": "Aider modifica i miei file e committa su git?", "text": "Sì. Aider modifica i file direttamente nel tuo repository e committa automaticamente ogni cambiamento con un messaggio sensato, così puoi fare diff, gestire e annullare il lavoro dell'AI con gli strumenti git che già usi."}, {"name": "Come do ad Aider le mie convenzioni di design?", "text": "Crea un CONVENTIONS.md con i tuoi token, le primitive e le regole, poi caricalo in sola lettura con /read CONVENTIONS.md o aider --read CONVENTIONS.md (o imposta read: CONVENTIONS.md in .aider.conf.yml per caricarlo a ogni esecuzione). Aider lavora poi rispetto al tuo brand invece che su un aspetto predefinito."}, {"name": "Open Design è affiliato ad Aider?", "text": "No. Aider è un progetto open source indipendente (Aider-AI); Open Design è un progetto open source indipendente e separato che supporta Aider come adattatore di prima parte. I due non sono affiliati."}, {"name": "I miei file e le mie credenziali sono al sicuro?", "text": "Sì — Open Design è local-first e open source. I tuoi file, gli artefatti e DESIGN.md restano nel tuo repo git, e le tue chiavi API del provider vengono usate direttamente dal tuo agente, mai instradate attraverso i server di Open Design."}], "ctaTitle": "Progetta con Aider, alla maniera aperta.", "ctaBody": "Porta la tua chiave API del provider, tieni ogni file in locale nel tuo repo git e ottieni una libreria di design curata attorno all'agente che già usi.", "ctaActions": [{"label": "Usa Aider dentro Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Metti una stella su GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Scarica l'app desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Vedi tutti gli agenti supportati"},
      },
      'antigravity': {
        ...en['antigravity']!,
        title: "Antigravity per il design — Open Design",
        description: "Come si usa Google Antigravity — la piattaforma di sviluppo agent-first di Google alimentata dai modelli multimodali Gemini 3.x, con la sua Editor View, la Manager Surface, il controllo integrato del browser e gli Artifacts — per il design di UI e web, e come Open Design trasforma Antigravity in un agente di design open source e local-first.",
        breadcrumb: "Antigravity",
        label: "Agente · Antigravity",
        heading: "Antigravity per il design.",
        lead: "Antigravity è la piattaforma di sviluppo agent-first di Google. I suoi modelli Gemini 3.x leggono gli screenshot e ragionano sul layout, il suo browser integrato permette agli agenti di verificare ciò che costruiscono, e i suoi Artifacts trasformano il lavoro dell'agente in deliverable revisionabili — il che lo rende un vero strumento di design una volta che gli fornisci riferimenti, convenzioni e un ciclo di verifica. Open Design lo collega a un flusso di lavoro di design open source: il tuo account Google, i tuoi file, local-first.",
        rich: {"heroCtaLead": "Open Design trasforma Antigravity in un agente di design open source e local-first — il tuo account Google, i tuoi file, una libreria curata di skill e design system attorno ad esso.", "heroCtaActions": [{"label": "Usa Antigravity dentro Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Metti una stella su GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Scarica l'app desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Antigravity è la piattaforma di sviluppo agent-first di Google, lanciata insieme a Gemini 3. Tre caratteristiche la rendono interessante per il design in particolare: i suoi agenti girano su modelli Gemini 3.x nativamente multimodali, così leggono uno screenshot e ragionano su layout, spaziatura e gerarchia; integra un browser che l'agente può pilotare, così renderizza e controlla la propria UI invece di tirare a indovinare; e produce Artifacts — elenchi di task, piani di implementazione, screenshot e registrazioni del browser — che trasformano il lavoro dell'agente in qualcosa che puoi davvero revisionare. Abbinato ai riferimenti giusti, alle convenzioni e a un ciclo di verifica, costruisce UI reali e responsive — ed è gratuito per iniziare con un account Google. Questa è una guida pratica ed end-to-end all'uso di Antigravity per il lavoro su UI, frontend e design system, e a come integrarlo in un flusso di lavoro di design strutturato con Open Design.", "Copre cos'è realmente Antigravity, perché un Gemini multimodale e un browser integrato si adattano al design, come configurarlo da zero, il ciclo dallo screenshot all'UI, come il suo contesto dell'agente e i suoi strumenti lo estendono, come si confronta con Codex, Claude Code, Cursor e Gemini CLI, le insidie che fanno sembrare generico l'output dell'AI, e come Open Design colma il divario come livello di design aperto e local-first — un abbinamento naturale, dato che Open Design è open source e gira sulla tua macchina."], "heroImage": {"src": "/agents/antigravity-design/antigravity-design-hero.webp", "alt": "Ciclo di feedback del design con Antigravity: un IDE agent-first che legge un'immagine di riferimento, un browser integrato che renderizza l'UI e una superficie Manager, con una freccia di feedback che ritorna", "caption": "Il ciclo centrale: un agente Antigravity legge i tuoi riferimenti, costruisce e verifica l'UI nel suo browser integrato, e itera in base ad essi — esponendo il lavoro come Artifacts revisionabili."}, "tocLabel": "In questa pagina", "toc": [{"id": "what-is-antigravity", "label": "Cos'è realmente Antigravity"}, {"id": "why-design", "label": "Perché Gemini multimodale + un browser integrato si adattano al design"}, {"id": "setup", "label": "Configura Antigravity per il design (da zero)"}, {"id": "screenshot-workflow", "label": "Il flusso di lavoro dallo screenshot all'UI"}, {"id": "extend", "label": "Contesto dell'agente, strumenti e Artifacts"}, {"id": "vs", "label": "Antigravity vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Insidie e l'aspetto da “AI slop”"}, {"id": "open-design", "label": "Progettare con Antigravity in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-antigravity", "heading": "Cos'è realmente Antigravity", "blocks": [{"kind": "p", "text": "Antigravity è la piattaforma di sviluppo agent-first di Google — un IDE potenziato dall'AI costruito perché siano agenti autonomi, non chatbot nella sidebar, a svolgere il lavoro. Annunciato il 18 novembre 2025 insieme a Gemini 3 e disponibile in public preview senza costi per i singoli, ti permette di delegare task software complessi e multi-strumento a un agente che opera tra l'editor, il terminale e un browser integrato. I suoi agenti girano principalmente sui modelli multimodali Gemini 3.x di Google."}, {"kind": "p", "text": "Per il lavoro di design spiccano tre proprietà. I suoi agenti leggono gli screenshot e ragionano sul layout reale, perché Gemini 3.x è nativamente multimodale. Può pilotare un browser reale, così renderizza e verifica ciò che costruisce. Ed espone Artifacts — elenchi di task, piani, screenshot e registrazioni del browser — così revisioni output tangibile invece di log grezzi degli strumenti."}, {"kind": "steps", "items": [{"label": "Editor View + Manager Surface", "body": "La Editor View è un familiare IDE AI con completamenti a tab e comandi inline; la Manager Surface ti permette di generare, orchestrare e osservare più agenti che lavorano in modo asincrono tra i workspace — il luogo naturale per eseguire un lungo task di design."}, {"label": "Browser integrato + Artifacts", "body": "Gli agenti possono agire in un browser integrato ed emettere Artifacts (screenshot, registrazioni del browser, elenchi di task, piani) su cui puoi lasciare feedback — un ciclo di verifica integrato nella piattaforma anziché aggiunto."}, {"label": "Gratuito per iniziare", "body": "Accedere con un account Google personale dà limiti di frequenza generosi su Gemini 3.x; la piattaforma gira su macOS, Windows e Linux."}]}, {"kind": "ul", "items": ["Fornitore: Google", "Credenziale: account Google (Gmail personale), gratuito durante la public preview", "Binario: avvia con agy; gira su macOS, Windows e Linux"]}]}, {"id": "why-design", "heading": "Perché Gemini multimodale e un browser integrato si adattano al design", "blocks": [{"kind": "p", "text": "Il vantaggio di Antigravity nel design deriva dal modello e dalla piattaforma insieme — ma, come con ogni agente, il gusto va comunque fornito."}, {"kind": "steps", "items": [{"label": "Forte comprensione multimodale", "body": "Poiché Gemini 3.x è nativamente multimodale, l'agente legge bene gli screenshot di riferimento — confrontando il suo output renderizzato con un'immagine invece di indovinare da una descrizione in prosa."}, {"label": "Un browser integrato per verificare", "body": "L'agente pilota un browser reale, così renderizza l'UI, la controlla nei vari stati e intercetta i layout rotti — e cattura il risultato come Artifact di registrazione del browser che puoi revisionare."}, {"label": "Convenzioni che l'agente legge", "body": "Codifica i tuoi token, componenti e regole di revisione nel contesto di progetto dell'agente così lavora rispetto al tuo brand invece che su un aspetto predefinito."}]}, {"kind": "image", "src": "/agents/antigravity-design/antigravity-design-taste-triangle.webp", "alt": "Diagramma che mostra design system, skill e immagine di riferimento che convergono in un buon output di design", "caption": "Il gusto deriva da tre input che fornisci tu: un design system, una skill e immagini di riferimento reali."}, {"kind": "p", "text": "La lezione è la stessa che insegna ogni agente: Antigravity non ha gusto per impostazione predefinita. Produce un buon design quando gli dai dei vincoli — un design system, una skill estetica e riferimenti concreti. Open Design impacchetta esattamente questi input, ed è per questo che i due si integrano bene (più avanti il dettaglio)."}]}, {"id": "setup", "heading": "Configura Antigravity per il lavoro di design, da zero", "blocks": [{"kind": "p", "text": "Ecco il percorso completo da una macchina pulita a un agente Antigravity capace di costruire e verificare UI. I menu esatti nell'app potrebbero cambiare durante la preview, quindi questo resta a un livello su cui puoi fare affidamento."}, {"kind": "code", "lang": "bash", "code": "# 1. Download Antigravity for your OS (macOS, Windows, Linux)\n#    from the official download page: antigravity.google/download\n\n# 2. Launch it and sign in\nagy               # opens Antigravity; sign in with your Google account\n\n# 3. Accept the data-use policy, pick a theme, and open your project folder\n\n# 4. Start an agent task in the Editor View or the Manager Surface,\n#    selecting a Gemini 3.x model (e.g. Gemini 3.1 Pro)"}, {"kind": "image", "src": "/agents/antigravity-design/antigravity-design-setup-flow.webp", "alt": "Flusso di configurazione in cinque passi: scarica, accedi con Google, apri il progetto, aggiungi regole di design e una skill, abilita la verifica nel browser", "caption": "La sequenza di configurazione: scarica → accedi con Google → apri il tuo progetto → aggiungi regole di design e una skill → usa il browser integrato per verificare."}, {"kind": "steps", "items": [{"label": "Codifica le tue regole di design", "body": "Metti i tuoi token, le primitive e le convenzioni nel contesto di progetto dell'agente così l'output corrisponde a un brand invece di ripiegare su un aspetto generico."}, {"label": "Usa il browser integrato", "body": "Fai renderizzare all'agente nel browser integrato di Antigravity e controllare il suo output attraverso i breakpoint — verificando che l'UI abbia un bell'aspetto, non solo che la build passi."}]}]}, {"id": "screenshot-workflow", "heading": "Il flusso di lavoro dallo screenshot all'UI", "blocks": [{"kind": "p", "text": "Il ciclo di design a maggior leva con Antigravity è trasformare un'immagine di riferimento in un'UI funzionante e responsive e iterare finché non corrisponde — appoggiandosi al modello multimodale per confrontare l'output con il riferimento, e al browser integrato per verificarlo."}, {"kind": "ol", "items": ["Parti dai riferimenti visivi più chiari che hai — e includi più stati (desktop e mobile, hover, vuoto, caricamento), non solo un'unica schermata hero.", "Sii specifico nel prompt; i prompt vaghi producono UI generiche anche con un modello forte.", "Tieni il tuo design system e le tue convenzioni nel contesto di progetto dell'agente, e indicagli dove si trovano i token e le primitive canoniche.", "Lascia che l'agente renderizzi nel browser integrato di Antigravity, ridimensionando ai breakpoint per controllare il risultato.", "Itera facendo confrontare all'agente la sua implementazione con gli screenshot — non limitarti a confermare che si compili — e revisiona gli Artifacts di registrazione del browser e gli screenshot che produce."]}, {"kind": "p", "text": "Allega le tue immagini di riferimento e dai vincoli concreti, poi lascia che l'agente verifichi nel browser:"}, {"kind": "code", "lang": "text", "code": "# In an Antigravity agent task, attach reference-desktop.png and\n# reference-mobile.png, then prompt:\n\nImplement this design in React + Vite + Tailwind + TypeScript.\nReuse my existing design-system components and tokens.\nMatch spacing, layout, and hierarchy; make it responsive.\nRender it in the integrated browser and iterate until it matches\nthe references across breakpoints, and show me the screenshots."}, {"kind": "p", "text": "Tieni i prompt piccoli e mirati, committa le buone iterazioni e annulla quelle cattive (dicendolo all'agente quando annulli), così ogni passaggio si costruisce su una base pulita."}]}, {"id": "extend", "heading": "Contesto dell'agente, strumenti e Artifacts", "blocks": [{"kind": "p", "text": "Tre punti di estensione rendono Antigravity pratico per un lavoro di design continuativo, e tutti e tre si mappano in modo pulito su un flusso di lavoro di design aperto."}, {"kind": "steps", "items": [{"label": "Contesto di progetto", "body": "Le regole di progetto persistenti sono la sede durevole per le tue convenzioni di design — token, primitive e checklist di revisione che l'agente legge a ogni task, così l'output resta on-brand."}, {"label": "Browser integrato + terminale", "body": "Gli agenti agiscono tra l'editor, il terminale e un browser integrato, così possono raccogliere riferimenti, avviare un dev server e verificare l'UI renderizzata senza lasciare la piattaforma."}, {"label": "Artifacts che revisioni", "body": "Elenchi di task, piani di implementazione, screenshot e registrazioni del browser rendono leggibile il lavoro dell'agente; lasci feedback sull'Artifact e l'agente incorpora le correzioni."}]}, {"kind": "p", "text": "Sono le capacità di cui un serio ciclo di design ha bisogno — esattamente il tipo di cosa che Open Design è costruito per orchestrare, invece di ricrearle per ogni progetto."}]}, {"id": "vs", "heading": "Antigravity vs Codex vs Claude Code vs Cursor vs Gemini CLI per il design", "blocks": [{"kind": "p", "text": "Non c'è un unico vincitore per il lavoro di design — ogni agente ha un punto di forza diverso, e i team esperti li combinano. Un riepilogo onesto:"}, {"kind": "table", "columns": ["Agente", "Punto di forza nel design", "Ideale per"], "rows": [["Antigravity", "IDE agent-first con Gemini 3.x multimodale, un browser integrato per l'autoverifica e Artifacts revisionabili; gratuito in preview", "Build multi-agente asincrone con verifica integrata dell'UI nel browser"], ["Codex", "Forte rifinitura visiva con una skill frontend; build asincrone in sandbox", "Build asincrone delegate e regole AGENTS.md portabili"], ["Claude Code", "Decisioni di design specifiche (hex, spaziatura, tipografia) e UX consapevole del codebase", "Ragionamento frontend e refactoring a grande contesto"], ["Cursor", "Ciclo visivo build-and-see con anteprima live e modifiche inline", "Lavoro su UI stretto, itera-e-osserva dentro un IDE"], ["Gemini CLI", "Agente da terminale open source su Gemini multimodale con contesto da 1M token e tier gratuito", "Lavoro da terminale ricco di screenshot e mantenere un intero design system nel contesto"]]}, {"kind": "p", "text": "Il verdetto ricorrente della community è che il gusto viene dalle persone: tutti ripiegano su un'estetica generica senza skill, riferimenti e vincoli. Questo è il vero problema da risolvere — ed è di forma da strumento di design, non da modello."}]}, {"id": "pitfalls", "heading": "Insidie, e come evitare l'aspetto da “AI slop”", "blocks": [{"kind": "p", "text": "La lamentela più comune sul design generato dall'AI è che sembra generico — gradienti morbidi, pannelli fluttuanti, angoli arrotondati sovradimensionati, ombre drammatiche, un'atmosfera Inter-e-viola che “urla che l'ha fatto un'AI”. Altri problemi segnalati includono layout mobile rotti e istruzioni che finiscono nei testi dell'UI. Nessuno di questi è esclusivo di Antigravity; sono ciò che accade quando un qualsiasi agente gira senza un contesto di design curato."}, {"kind": "steps", "items": [{"label": "Aggiungi una skill estetica", "body": "Una skill di design curata costringe l'agente a impegnarsi su una direzione reale invece dell'aspetto predefinito."}, {"label": "Verifica nel browser integrato", "body": "Usa il modello multimodale e il browser integrato di Antigravity per renderizzare e autocontrollare attraverso i breakpoint così i layout non si rompono silenziosamente su mobile."}, {"label": "Fornisci token e riferimenti", "body": "Token di design reali e screenshot di riferimento sono la leva singola più grande sulla qualità dell'output."}, {"label": "Codifica le regole nel contesto di progetto", "body": "Metti regole in stile “niente hero card, massimo due font, gerarchia brand-first” dove l'agente le legge a ogni task."}]}, {"kind": "p", "text": "Nota che ogni mitigazione riguarda il fornire all'agente un contesto di design curato. Mantenere quel contesto a mano, progetto per progetto, è la fatica che Open Design elimina."}]}, {"id": "open-design", "heading": "Progettare con Antigravity dentro Open Design", "blocks": [{"kind": "p", "text": "Open Design è il livello di design open source che il flusso di lavoro qui sopra continua a richiedere. Tratta Antigravity come un adattatore di prima parte e lo avvolge in una libreria curata di skill e design system, una pipeline di rendering strutturata e un'UI desktop locale — così il contesto di design che rende Antigravity valido è presente dalla prima esecuzione, non assemblato a mano ogni volta. Open Design è open source e local-first, il che rende l'abbinamento naturale."}, {"kind": "ol", "items": ["Installa Open Design e seleziona Antigravity come tuo agente.", "Autentica con il tuo account Google — le credenziali restano sulla tua macchina e non passano mai attraverso di noi tramite proxy.", "Scegli un design system e una skill, poi genera deck, prototipi e landing page con un gusto coerente.", "Ogni artefatto e file DESIGN.md vive nel tuo repo, non in un cloud ospitato."]}, {"kind": "p", "text": "Stesso agente Antigravity, stesso account Google — più un flusso di lavoro di design reale, portabile e open source attorno ad esso. Open Design è local-first e Apache-2.0, quindi nulla del tuo lavoro o delle tue credenziali lascia la tua macchina."}]}], "faqTitle": "Domande frequenti", "faq": [{"name": "Antigravity può davvero fare lavoro di design?", "text": "Sì — con una skill estetica, un design system e immagini di riferimento reali nel contesto, Antigravity produce UI responsive di qualità da produzione, e i suoi agenti Gemini 3.x multimodali verificano l'output nel browser integrato. Senza quel contesto tende a ripiegare su un aspetto generico, che è il divario che Open Design colma."}, {"name": "Devo pagare per progettare con Antigravity?", "text": "Antigravity è disponibile in public preview senza costi per i singoli, con limiti di frequenza generosi su Gemini 3.x quando accedi con un account Google personale. Open Design non fa comunque mai da proxy alle tue credenziali."}, {"name": "Cosa rende Antigravity buono per il design in particolare?", "text": "Tre cose: i suoi agenti girano su modelli Gemini 3.x nativamente multimodali che leggono bene gli screenshot di riferimento, integra un browser che l'agente può pilotare per verificare l'UI, ed espone Artifacts — screenshot e registrazioni del browser — che puoi revisionare. Il gusto viene comunque dal design system, dalla skill e dai riferimenti che fornisci."}, {"name": "Antigravity o Claude Code per il design frontend?", "text": "Entrambi sono forti. Claude Code è noto per decisioni di design specifiche e consapevoli del codebase; il vantaggio di Antigravity è la sua piattaforma agent-first — Gemini 3.x multimodale, un browser integrato per la verifica e Artifacts revisionabili. Molti team usano entrambi — Open Design ti permette di cambiare agente senza cambiare il tuo flusso di lavoro di design."}, {"name": "Come verifico ciò che Antigravity costruisce?", "text": "Antigravity integra un browser che i suoi agenti possono pilotare, così renderizzano l'UI, la controllano attraverso i breakpoint e catturano screenshot e registrazioni del browser come Artifacts. Revisionare quegli Artifacts — e far confrontare all'agente il suo output con i tuoi riferimenti — è il modo per mantenere il risultato conforme alle specifiche."}, {"name": "Open Design è affiliato a Google?", "text": "No. Antigravity è un prodotto di Google; Open Design è un progetto open source indipendente che lo supporta come adattatore di prima parte. Antigravity e Gemini sono marchi di Google."}, {"name": "I miei file e le mie credenziali sono al sicuro?", "text": "Sì — Open Design è local-first e Apache-2.0. I tuoi file, gli artefatti e DESIGN.md restano nel tuo repo, e le tue credenziali Google vengono usate direttamente dal tuo agente, mai instradate attraverso i server di Open Design."}], "ctaTitle": "Progetta con Antigravity, alla maniera aperta.", "ctaBody": "Porta il tuo account Google, tieni ogni file in locale e ottieni una libreria di design curata attorno all'agente che già usi.", "ctaActions": [{"label": "Usa Antigravity dentro Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Metti una stella su GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Scarica l'app desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Vedi tutti gli agenti supportati"},
      },
      'reasonix': {
        ...en['reasonix']!,
        title: "DeepSeek Reasonix per il design — Open Design",
        description: "Come si usa DeepSeek Reasonix — l'agente di codice da terminale costruito dalla community e nativo per DeepSeek — per il design di UI e web, e come Open Design lo trasforma in un agente di design open source e local-first. BYOK con la tua chiave API DeepSeek.",
        breadcrumb: "DeepSeek Reasonix",
        label: "Agente · DeepSeek Reasonix",
        heading: "DeepSeek Reasonix per il design.",
        lead: "DeepSeek Reasonix è un agente di codice da terminale open source, costruito dalla community e alimentato dai modelli DeepSeek. Legge il tuo repo, modifica i file ed esegue il tuo ciclo di verifica a basso costo — il suo intero design è costruito attorno alla cache di prefisso di DeepSeek per mantenere economiche le sessioni lunghe. Con riferimenti, convenzioni e un controllo nel browser, diventa un vero strumento di design. Open Design lo collega a un flusso di lavoro di design open source: la tua chiave API DeepSeek, i tuoi file, local-first.",
        rich: {"heroCtaLead": "Open Design trasforma DeepSeek Reasonix in un agente di design open source e local-first — la tua chiave API DeepSeek, i tuoi file, una libreria curata di skill e design system attorno ad esso.", "heroCtaActions": [{"label": "Usa DeepSeek Reasonix dentro Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Metti una stella su GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Scarica l'app desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["DeepSeek Reasonix è un agente di codice AI per il terminale, open source e costruito dalla community, alimentato dai modelli di DeepSeek. Non è un prodotto ufficiale di DeepSeek — è mantenuto dall'autore GitHub esengine e dalla community, ed è costruito specificamente attorno ai meccanismi di cache di prefisso di DeepSeek così che le sessioni lunghe e iterative restino economiche. Legge il tuo repository, modifica i file, esegue comandi e lavora a partire da task in linguaggio naturale anziché limitarsi a completare righe. Porti la tua chiave API DeepSeek (BYOK), e l'agente gira su modelli DeepSeek come deepseek-v4-pro e deepseek-v4-flash. Questa è una guida pratica ed end-to-end all'uso di DeepSeek Reasonix per il lavoro su UI, frontend e design system, e a come integrarlo in un flusso di lavoro di design strutturato con Open Design.", "Copre cos'è realmente DeepSeek Reasonix, perché un agente alimentato da DeepSeek ed economico si adatta al design iterativo, come configurarlo da zero con la tua chiave, il ciclo dal riferimento all'UI, come le skill e MCP lo estendono, come si confronta con Codex, Claude Code, Cursor e Gemini CLI, le insidie che fanno sembrare generico l'output dell'AI, e come Open Design colma il divario come livello di design aperto e local-first — un abbinamento naturale, dato che entrambi sono open source e girano sulla tua macchina."], "heroImage": {"src": "/agents/reasonix-design/reasonix-design-hero.webp", "alt": "Ciclo di feedback del design con DeepSeek Reasonix: un agente da terminale che legge riferimenti di design, un browser che renderizza l'UI e un workspace, con una freccia di feedback che ritorna", "caption": "Il ciclo centrale: DeepSeek Reasonix lavora nel terminale rispetto ai tuoi riferimenti e alle tue convenzioni, tu verifichi l'UI in un browser reale, e itera — a basso costo, grazie alla cache di prefisso di DeepSeek."}, "tocLabel": "In questa pagina", "toc": [{"id": "what-is-reasonix", "label": "Cos'è realmente DeepSeek Reasonix"}, {"id": "why-design", "label": "Perché un agente DeepSeek economico si adatta al design"}, {"id": "setup", "label": "Configura DeepSeek Reasonix per il design (da zero)"}, {"id": "screenshot-workflow", "label": "Il flusso di lavoro dal riferimento all'UI"}, {"id": "extend", "label": "Skill, MCP e configurazione"}, {"id": "vs", "label": "DeepSeek Reasonix vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Insidie e l'aspetto da “AI slop”"}, {"id": "open-design", "label": "Progettare con DeepSeek Reasonix in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-reasonix", "heading": "Cos'è realmente DeepSeek Reasonix", "blocks": [{"kind": "p", "text": "DeepSeek Reasonix è un agente di codice AI per il terminale, open source (MIT), costruito dall'autore GitHub esengine e dalla community. È nativo per DeepSeek: progettato attorno ai meccanismi di cache di prefisso di DeepSeek così che le sessioni lunghe e iterative restino economiche. Legge il tuo repository, modifica i file con un editor SEARCH/REPLACE protetto da revisione, esegue comandi shell e lavora a partire da task in linguaggio naturale — pianificando e verificando anziché limitarsi a completare righe. È importante essere chiari sul fatto che questo è un progetto della community, non un prodotto ufficiale di DeepSeek l'azienda."}, {"kind": "p", "text": "Per il lavoro di design, ciò che conta è che si tratta di un agente di codice capace e consapevole del repo che gira su forti modelli DeepSeek a basso costo. I modelli DeepSeek che usa sono solo testo — non leggono nativamente le immagini — quindi il ciclo di design pratico è guidato dai riferimenti e verificato in un browser reale, anziché con l'agente che “vede” direttamente uno screenshot. L'efficienza di costo è il vantaggio rilevante per il design: puoi iterare sull'UI molte volte senza la fattura che di solito scoraggia i cicli stretti."}, {"kind": "steps", "items": [{"label": "Nativo per DeepSeek, BYOK", "body": "Reasonix gira su modelli DeepSeek come deepseek-v4-pro e deepseek-v4-flash. Porti la tua chiave API DeepSeek — la credenziale vive nel tuo ambiente, non nella configurazione dell'agente."}, {"label": "Editing consapevole del repo", "body": "Legge e modifica i file nel tuo progetto con un editor protetto da revisione ed esegue comandi shell, così può costruire e iterare su codice UI reale nel tuo repository."}, {"label": "Skill + MCP", "body": "Supporta skill scritte in Markdown e server MCP, così puoi dargli convenzioni durevoli e collegare contesto esterno come una fonte di design."}]}, {"kind": "ul", "items": ["Fornitore: community / l'autore GitHub esengine (non DeepSeek l'azienda)", "Credenziale: la tua chiave API DeepSeek (BYOK), fornita tramite ambiente", "Licenza: MIT, open source"]}]}, {"id": "why-design", "heading": "Perché un agente DeepSeek economico si adatta al design", "blocks": [{"kind": "p", "text": "Il vantaggio di DeepSeek Reasonix nel design riguarda meno una singola capacità appariscente e più il rendere economico e ripetibile il lavoro iterativo sull'UI — ma, come con ogni agente, il gusto va comunque fornito."}, {"kind": "steps", "items": [{"label": "Iterazione economica e stretta", "body": "Poiché è progettato attorno alla cache di prefisso di DeepSeek, le sessioni di design lunghe restano accessibili — così puoi eseguire il ciclo costruisci-verifica-rifinisci molte volte invece di razionarlo."}, {"label": "Riuso consapevole del repo", "body": "Modifica i file direttamente nel tuo repo, così può riutilizzare i tuoi componenti e token esistenti invece di inventare stili una tantum, quando lo punti verso di essi."}, {"label": "Convenzioni nelle skill", "body": "Le skill Markdown e la configurazione di progetto ti permettono di codificare token, componenti e regole di revisione, così l'agente lavora rispetto al tuo brand invece che su un aspetto predefinito."}]}, {"kind": "image", "src": "/agents/reasonix-design/reasonix-design-taste-triangle.webp", "alt": "Diagramma che mostra design system, skill e immagine di riferimento che convergono in un buon output di design", "caption": "Il gusto deriva da tre input che fornisci tu: un design system, una skill e immagini di riferimento reali."}, {"kind": "p", "text": "La lezione è la stessa che insegna ogni agente: DeepSeek Reasonix non ha gusto per impostazione predefinita. Produce un buon design quando gli dai dei vincoli — un design system, una skill estetica e riferimenti concreti descritti ad esso — e un browser rispetto a cui verificare. Open Design impacchetta esattamente questi input, ed è per questo che i due si integrano bene (più avanti il dettaglio)."}]}, {"id": "setup", "heading": "Configura DeepSeek Reasonix per il lavoro di design, da zero", "blocks": [{"kind": "p", "text": "Ecco il percorso da una macchina pulita a un DeepSeek Reasonix capace di costruire e verificare UI. Poiché è un progetto della community, segui sempre le istruzioni di installazione nel README del repo; lo schema qui sotto è la forma generale."}, {"kind": "code", "lang": "bash", "code": "# 1. Install DeepSeek Reasonix (Node 22+) — see the repo README\nnpm install -g reasonix\n\n# 2. Bring your own DeepSeek API key (BYOK)\n#    Reasonix reads it from your environment, not from config files.\nexport DEEPSEEK_API_KEY=sk-...    # your DeepSeek key\n\n# 3. Start it in your project\ncd your-project\nreasonix                         # see README for the exact subcommands\n\n# 4. Add a design source via MCP (optional)\n#    e.g. a Figma MCP server, configured per the repo docs"}, {"kind": "image", "src": "/agents/reasonix-design/reasonix-design-setup-flow.webp", "alt": "Flusso di configurazione in cinque passi: installa, aggiungi la tua chiave DeepSeek, configura le convenzioni, aggiungi una skill, verifica in un browser", "caption": "La sequenza di configurazione: installa → aggiungi la tua chiave API DeepSeek → codifica le convenzioni → aggiungi una skill → abilita la verifica nel browser."}, {"kind": "steps", "items": [{"label": "Codifica le tue regole di design", "body": "Metti i tuoi token, le primitive e le convenzioni in una skill o nella configurazione di progetto e punta Reasonix verso di essi, così l'output corrisponde a un brand invece di ripiegare su un aspetto generico."}, {"label": "Aggiungi la verifica nel browser", "body": "Poiché i modelli DeepSeek sono solo testo, collega un MCP Playwright o di browser così l'agente renderizza in un browser reale e controlla il suo output attraverso i breakpoint invece di limitarsi a confermare che la build passi."}]}]}, {"id": "screenshot-workflow", "heading": "Il flusso di lavoro dal riferimento all'UI", "blocks": [{"kind": "p", "text": "Il ciclo di design a maggior leva con DeepSeek Reasonix è trasformare riferimenti chiari in un'UI funzionante e responsive e iterare finché non corrisponde. Poiché i modelli DeepSeek sono solo testo, i riferimenti vengono forniti come descrizioni dettagliate e specifiche — non letti nativamente come immagini — e la corrispondenza viene confermata renderizzando in un browser reale."}, {"kind": "ol", "items": ["Traduci i tuoi riferimenti in specifiche concrete — descrivi layout, spaziatura, gerarchia e stati (desktop e mobile, hover, vuoto, caricamento) a parole, dato che il modello legge testo, non pixel.", "Sii specifico nel prompt; i prompt vaghi producono UI generiche anche con un modello forte.", "Tieni il tuo design system e le tue convenzioni in una skill o nella configurazione di progetto, e indica a Reasonix dove si trovano i token e le primitive canoniche.", "Avvia un dev server e verifica il risultato in un browser reale, ridimensionando ai breakpoint — collega un MCP di browser così l'agente può autocontrollarsi.", "Itera confrontando l'UI renderizzata con i tuoi riferimenti nel browser — non limitarti a confermare che si compili."]}, {"kind": "p", "text": "Dai all'agente vincoli concreti nel prompt anziché un brief vago:"}, {"kind": "code", "lang": "bash", "code": "reasonix\n# in the prompt:\n> Implement this design in React + Vite + Tailwind + TypeScript.\n  Reference: a two-column hero, 48px vertical rhythm, brand teal\n  accent, system-ui type — desktop and mobile described in DESIGN.md.\n  Reuse my existing design-system components and tokens.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in a browser and iterate until it matches the spec\n  across breakpoints."}, {"kind": "p", "text": "Tieni i prompt piccoli e mirati, committa le buone iterazioni e annulla quelle cattive (dicendolo a Reasonix quando annulli), così ogni passaggio si costruisce su una base pulita — e così il ciclo economico, favorevole alla cache, resta produttivo."}]}, {"id": "extend", "heading": "Skill, MCP e configurazione", "blocks": [{"kind": "p", "text": "Alcuni punti di estensione rendono DeepSeek Reasonix pratico per un lavoro di design continuativo, e si mappano in modo pulito su un flusso di lavoro di design aperto."}, {"kind": "steps", "items": [{"label": "Skill Markdown", "body": "Reasonix supporta skill scritte in Markdown — la sede durevole per le tue convenzioni di design, i token e le checklist di revisione, applicate a ogni esecuzione."}, {"label": "Server MCP", "body": "Integra server MCP, il modo portabile per portare contesto di design e strumenti esterni — più rilevante una fonte di design come un server MCP Figma — che funzionano tra gli agenti, non solo Reasonix."}, {"label": "Configurazione di progetto e strumenti integrati", "body": "La configurazione per progetto più gli strumenti integrati di file, shell e web gli permettono di raccogliere contesto ed eseguire il ciclo di verifica senza lasciare il terminale. Controlla il README del repo per i percorsi di configurazione esatti."}]}, {"kind": "p", "text": "Sono capacità portabili e multi-agente — esattamente il tipo di cosa che Open Design è costruito per orchestrare, invece di ricrearle per ogni progetto."}]}, {"id": "vs", "heading": "DeepSeek Reasonix vs Codex vs Claude Code vs Cursor vs Gemini CLI per il design", "blocks": [{"kind": "p", "text": "Non c'è un unico vincitore per il lavoro di design — ogni agente ha un punto di forza diverso, e i team esperti li combinano. Un riepilogo onesto:"}, {"kind": "table", "columns": ["Agente", "Punto di forza nel design", "Ideale per"], "rows": [["DeepSeek Reasonix", "Open source e alimentato da DeepSeek; economico grazie alla cache di prefisso, BYOK con la tua chiave DeepSeek (costruito dalla community, modelli solo testo)", "Iterazione economica e ad alto volume sull'UI nel tuo repo"], ["Codex", "Forte rifinitura visiva con una skill frontend; build asincrone in sandbox", "Build asincrone delegate e regole AGENTS.md portabili"], ["Claude Code", "Decisioni di design specifiche (hex, spaziatura, tipografia) e UX consapevole del codebase", "Ragionamento frontend e refactoring a grande contesto"], ["Cursor", "Ciclo visivo build-and-see con anteprima live e modifiche inline", "Lavoro su UI stretto, itera-e-osserva dentro un IDE"], ["Gemini CLI", "Forte comprensione multimodale delle immagini e contesto da 1M token; open source con tier gratuito", "Lavoro ricco di screenshot e mantenere un intero design system nel contesto"]]}, {"kind": "p", "text": "Il verdetto ricorrente della community è che il gusto viene dalle persone: tutti ripiegano su un'estetica generica senza skill, riferimenti e vincoli. Questo è il vero problema da risolvere — ed è di forma da strumento di design, non da modello."}]}, {"id": "pitfalls", "heading": "Insidie, e come evitare l'aspetto da “AI slop”", "blocks": [{"kind": "p", "text": "La lamentela più comune sul design generato dall'AI è che sembra generico — gradienti morbidi, pannelli fluttuanti, angoli arrotondati sovradimensionati, ombre drammatiche, un'atmosfera Inter-e-viola che “urla che l'ha fatto un'AI”. Altri problemi segnalati includono layout mobile rotti e istruzioni che finiscono nei testi dell'UI. Nessuno di questi è esclusivo di DeepSeek Reasonix; sono ciò che accade quando un qualsiasi agente gira senza un contesto di design curato — e poiché i suoi modelli sono solo testo, descrivere i riferimenti con precisione conta ancora di più."}, {"kind": "steps", "items": [{"label": "Aggiungi una skill estetica", "body": "Una skill di design curata costringe l'agente a impegnarsi su una direzione reale invece dell'aspetto predefinito."}, {"label": "Verifica in un browser reale", "body": "Poiché il modello non può vedere, renderizza e autocontrolla attraverso i breakpoint in un browser reale così i layout non si rompono silenziosamente su mobile."}, {"label": "Fornisci token e riferimenti descritti", "body": "Token di design reali e stati di riferimento descritti con precisione sono la leva singola più grande sulla qualità dell'output per un agente solo testo."}, {"label": "Codifica le regole in una skill o configurazione", "body": "Metti regole in stile “niente hero card, massimo due font, gerarchia brand-first” dove l'agente le legge a ogni esecuzione."}]}, {"kind": "p", "text": "Nota che ogni mitigazione riguarda il fornire all'agente un contesto di design curato. Mantenere quel contesto a mano, progetto per progetto, è la fatica che Open Design elimina."}]}, {"id": "open-design", "heading": "Progettare con DeepSeek Reasonix dentro Open Design", "blocks": [{"kind": "p", "text": "Open Design è il livello di design open source che il flusso di lavoro qui sopra continua a richiedere. Tratta DeepSeek Reasonix come un adattatore di prima parte e lo avvolge in una libreria curata di skill e design system, una pipeline di rendering strutturata e un'UI desktop locale — così il contesto di design che rende Reasonix valido è presente dalla prima esecuzione, non assemblato a mano ogni volta. Entrambi sono open source e local-first, il che rende l'abbinamento naturale."}, {"kind": "ol", "items": ["Installa Open Design e seleziona DeepSeek Reasonix come tuo agente.", "Autentica con la tua chiave API DeepSeek (BYOK) — le credenziali restano sulla tua macchina e non passano mai attraverso di noi tramite proxy.", "Scegli un design system e una skill, poi genera deck, prototipi e landing page con un gusto coerente.", "Ogni artefatto e file DESIGN.md vive nel tuo repo, non in un cloud ospitato."]}, {"kind": "p", "text": "Stesso agente DeepSeek Reasonix, stessa chiave — più un flusso di lavoro di design reale, portabile e open source attorno ad esso. È local-first e open source, quindi nulla del tuo lavoro o delle tue credenziali lascia la tua macchina."}]}], "faqTitle": "Domande frequenti", "faq": [{"name": "DeepSeek Reasonix può davvero fare lavoro di design?", "text": "Sì — con una skill estetica, un design system e riferimenti descritti con precisione nel contesto, DeepSeek Reasonix produce UI responsive di qualità da produzione nel tuo repo, e tu verifichi l'output in un browser reale. I suoi modelli DeepSeek sono solo testo, quindi il ciclo è riferimento-descritto-e-verificato anziché lettura di immagini. Senza quel contesto tende a ripiegare su un aspetto generico, che è il divario che Open Design colma."}, {"name": "Devo pagare per progettare con DeepSeek Reasonix?", "text": "Porti la tua chiave API DeepSeek, quindi paghi DeepSeek per l'uso (BYOK) — ma l'agente è costruito attorno alla cache di prefisso di DeepSeek per mantenere basso quel costo nelle sessioni lunghe. Reasonix in sé è gratuito e con licenza MIT. Open Design non fa mai da proxy alle tue credenziali."}, {"name": "DeepSeek Reasonix è un prodotto ufficiale di DeepSeek?", "text": "No. DeepSeek Reasonix è un progetto open source costruito dalla community dall'autore GitHub esengine — gira sui modelli di DeepSeek e usa una chiave API DeepSeek, ma non è realizzato né approvato da DeepSeek l'azienda. DeepSeek è un marchio del rispettivo proprietario."}, {"name": "DeepSeek Reasonix o Claude Code per il design frontend?", "text": "Entrambi possono fare vero lavoro di design. Claude Code è noto per decisioni di design specifiche e consapevoli del codebase; il vantaggio di DeepSeek Reasonix è l'essere open source ed economico, eseguendo iterazione economica e ad alto volume su modelli DeepSeek con la tua chiave. Molti team ne usano più di uno — Open Design ti permette di cambiare agente senza cambiare il tuo flusso di lavoro di design."}, {"name": "Come collego DeepSeek Reasonix a una fonte di design come Figma?", "text": "Reasonix supporta server MCP, così puoi aggiungere un MCP di fonte di design (come un server MCP Figma) secondo la documentazione del repo. L'agente può poi estrarre contesto di design reale — componenti, variabili, dati di layout — come testo su cui agire, così il codice generato corrisponde alla fonte invece di approssimarla."}, {"name": "Open Design è affiliato a DeepSeek?", "text": "No. DeepSeek Reasonix è un progetto della community che gira sui modelli di DeepSeek; Open Design è un progetto open source indipendente che lo supporta come adattatore di prima parte. Non è affiliato né a DeepSeek l'azienda né ai manutentori di Reasonix. DeepSeek è un marchio del rispettivo proprietario."}, {"name": "I miei file e le mie credenziali sono al sicuro?", "text": "Sì — Open Design è local-first e open source. I tuoi file, gli artefatti e DESIGN.md restano nel tuo repo, e la tua chiave API DeepSeek viene usata direttamente dal tuo agente, mai instradata attraverso i server di Open Design."}], "ctaTitle": "Progetta con DeepSeek Reasonix, alla maniera aperta.", "ctaBody": "Porta la tua chiave API DeepSeek, tieni ogni file in locale e ottieni una libreria di design curata attorno all'agente open source che già usi.", "ctaActions": [{"label": "Usa DeepSeek Reasonix dentro Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Metti una stella su GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Scarica l'app desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Vedi tutti gli agenti supportati"},
      },
      'hermes': {
        ...en['hermes']!,
        title: "Hermes per il design — Open Design",
        description: "Come si usa Hermes di Nous Research — l'agente di codice da terminale autonomo e multi-provider — per il design di UI e web, e come Open Design lo trasforma in un agente di design open source e local-first con la tua chiave xAI, OpenAI o Anthropic.",
        breadcrumb: "Hermes",
        label: "Agente · Hermes",
        heading: "Hermes per il design.",
        lead: "Hermes è l'agente da terminale autonomo e open source di Nous Research. Pianifica, esegue e delega il lavoro sulla propria macchina — ed è indipendente dal provider, quindi porti la tua chiave xAI, OpenAI o Anthropic. Quell'autonomia lo rende un vero strumento di design una volta che gli fornisci riferimenti, convenzioni e un ciclo di verifica. Open Design lo collega a un flusso di lavoro di design open source: la tua chiave, i tuoi file, local-first.",
        rich: {"heroCtaLead": "Open Design trasforma Hermes in un agente di design open source e local-first — la tua chiave xAI, OpenAI o Anthropic, i tuoi file, una libreria curata di skill e design system attorno ad esso.", "heroCtaActions": [{"label": "Usa Hermes dentro Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Metti una stella su GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Scarica l'app desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Hermes è l'agente AI autonomo e open source di Nous Research. Due caratteristiche lo rendono interessante per il design in particolare: è genuinamente agentico, quindi pianifica un task, lo esegue e delega parti a subagenti isolati anziché limitarsi a completare righe; ed è indipendente dal provider, quindi lo punti verso il modello di cui ti fidi — xAI Grok di default, oppure OpenAI e Anthropic tramite bring-your-own-key. Abbinato ai riferimenti giusti, alle convenzioni e a un ciclo di verifica, costruisce UI reali e responsive sulla tua macchina. Questa è una guida pratica ed end-to-end all'uso di Hermes per il lavoro su UI, frontend e design system, e a come integrarlo in un flusso di lavoro di design strutturato con Open Design.", "Copre cos'è realmente Hermes, perché un agente autonomo e multi-provider si adatta al design, come configurarlo da zero, il ciclo dallo screenshot all'UI, come le skill e i subagenti lo estendono, come si confronta con Codex, Claude Code, Cursor e Gemini CLI, le insidie che fanno sembrare generico l'output dell'AI, e come Open Design colma il divario come livello di design aperto e local-first — un abbinamento naturale, dato che entrambi sono open source e girano sulla tua macchina."], "heroImage": {"src": "/agents/hermes-design/hermes-design-hero.webp", "alt": "Ciclo di feedback del design con Hermes: un agente da terminale autonomo che legge un'immagine di riferimento, delega a subagenti, un browser che renderizza l'UI e un workspace, con una freccia di feedback che ritorna", "caption": "Il ciclo centrale: Hermes legge i tuoi riferimenti nel terminale, pianifica e delega la build, verifica l'UI in un browser reale, e itera in base ad essi — su qualsiasi modello tu porti."}, "tocLabel": "In questa pagina", "toc": [{"id": "what-is-hermes", "label": "Cos'è realmente Hermes"}, {"id": "why-design", "label": "Perché un agente autonomo e multi-provider si adatta al design"}, {"id": "setup", "label": "Configura Hermes per il design (da zero)"}, {"id": "screenshot-workflow", "label": "Il flusso di lavoro dallo screenshot all'UI"}, {"id": "extend", "label": "Skill, subagenti e provider"}, {"id": "vs", "label": "Hermes vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Insidie e l'aspetto da “AI slop”"}, {"id": "open-design", "label": "Progettare con Hermes in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-hermes", "heading": "Cos'è realmente Hermes", "blocks": [{"kind": "p", "text": "Hermes è un agente AI autonomo open source (MIT) di Nous Research. Gira in modo persistente sulla tua macchina o sul tuo server, legge il tuo repository, modifica i file, esegue comandi shell, cerca sul web e — soprattutto — pianifica ed esegue lavoro multi-step da solo, delegando parti a subagenti isolati. È un agente autonomo, non un copilota legato a un IDE."}, {"kind": "p", "text": "Per il lavoro di design spiccano due proprietà. È genuinamente agentico, quindi puoi affidargli un obiettivo e lui pianifica, costruisce e verifica anziché aspettare indicazioni riga per riga. Ed è indipendente dal provider: porti la tua chiave, con default su xAI Grok ma libero di puntarlo verso OpenAI, Anthropic o qualsiasi altro endpoint supportato — così controlli quale modello ragiona sul tuo design."}, {"kind": "steps", "items": [{"label": "Skill", "body": "Hermes costruisce e riutilizza skill — memoria procedurale che crea dall'esperienza — il luogo naturale per catturare le tue convenzioni di design, i token e le checklist di revisione così che persistano tra le esecuzioni."}, {"label": "Subagenti + strumenti", "body": "Genera subagenti isolati per flussi di lavoro paralleli e include strumenti per file, shell, web e browser, così può raccogliere riferimenti ed eseguire un ciclo costruisci-e-verifica senza lasciare il terminale."}, {"label": "Porta la tua chiave", "body": "Hermes ha default su xAI Grok e supporta OpenAI, Anthropic, OpenRouter e molti altri provider tramite BYOK — imposta una chiave o esegui un flusso OAuth e scegli il tuo modello."}]}, {"kind": "ul", "items": ["Fornitore: Nous Research", "Credenziale: chiave del provider tramite BYOK — xAI (Grok, default), OpenAI o Anthropic — aggiunta con hermes auth add", "Licenza: MIT, open source"]}]}, {"id": "why-design", "heading": "Perché un agente autonomo e multi-provider si adatta al design", "blocks": [{"kind": "p", "text": "Il vantaggio di Hermes nel design deriva da due proprietà — ma, come con ogni agente, il gusto va comunque fornito."}, {"kind": "steps", "items": [{"label": "Pianifica ed esegui in autonomia", "body": "Poiché Hermes pianifica, esegue e delega da solo, può prendere un obiettivo di design — corrispondi a questo riferimento, rendilo responsive — e iterare verso di esso invece di aver bisogno che ogni passo sia esplicitato."}, {"label": "Porta il modello di cui ti fidi", "body": "Il BYOK indipendente dal provider significa che scegli il modello di ragionamento per il lavoro: xAI Grok di default, oppure modelli OpenAI e Anthropic quando vuoi i loro punti di forza — nessun vincolo all'estetica di un solo fornitore."}, {"label": "Convenzioni nelle skill", "body": "Le skill (più un server MCP come Figma) puntano l'agente verso i tuoi token, componenti e specifiche reali, così lavora rispetto a un brand invece che su un aspetto predefinito."}]}, {"kind": "image", "src": "/agents/hermes-design/hermes-design-taste-triangle.webp", "alt": "Diagramma che mostra design system, skill e immagine di riferimento che convergono in un buon output di design", "caption": "Il gusto deriva da tre input che fornisci tu: un design system, una skill e immagini di riferimento reali."}, {"kind": "p", "text": "La lezione è la stessa che insegna ogni agente: Hermes non ha gusto per impostazione predefinita. Produce un buon design quando gli dai dei vincoli — un design system, una skill estetica e riferimenti concreti. Open Design impacchetta esattamente questi input, ed è per questo che i due si integrano bene (più avanti il dettaglio)."}]}, {"id": "setup", "heading": "Configura Hermes per il lavoro di design, da zero", "blocks": [{"kind": "p", "text": "Ecco il percorso completo da una macchina pulita a un Hermes capace di costruire e verificare UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Hermes (one-line installer from Nous Research)\ncurl -fsSL https://hermes-agent.nousresearch.com/install.sh | bash\n\n# 2. Run the setup wizard\nhermes setup\n\n# 3. Add a provider and authenticate (BYOK)\n#    default is xAI Grok; OpenAI / Anthropic also supported\nhermes auth add        # add a provider key or run its OAuth flow\nhermes model           # pick the provider and model (grok-4.3 by default)\n\n# 4. Wire a Figma MCP server (optional, for design handoff)\n#    configure it among Hermes' MCP / tool settings"}, {"kind": "image", "src": "/agents/hermes-design/hermes-design-setup-flow.webp", "alt": "Flusso di configurazione in cinque passi: installa, autentica, configura una skill, aggiungi un design system, verifica", "caption": "La sequenza di configurazione: installa → aggiungi una chiave del provider → cattura le regole di design in una skill → aggiungi un design system → abilita la verifica nel browser."}, {"kind": "steps", "items": [{"label": "Codifica le tue regole di design", "body": "Cattura i tuoi token, le primitive e le convenzioni in una skill Hermes e punta l'agente verso di esse, così l'output corrisponde a un brand invece di ripiegare su un aspetto generico."}, {"label": "Aggiungi la verifica nel browser", "body": "Collega un MCP Playwright o di browser così Hermes renderizza in un browser reale e controlla il suo output attraverso i breakpoint invece di limitarsi a confermare che la build passi."}]}]}, {"id": "screenshot-workflow", "heading": "Il flusso di lavoro dallo screenshot all'UI", "blocks": [{"kind": "p", "text": "Il ciclo di design a maggior leva con Hermes è trasformare un'immagine di riferimento in un'UI funzionante e responsive e iterare finché non corrisponde — lasciando che l'agente autonomo pianifichi la build e confronti il suo output con il riferimento."}, {"kind": "ol", "items": ["Parti dai riferimenti visivi più chiari che hai — e includi più stati (desktop e mobile, hover, vuoto, caricamento), non solo un'unica schermata hero.", "Sii specifico nel prompt; i prompt vaghi producono UI generiche anche con un modello forte.", "Tieni il tuo design system e le tue convenzioni in una skill, e indica a Hermes dove si trovano i token e le primitive canoniche.", "Avvia un dev server e fai renderizzare a Hermes in un browser reale, ridimensionando ai breakpoint per controllare il risultato.", "Itera facendo confrontare a Hermes la sua implementazione con gli screenshot — non limitarti a confermare che si compili."]}, {"kind": "p", "text": "Punta Hermes verso i tuoi riferimenti e dai vincoli concreti:"}, {"kind": "code", "lang": "bash", "code": "hermes\n# in the prompt:\n> Use reference-desktop.png and reference-mobile.png in this folder.\n  Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from my skill.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the references\n  across breakpoints."}, {"kind": "p", "text": "Tieni i prompt piccoli e mirati, committa le buone iterazioni e annulla quelle cattive (dicendolo a Hermes quando annulli), così ogni passaggio si costruisce su una base pulita."}]}, {"id": "extend", "heading": "Skill, subagenti e provider", "blocks": [{"kind": "p", "text": "Tre punti di estensione rendono Hermes pratico per un lavoro di design continuativo, e tutti e tre si mappano in modo pulito su un flusso di lavoro di design aperto."}, {"kind": "steps", "items": [{"label": "Skill", "body": "Hermes costruisce e riutilizza skill — memoria procedurale creata dall'esperienza. Sono la sede durevole per le tue convenzioni di design, applicate nelle esecuzioni successive invece di rispiegate ogni volta."}, {"label": "Subagenti e MCP", "body": "Delega il lavoro a subagenti isolati e supporta server MCP — il modo portabile per portare contesto di design e strumenti esterni, più rilevante un server MCP Figma, che funzionano tra gli agenti, non solo Hermes."}, {"label": "Scelta del provider", "body": "Poiché Hermes è indipendente dal provider (xAI Grok di default, OpenAI e Anthropic tramite BYOK), puoi abbinare il modello al task senza ricostruire il tuo flusso di lavoro."}]}, {"kind": "p", "text": "Sono capacità portabili e multi-agente — esattamente il tipo di cosa che Open Design è costruito per orchestrare, invece di ricrearle per ogni progetto."}]}, {"id": "vs", "heading": "Hermes vs Codex vs Claude Code vs Cursor vs Gemini CLI per il design", "blocks": [{"kind": "p", "text": "Non c'è un unico vincitore per il lavoro di design — ogni agente ha un punto di forza diverso, e i team esperti li combinano. Un riepilogo onesto:"}, {"kind": "table", "columns": ["Agente", "Punto di forza nel design", "Ideale per"], "rows": [["Hermes", "Agente autonomo pianifica-esegui-delega; BYOK indipendente dal provider (xAI Grok default, anche OpenAI/Anthropic); open source e self-hosted", "Build autonome senza intervento su qualsiasi modello di cui ti fidi, mantenute in locale"], ["Codex", "Forte rifinitura visiva con una skill frontend; build asincrone in sandbox", "Build asincrone delegate e regole AGENTS.md portabili"], ["Claude Code", "Decisioni di design specifiche (hex, spaziatura, tipografia) e UX consapevole del codebase", "Ragionamento frontend e refactoring a grande contesto"], ["Cursor", "Ciclo visivo build-and-see con anteprima live e modifiche inline", "Lavoro su UI stretto, itera-e-osserva dentro un IDE"], ["Gemini CLI", "Forte comprensione multimodale delle immagini e contesto da 1M token; tier gratuito", "Lavoro ricco di screenshot e mantenere un intero design system nel contesto"]]}, {"kind": "p", "text": "Il verdetto ricorrente della community è che il gusto viene dalle persone: tutti ripiegano su un'estetica generica senza skill, riferimenti e vincoli. Questo è il vero problema da risolvere — ed è di forma da strumento di design, non da modello."}]}, {"id": "pitfalls", "heading": "Insidie, e come evitare l'aspetto da “AI slop”", "blocks": [{"kind": "p", "text": "La lamentela più comune sul design generato dall'AI è che sembra generico — gradienti morbidi, pannelli fluttuanti, angoli arrotondati sovradimensionati, ombre drammatiche, un'atmosfera Inter-e-viola che “urla che l'ha fatto un'AI”. Altri problemi segnalati includono layout mobile rotti e istruzioni che finiscono nei testi dell'UI. Nessuno di questi è esclusivo di Hermes; sono ciò che accade quando un qualsiasi agente gira senza un contesto di design curato."}, {"kind": "steps", "items": [{"label": "Aggiungi una skill estetica", "body": "Una skill di design curata costringe l'agente a impegnarsi su una direzione reale invece dell'aspetto predefinito."}, {"label": "Verifica in un browser reale", "body": "Fai renderizzare e autocontrollare a Hermes attraverso i breakpoint così i layout non si rompono silenziosamente su mobile."}, {"label": "Fornisci token e riferimenti", "body": "Token di design reali e screenshot di riferimento sono la leva singola più grande sulla qualità dell'output."}, {"label": "Codifica le regole in una skill", "body": "Metti regole in stile “niente hero card, massimo due font, gerarchia brand-first” in una skill che l'agente applica a ogni esecuzione."}]}, {"kind": "p", "text": "Nota che ogni mitigazione riguarda il fornire all'agente un contesto di design curato. Mantenere quel contesto a mano, progetto per progetto, è la fatica che Open Design elimina."}]}, {"id": "open-design", "heading": "Progettare con Hermes dentro Open Design", "blocks": [{"kind": "p", "text": "Open Design è il livello di design open source che il flusso di lavoro qui sopra continua a richiedere. Tratta Hermes come un adattatore di prima parte e lo avvolge in una libreria curata di skill e design system, una pipeline di rendering strutturata e un'UI desktop locale — così il contesto di design che rende Hermes valido è presente dalla prima esecuzione, non assemblato a mano ogni volta. Entrambi sono open source e local-first, il che rende l'abbinamento naturale."}, {"kind": "ol", "items": ["Installa Open Design e seleziona Hermes come tuo agente.", "Autentica con la tua chiave del provider (BYOK) — xAI Grok di default, oppure OpenAI o Anthropic — le credenziali restano sulla tua macchina e non passano mai attraverso di noi tramite proxy.", "Scegli un design system e una skill, poi genera deck, prototipi e landing page con un gusto coerente.", "Ogni artefatto e file DESIGN.md vive nel tuo repo, non in un cloud ospitato."]}, {"kind": "p", "text": "Stesso agente Hermes, stessa chiave — più un flusso di lavoro di design reale, portabile e open source attorno ad esso. È local-first e Apache-2.0, quindi nulla del tuo lavoro o delle tue credenziali lascia la tua macchina."}]}], "faqTitle": "Domande frequenti", "faq": [{"name": "Hermes può davvero fare lavoro di design?", "text": "Sì — con una skill estetica, un design system e immagini di riferimento reali nel contesto, Hermes produce UI responsive di qualità da produzione, e come agente autonomo può renderizzare e verificare l'output rispetto ai riferimenti da solo. Senza quel contesto tende a ripiegare su un aspetto generico, che è il divario che Open Design colma."}, {"name": "Quali modelli e chiavi usa Hermes?", "text": "Hermes è indipendente dal provider e bring-your-own-key. Ha default su xAI Grok (ad esempio grok-4.3) e supporta anche OpenAI, Anthropic, OpenRouter e molti altri provider — aggiungi una chiave del provider (o esegui il suo flusso OAuth) con hermes auth add e scegli un modello con hermes model. Open Design non fa mai da proxy alle tue credenziali."}, {"name": "Cosa rende Hermes buono per il design in particolare?", "text": "Due cose: è genuinamente autonomo, quindi pianifica, costruisce e verifica l'UI anziché aspettare indicazioni riga per riga; ed è indipendente dal provider, così puoi eseguire il modello di ragionamento di cui ti fidi. Entrambe aiutano — ma il gusto viene comunque dal design system, dalla skill e dai riferimenti che fornisci."}, {"name": "Hermes o Claude Code per il design frontend?", "text": "Entrambi sono forti. Claude Code è noto per decisioni di design specifiche e consapevoli del codebase; il vantaggio di Hermes è il pianifica-ed-esegui autonomo più la scelta del provider — e puoi persino puntare Hermes verso una chiave Anthropic. Molti team usano entrambi — Open Design ti permette di cambiare agente senza cambiare il tuo flusso di lavoro di design."}, {"name": "Come collego Hermes a Figma?", "text": "Aggiungi un server MCP Figma nella configurazione degli strumenti di Hermes. Hermes può poi estrarre contesto di design reale — componenti, variabili, dati di layout — così il codice generato corrisponde alla fonte invece di approssimarla."}, {"name": "Open Design è affiliato a Nous Research?", "text": "No. Hermes è un prodotto di Nous Research; Open Design è un progetto open source indipendente che lo supporta come adattatore di prima parte. Hermes e Nous Research sono marchi del rispettivo proprietario."}, {"name": "I miei file e le mie credenziali sono al sicuro?", "text": "Sì — Open Design è local-first e Apache-2.0. I tuoi file, gli artefatti e DESIGN.md restano nel tuo repo, e le credenziali del tuo provider vengono usate direttamente dal tuo agente, mai instradate attraverso i server di Open Design."}], "ctaTitle": "Progetta con Hermes, alla maniera aperta.", "ctaBody": "Porta la tua chiave xAI, OpenAI o Anthropic, tieni ogni file in locale e ottieni una libreria di design curata attorno all'agente che già usi.", "ctaActions": [{"label": "Usa Hermes dentro Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Metti una stella su GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Scarica l'app desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Vedi tutti gli agenti supportati"},
      },
      'devin': {
        ...en['devin']!,
        title: "Devin for Terminal per il design — Open Design",
        description: "Come si usa Devin for Terminal — l'ingegnere software AI autonomo di Cognition nella riga di comando — per il design di UI e web, e come Open Design lo trasforma in un agente di design open source e local-first con una libreria curata di skill e design system.",
        breadcrumb: "Devin for Terminal",
        label: "Agente · Devin",
        heading: "Devin for Terminal per il design.",
        lead: "Devin for Terminal è l'ingegnere software AI autonomo di Cognition, in esecuzione nel tuo terminale. Pianifica ed esegue task multi-step da solo e può passare una sessione a un agente cloud in sandbox — il che lo rende un vero modo per consegnare lavoro frontend, una volta che gli fornisci riferimenti, convenzioni e un ciclo di verifica. Open Design lo collega a un flusso di lavoro di design open source: il tuo account Devin, i tuoi file, local-first.",
        rich: {"heroCtaLead": "Open Design trasforma Devin for Terminal in un agente di design open source e local-first — il tuo account Devin, i tuoi file, una libreria curata di skill e design system attorno ad esso.", "heroCtaActions": [{"label": "Usa Devin dentro Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Metti una stella su GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Scarica l'app desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Devin for Terminal è l'ingegnere software AI autonomo di Cognition, portato nella riga di comando locale. Due caratteristiche lo rendono interessante per il design in particolare: è genuinamente agentico, quindi pianifica ed esegue un task multi-step da capo a fondo anziché limitarsi a completare righe; e può passare una sessione a un agente cloud in sandbox con il proprio computer, così le build più lunghe continuano a girare dopo che hai chiuso il portatile. Abbinato ai riferimenti giusti, alle convenzioni e a un ciclo di verifica, costruisce UI reali e responsive. Questa è una guida pratica ed end-to-end all'uso di Devin for Terminal per il lavoro su UI, frontend e design system, e a come integrarlo in un flusso di lavoro di design strutturato con Open Design.", "Copre cos'è realmente Devin for Terminal, perché un ingegnere software autonomo si adatta al lavoro di design, come configurarlo da zero, il ciclo dallo screenshot all'UI, come le regole di progetto e gli strumenti esterni lo estendono, come si confronta con Codex, Claude Code, Cursor e Gemini CLI, le insidie che fanno sembrare generico l'output dell'AI, e come Open Design colma il divario come livello di design aperto e local-first — un abbinamento naturale per qualsiasi agente capace di pianificare e consegnare lavoro frontend."], "heroImage": {"src": "/agents/devin-design/devin-design-hero.webp", "alt": "Ciclo di feedback del design con Devin for Terminal: un agente da terminale autonomo che legge un'immagine di riferimento, un browser che renderizza l'UI e un workspace, con una freccia di feedback che ritorna", "caption": "Il ciclo centrale: Devin legge i tuoi riferimenti nel terminale, pianifica e costruisce l'UI, la verifica in un browser reale, e itera in base ad essi — passando le esecuzioni più lunghe al cloud quando serve."}, "tocLabel": "In questa pagina", "toc": [{"id": "what-is-devin", "label": "Cos'è realmente Devin for Terminal"}, {"id": "why-design", "label": "Perché un ingegnere software autonomo si adatta al design"}, {"id": "setup", "label": "Configura Devin per il design (da zero)"}, {"id": "screenshot-workflow", "label": "Il flusso di lavoro dallo screenshot all'UI"}, {"id": "extend", "label": "Regole di progetto, strumenti e handoff al cloud"}, {"id": "vs", "label": "Devin vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Insidie e l'aspetto da “AI slop”"}, {"id": "open-design", "label": "Progettare con Devin in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-devin", "heading": "Cos'è realmente Devin for Terminal", "blocks": [{"kind": "p", "text": "Devin for Terminal è la versione da riga di comando di Devin, l'ingegnere software AI autonomo di Cognition. Gira come agente di codice locale con accesso al tuo codebase, ai tuoi strumenti e al tuo ambiente — leggendo il tuo repository, modificando i file, eseguendo comandi shell, e pianificando e verificando il lavoro a partire da un task in linguaggio naturale anziché limitarsi a completare righe. Cognition ha costruito una libreria di rendering del terminale personalizzata in Rust per mantenere l'interfaccia veloce e reattiva."}, {"kind": "p", "text": "Per il lavoro di design spiccano due proprietà. È genuinamente autonomo, quindi puoi descrivere un risultato e lui esegue il percorso multi-step per arrivarci. E quando una build supera le capacità del tuo portatile, puoi passare la sessione a un agente cloud che gira nel proprio ambiente in sandbox e continua a lavorare in modo asincrono — così puoi tornare a una pull request finita."}, {"kind": "steps", "items": [{"label": "Esecuzione autonoma e agentica", "body": "Devin pianifica ed esegue un task multi-step da solo — implementando una funzionalità, costruendo UI, eseguendola e testandola — guidato da prompt chiari con criteri di completamento espliciti."}, {"label": "Agente locale, handoff al cloud", "body": "Gira in locale nel tuo terminale e può promuovere una sessione a un agente cloud in sandbox che ha il proprio computer e continua il lavoro dopo che ti sei allontanato."}, {"label": "Basato su account, scelta del modello", "body": "Accedi con un account Devin (Cognition); Devin gira su modelli di frontiera — puoi scegliere tra opzioni come la SWE-1.6 di Cognition e altri modelli di frontiera."}]}, {"kind": "ul", "items": ["Fornitore: Cognition", "Credenziale: account Devin (Cognition) — accesso basato su abbonamento/account, non bring-your-own-key", "Forma: agente da terminale locale con handoff opzionale a un cloud in sandbox"]}]}, {"id": "why-design", "heading": "Perché un ingegnere software autonomo si adatta al design", "blocks": [{"kind": "p", "text": "Il vantaggio di Devin nel design deriva da come lavora — esecuzione autonoma, end-to-end — ma, come con ogni agente, il gusto va comunque fornito."}, {"kind": "steps", "items": [{"label": "Build end-to-end, multi-step", "body": "Poiché Devin pianifica ed esegue interi task, può fare lo scaffolding di una pagina, cablare i componenti, avviare un dev server e testare il risultato in un colpo solo invece di fermarsi a uno snippet."}, {"label": "Esecuzioni cloud in sandbox", "body": "Il lavoro frontend più lungo — una landing page completa, un flusso a più schermate — può passare a un agente cloud in sandbox e continuare a costruire, così l'iterazione non è bloccata dal tuo portatile."}, {"label": "Convenzioni nelle regole di progetto", "body": "Punta l'agente verso i tuoi token, componenti e specifiche reali tramite le regole e la documentazione del tuo progetto, così lavora rispetto a un brand invece che su un aspetto predefinito."}]}, {"kind": "image", "src": "/agents/devin-design/devin-design-taste-triangle.webp", "alt": "Diagramma che mostra design system, skill e immagine di riferimento che convergono in un buon output di design", "caption": "Il gusto deriva da tre input che fornisci tu: un design system, una skill e immagini di riferimento reali."}, {"kind": "p", "text": "La lezione è la stessa che insegna ogni agente: Devin non ha gusto per impostazione predefinita. Produce un buon design quando gli dai dei vincoli — un design system, una skill estetica e riferimenti concreti. Open Design impacchetta esattamente questi input, ed è per questo che i due si integrano bene (più avanti il dettaglio)."}]}, {"id": "setup", "heading": "Configura Devin per il lavoro di design, da zero", "blocks": [{"kind": "p", "text": "Ecco il percorso completo da una macchina pulita a un Devin for Terminal capace di costruire e verificare UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Devin for Terminal\ncurl -fsSL https://cli.devin.ai/install.sh | bash\n\n# 2. Start it in your project and sign in on first run\ncd your-project\ndevin             # sign in with your Devin (Cognition) account\n\n# 3. Describe the task in natural language, with clear\n#    completion criteria, and let Devin plan and execute.\n\n# 4. When a build outgrows your laptop, hand the session\n#    off to a sandboxed cloud agent that keeps working."}, {"kind": "image", "src": "/agents/devin-design/devin-design-setup-flow.webp", "alt": "Flusso di configurazione in cinque passi: installa, accedi, codifica le regole di design, aggiungi riferimenti, verifica in un browser", "caption": "La sequenza di configurazione: installa → accedi → codifica le tue regole di design → fornisci riferimenti → verifica in un browser reale."}, {"kind": "steps", "items": [{"label": "Codifica le tue regole di design", "body": "Metti i tuoi token, le primitive e le convenzioni dove l'agente le legge — nelle regole e nella documentazione del tuo progetto — così l'output corrisponde a un brand invece di ripiegare su un aspetto generico."}, {"label": "Aggiungi la verifica nel browser", "body": "Fai renderizzare a Devin in un browser reale e controllare il suo output attraverso i breakpoint, così verifica rispetto al design invece di limitarsi a confermare che la build passi."}]}]}, {"id": "screenshot-workflow", "heading": "Il flusso di lavoro dallo screenshot all'UI", "blocks": [{"kind": "p", "text": "Il ciclo di design a maggior leva con Devin è trasformare un'immagine di riferimento in un'UI funzionante e responsive e iterare finché non corrisponde — lasciando che l'agente autonomo costruisca, esegua e confronti il suo output con il riferimento."}, {"kind": "ol", "items": ["Parti dai riferimenti visivi più chiari che hai — e includi più stati (desktop e mobile, hover, vuoto, caricamento), non solo un'unica schermata hero.", "Sii specifico nel prompt e dai criteri di completamento espliciti; i prompt vaghi producono UI generiche anche con un agente forte.", "Tieni il tuo design system e le tue convenzioni nelle regole di progetto, e indica a Devin dove si trovano i token e le primitive canoniche.", "Avvia un dev server e fai renderizzare a Devin in un browser reale, ridimensionando ai breakpoint per controllare il risultato.", "Itera facendo confrontare a Devin la sua implementazione con i riferimenti — non limitarti a confermare che si compili — e passa al cloud per i passaggi più lunghi."]}, {"kind": "p", "text": "Dai a Devin i riferimenti e vincoli concreti, con una chiara definizione di fatto:"}, {"kind": "code", "lang": "bash", "code": "devin\n# in the prompt:\n> Implement the attached reference (desktop + mobile) in\n  React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the\n  references across breakpoints. Done = pixel-close on both\n  desktop and mobile with no console errors."}, {"kind": "p", "text": "Tieni i prompt mirati, committa le buone iterazioni e annulla quelle cattive (dicendolo a Devin quando annulli), così ogni passaggio si costruisce su una base pulita."}]}, {"id": "extend", "heading": "Regole di progetto, strumenti e handoff al cloud", "blocks": [{"kind": "p", "text": "Tre punti di estensione rendono Devin for Terminal pratico per un lavoro di design continuativo, e tutti e tre si mappano in modo pulito su un flusso di lavoro di design aperto."}, {"kind": "steps", "items": [{"label": "Regole di progetto e contesto", "body": "Tieni le tue convenzioni di design, i token e le checklist di revisione nelle regole e nella documentazione del tuo progetto, così l'agente le legge a ogni esecuzione e lavora rispetto al tuo brand."}, {"label": "Codebase, strumenti e ambiente", "body": "Devin gira come agente locale con accesso al tuo codebase, ai tuoi strumenti e al tuo ambiente — può avviare un dev server, eseguire la build e verificare l'output senza lasciare il terminale."}, {"label": "Handoff al cloud in sandbox", "body": "Passa una sessione a un agente cloud nella propria sandbox per eseguire build più lunghe, test e creazione di PR in modo asincrono, poi torna a una pull request finita."}]}, {"kind": "p", "text": "Sono esattamente il tipo di capacità portabili e di forma agentica che Open Design è costruito per orchestrare, invece di ricrearle per ogni progetto."}]}, {"id": "vs", "heading": "Devin vs Codex vs Claude Code vs Cursor vs Gemini CLI per il design", "blocks": [{"kind": "p", "text": "Non c'è un unico vincitore per il lavoro di design — ogni agente ha un punto di forza diverso, e i team esperti li combinano. Un riepilogo onesto:"}, {"kind": "table", "columns": ["Agente", "Punto di forza nel design", "Ideale per"], "rows": [["Devin", "Ingegnere software completamente autonomo; pianifica ed esegue build multi-step e passa a un agente cloud in sandbox", "Delegare build frontend end-to-end che continuano a girare dopo che ti sei allontanato"], ["Codex", "Forte rifinitura visiva con una skill frontend; build asincrone in sandbox", "Build asincrone delegate e regole AGENTS.md portabili"], ["Claude Code", "Decisioni di design specifiche (hex, spaziatura, tipografia) e UX consapevole del codebase", "Ragionamento frontend e refactoring a grande contesto"], ["Cursor", "Ciclo visivo build-and-see con anteprima live e modifiche inline", "Lavoro su UI stretto, itera-e-osserva dentro un IDE"], ["Gemini CLI", "Forte comprensione multimodale delle immagini e contesto da 1M token; open source con tier gratuito", "Lavoro ricco di screenshot e mantenere un intero design system nel contesto"]]}, {"kind": "p", "text": "Il verdetto ricorrente della community è che il gusto viene dalle persone: tutti ripiegano su un'estetica generica senza skill, riferimenti e vincoli. Questo è il vero problema da risolvere — ed è di forma da strumento di design, non da modello."}]}, {"id": "pitfalls", "heading": "Insidie, e come evitare l'aspetto da “AI slop”", "blocks": [{"kind": "p", "text": "La lamentela più comune sul design generato dall'AI è che sembra generico — gradienti morbidi, pannelli fluttuanti, angoli arrotondati sovradimensionati, ombre drammatiche, un'atmosfera Inter-e-viola che “urla che l'ha fatto un'AI”. Altri problemi segnalati includono layout mobile rotti e istruzioni che finiscono nei testi dell'UI. Nessuno di questi è esclusivo di Devin; sono ciò che accade quando un qualsiasi agente gira senza un contesto di design curato."}, {"kind": "steps", "items": [{"label": "Aggiungi una skill estetica", "body": "Una skill di design curata costringe l'agente a impegnarsi su una direzione reale invece dell'aspetto predefinito."}, {"label": "Verifica in un browser reale", "body": "Fai renderizzare e autocontrollare a Devin attraverso i breakpoint così i layout non si rompono silenziosamente su mobile."}, {"label": "Fornisci token e riferimenti", "body": "Token di design reali e screenshot di riferimento sono la leva singola più grande sulla qualità dell'output."}, {"label": "Codifica le regole nel contesto di progetto", "body": "Metti regole in stile “niente hero card, massimo due font, gerarchia brand-first” dove l'agente le legge a ogni esecuzione, con criteri di completamento espliciti."}]}, {"kind": "p", "text": "Nota che ogni mitigazione riguarda il fornire all'agente un contesto di design curato. Mantenere quel contesto a mano, progetto per progetto, è la fatica che Open Design elimina."}]}, {"id": "open-design", "heading": "Progettare con Devin dentro Open Design", "blocks": [{"kind": "p", "text": "Open Design è il livello di design open source che il flusso di lavoro qui sopra continua a richiedere. Tratta Devin for Terminal come un adattatore di prima parte e lo avvolge in una libreria curata di skill e design system, una pipeline di rendering strutturata e un'UI desktop locale — così il contesto di design che rende Devin valido è presente dalla prima esecuzione, non assemblato a mano ogni volta. Open Design è open source e local-first, il che rende l'abbinamento naturale per un agente che già esegui nel tuo terminale."}, {"kind": "ol", "items": ["Installa Open Design e seleziona Devin for Terminal come tuo agente.", "Autentica con il tuo account Devin (Cognition) — le credenziali vengono usate direttamente dal tuo agente e non passano mai attraverso di noi tramite proxy.", "Scegli un design system e una skill, poi genera deck, prototipi e landing page con un gusto coerente.", "Ogni artefatto e file DESIGN.md vive nel tuo repo, non in un cloud ospitato."]}, {"kind": "p", "text": "Stesso agente Devin, stesso account — più un flusso di lavoro di design reale, portabile e open source attorno ad esso. Open Design è local-first e Apache-2.0, quindi nulla del tuo lavoro o delle tue credenziali lascia la tua macchina attraverso di noi."}]}], "faqTitle": "Domande frequenti", "faq": [{"name": "Devin for Terminal può davvero fare lavoro di design?", "text": "Sì — con una skill estetica, un design system e immagini di riferimento reali nel contesto, Devin produce UI responsive di qualità da produzione, e come agente autonomo può costruire, eseguire e verificare il risultato rispetto ai tuoi riferimenti. Senza quel contesto tende a ripiegare su un aspetto generico, che è il divario che Open Design colma."}, {"name": "Come accedo a Devin?", "text": "Devin è basato su account: accedi con un account Devin (Cognition) anziché portare la tua chiave del modello. Installa Devin for Terminal, eseguilo nel tuo progetto e autentica alla prima esecuzione. Open Design non fa mai da proxy alle tue credenziali — il tuo agente le usa direttamente."}, {"name": "Cosa rende Devin buono per il design in particolare?", "text": "È un ingegnere software completamente autonomo: pianifica ed esegue build frontend multi-step da capo a fondo, e può passare una sessione a un agente cloud in sandbox che continua a lavorare dopo che ti sei allontanato. Il gusto viene comunque dal design system, dalla skill e dai riferimenti che fornisci."}, {"name": "Devin o Claude Code per il design frontend?", "text": "Entrambi sono forti. Claude Code è noto per decisioni di design specifiche e consapevoli del codebase; il vantaggio di Devin è l'esecuzione completamente autonoma, end-to-end con handoff a un cloud in sandbox. Molti team usano entrambi — Open Design ti permette di cambiare agente senza cambiare il tuo flusso di lavoro di design."}, {"name": "Devin gira in una sandbox?", "text": "Devin for Terminal gira in locale con accesso al tuo codebase e al tuo ambiente, e può passare una sessione a un agente cloud che gira nel proprio ambiente in sandbox — utile per build più lunghe, test e creazione di PR che continuano in modo asincrono."}, {"name": "Open Design è affiliato a Cognition?", "text": "No. Devin for Terminal è un prodotto di Cognition; Open Design è un progetto open source indipendente che lo supporta come adattatore di prima parte. Devin è un marchio di Cognition."}, {"name": "I miei file e le mie credenziali sono al sicuro?", "text": "Sì — Open Design è local-first e Apache-2.0. I tuoi file, gli artefatti e DESIGN.md restano nel tuo repo, e le tue credenziali Devin vengono usate direttamente dal tuo agente, mai instradate attraverso i server di Open Design."}], "ctaTitle": "Progetta con Devin, alla maniera aperta.", "ctaBody": "Accedi con il tuo account Devin, tieni ogni file in locale e ottieni una libreria di design curata attorno all'agente autonomo che già usi.", "ctaActions": [{"label": "Usa Devin dentro Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Metti una stella su GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Scarica l'app desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Vedi tutti gli agenti supportati"},
      },
      'pi': {
        ...en['pi']!,
        title: "Pi per il design — Open Design",
        description: "Come si usa Pi, l'agente di codice da terminale multi-provider e open source, per il design di UI e web — il suo routing verso qualsiasi modello, le chiavi del provider BYOK, le Skill e le Extension — e come Open Design trasforma Pi in un agente di design open source e local-first.",
        breadcrumb: "Pi",
        label: "Agente · Pi",
        heading: "Pi per il design.",
        lead: "Pi è un agente di codice da terminale open source che instrada verso qualsiasi modello — Anthropic, OpenAI, Google e oltre 20 provider — con le tue chiavi API. Quel nucleo indipendente dal provider lo rende uno strumento di design flessibile: scegli il modello che oggi legge meglio gli screenshot, cambialo domani, mantieni il tuo flusso di lavoro. Open Design lo collega a un flusso di lavoro di design open source: le tue chiavi del provider, i tuoi file, local-first.",
        rich: {"heroCtaLead": "Open Design trasforma Pi in un agente di design open source e local-first — le tue chiavi API del provider, i tuoi file, una libreria curata di skill e design system attorno ad esso.", "heroCtaActions": [{"label": "Usa Pi dentro Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Metti una stella su GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Scarica l'app desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Pi è un agente di codice AI open source (MIT) per il terminale. Ciò che lo rende interessante per il design in particolare è che è indipendente dal provider: normalizza tra Anthropic, OpenAI, Google e oltre 20 altri provider dietro un'unica interfaccia, così autentichi con le tue chiavi API (BYOK) e scegli il modello adatto al task — e puoi cambiare modello a metà sessione senza dover reimparare lo strumento. Abbinato ai riferimenti giusti, alle convenzioni e a un ciclo di verifica, costruisce UI reali e responsive. Questa è una guida pratica ed end-to-end all'uso di Pi per il lavoro su UI, frontend e design system, e a come integrarlo in un flusso di lavoro di design strutturato con Open Design.", "Copre cos'è realmente Pi, perché un agente BYOK multi-provider si adatta al design, come configurarlo da zero, il ciclo dallo screenshot all'UI, come le Skill e le Extension lo estendono, come si confronta con Codex, Claude Code, Cursor e Gemini CLI, le insidie che fanno sembrare generico l'output dell'AI, e come Open Design colma il divario come livello di design aperto e local-first — un abbinamento naturale, dato che entrambi sono open source e girano sulla tua macchina."], "heroImage": {"src": "/agents/pi-design/pi-design-hero.webp", "alt": "Ciclo di feedback del design con Pi: un agente da terminale che legge un'immagine di riferimento, un browser che renderizza l'UI e un workspace, con una freccia di feedback che ritorna", "caption": "Il ciclo centrale: Pi legge i tuoi riferimenti nel terminale, costruisce e verifica l'UI in un browser reale, e itera in base ad essi — su qualunque provider tu lo punti."}, "tocLabel": "In questa pagina", "toc": [{"id": "what-is-pi", "label": "Cos'è realmente Pi"}, {"id": "why-design", "label": "Perché un agente BYOK multi-provider si adatta al design"}, {"id": "setup", "label": "Configura Pi per il design (da zero)"}, {"id": "screenshot-workflow", "label": "Il flusso di lavoro dallo screenshot all'UI"}, {"id": "extend", "label": "Skill, Extension e temi"}, {"id": "vs", "label": "Pi vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Insidie e l'aspetto da “AI slop”"}, {"id": "open-design", "label": "Progettare con Pi in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-pi", "heading": "Cos'è realmente Pi", "blocks": [{"kind": "p", "text": "Pi è un agente di codice AI open source (MIT) per il terminale, parte del toolkit pi di earendil-works. Legge il tuo repository, modifica i file ed esegue comandi shell — pianificando e verificando il lavoro a partire da task in linguaggio naturale anziché limitarsi a completare righe. Il suo nucleo è deliberatamente piccolo: quattro strumenti predefiniti — read, write, edit e bash — più grep, find e ls integrati."}, {"kind": "p", "text": "Per il lavoro di design, la proprietà che spicca è che Pi è indipendente dal provider. Normalizza tra Anthropic, OpenAI, Google e molti altri provider dietro un'unica API unificata, così porti le tue chiavi e scegli il modello per task — ad esempio un forte modello multimodale per leggere gli screenshot di riferimento — e cambi con /model o Ctrl+L a metà sessione senza modificare il tuo flusso di lavoro."}, {"kind": "steps", "items": [{"label": "Qualsiasi modello, le tue chiavi", "body": "Pi instrada verso oltre 20 provider, inclusi Anthropic e OpenAI. Autentichi con le tue chiavi API (BYOK), oppure accedi a un abbonamento Claude Pro/Max, ChatGPT Plus/Pro o GitHub Copilot con /login."}, {"label": "Skill + Extension", "body": "Pi carica Skill (pacchetti di capacità in Markdown che seguono lo standard Agent Skills) ed Extension in TypeScript — il luogo naturale per codificare le tue convenzioni di design e aggiungere strumenti personalizzati."}, {"label": "Sessioni ramificate", "body": "Le sessioni sono memorizzate come alberi JSONL, così puoi ramificare un'esplorazione e navigare la cronologia in un singolo file senza perdere i passaggi precedenti."}]}, {"kind": "ul", "items": ["Fornitore: earendil-works (progetto open source della community)", "Credenziale: la tua chiave API del provider (BYOK — Anthropic, OpenAI, Google, ecc.) o un accesso ad abbonamento tramite /login; memorizzata in locale in ~/.pi/agent/auth.json (0600)", "Licenza: MIT, open source"]}]}, {"id": "why-design", "heading": "Perché un agente BYOK multi-provider si adatta al design", "blocks": [{"kind": "p", "text": "Il vantaggio di Pi nel design è la flessibilità, non un singolo modello integrato — ma, come con ogni agente, il gusto va comunque fornito."}, {"kind": "steps", "items": [{"label": "Scegli il modello giusto per task", "body": "Poiché Pi instrada verso qualsiasi provider, puoi affidarti a un forte modello multimodale per leggere gli screenshot di riferimento, poi passare a un altro per il refactoring — senza lasciare l'agente."}, {"label": "Le tue chiavi, nessun vincolo", "body": "Il BYOK significa che non sei legato ai prezzi o ai limiti di contesto di un solo fornitore; scegli il modello i cui punti di forza si adattano al lavoro di design davanti a te."}, {"label": "Convenzioni nelle Skill", "body": "Una Skill (più una fonte MCP come un server Figma) punta l'agente verso i tuoi token, componenti e specifiche reali, così lavora rispetto a un brand invece che su un aspetto predefinito."}]}, {"kind": "image", "src": "/agents/pi-design/pi-design-taste-triangle.webp", "alt": "Diagramma che mostra design system, skill e immagine di riferimento che convergono in un buon output di design", "caption": "Il gusto deriva da tre input che fornisci tu: un design system, una skill e immagini di riferimento reali."}, {"kind": "p", "text": "La lezione è la stessa che insegna ogni agente: Pi non ha gusto per impostazione predefinita, e nessuna scelta di modello lo fornisce. Produce un buon design quando gli dai dei vincoli — un design system, una skill estetica e riferimenti concreti. Open Design impacchetta esattamente questi input, ed è per questo che i due si integrano bene (più avanti il dettaglio)."}]}, {"id": "setup", "heading": "Configura Pi per il lavoro di design, da zero", "blocks": [{"kind": "p", "text": "Ecco il percorso completo da una macchina pulita a un Pi capace di costruire e verificare UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install the Pi coding agent CLI (Node)\nnpm install -g --ignore-scripts @earendil-works/pi-coding-agent\n\n# 2. Authenticate with your own provider key (BYOK)\nexport ANTHROPIC_API_KEY=sk-ant-...   # or OPENAI_API_KEY=sk-...\n#    (or run /login inside Pi for a Claude / ChatGPT / Copilot subscription)\n\n# 3. Start it in your project\ncd your-project\npi\n\n# 4. Switch models any time with /model or Ctrl+L"}, {"kind": "image", "src": "/agents/pi-design/pi-design-setup-flow.webp", "alt": "Flusso di configurazione in cinque passi: installa, autentica, codifica le regole di design, aggiungi una skill, verifica", "caption": "La sequenza di configurazione: installa → autentica (BYOK) → codifica le regole di design in una Skill → scegli un modello → abilita la verifica nel browser."}, {"kind": "steps", "items": [{"label": "Codifica le tue regole di design", "body": "Metti i tuoi token, le primitive e le convenzioni in una Skill e punta Pi verso di esse, così l'output corrisponde a un brand invece di ripiegare su un aspetto generico."}, {"label": "Aggiungi la verifica nel browser", "body": "Collega un MCP Playwright o di browser così Pi renderizza in un browser reale e controlla il suo output attraverso i breakpoint invece di limitarsi a confermare che la build passi."}]}]}, {"id": "screenshot-workflow", "heading": "Il flusso di lavoro dallo screenshot all'UI", "blocks": [{"kind": "p", "text": "Il ciclo di design a maggior leva con Pi è trasformare un'immagine di riferimento in un'UI funzionante e responsive e iterare finché non corrisponde — appoggiandosi a un modello multimodale per confrontare l'output con il riferimento. Poiché Pi è indipendente dal provider, puntalo verso il modello che legge meglio le immagini per questo passaggio."}, {"kind": "ol", "items": ["Parti dai riferimenti visivi più chiari che hai — e includi più stati (desktop e mobile, hover, vuoto, caricamento), non solo un'unica schermata hero.", "Scegli un forte modello multimodale per il passaggio con /model, dato che la comprensione delle immagini è ciò che guida la qualità dallo screenshot all'UI.", "Sii specifico nel prompt; i prompt vaghi producono UI generiche anche con un modello forte.", "Tieni il tuo design system e le tue convenzioni in una Skill, e indica a Pi dove si trovano i token e le primitive canoniche.", "Avvia un dev server e fai renderizzare a Pi in un browser reale, ridimensionando ai breakpoint, poi itera confrontando la sua implementazione con gli screenshot — non limitarti a confermare che si compili."]}, {"kind": "p", "text": "Dai all'agente i riferimenti e i vincoli concreti fin da subito:"}, {"kind": "code", "lang": "bash", "code": "pi\n# in the prompt:\n> Implement reference-desktop.png and reference-mobile.png in\n  React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens (see the Skill).\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the references\n  across breakpoints."}, {"kind": "p", "text": "Tieni i prompt piccoli e mirati, committa le buone iterazioni e annulla quelle cattive (dicendolo a Pi quando annulli), così ogni passaggio si costruisce su una base pulita. Le sessioni JSONL ramificate di Pi ti permettono anche di esplorare un'alternativa senza perdere il thread originale."}]}, {"id": "extend", "heading": "Skill, Extension e temi", "blocks": [{"kind": "p", "text": "Pi si auto-estende a runtime attraverso alcuni livelli, e si mappano in modo pulito su un flusso di lavoro di design aperto."}, {"kind": "steps", "items": [{"label": "Skill", "body": "Pacchetti di capacità in Markdown che seguono lo standard Agent Skills — la sede durevole e portabile per le tue convenzioni di design, i token e le checklist di revisione. La stessa Skill funziona tra agenti compatibili, non solo Pi."}, {"label": "Extension e template di prompt", "body": "Le Extension in TypeScript aggiungono strumenti, comandi e UI personalizzati; i template di prompt riutilizzabili si eseguono tramite /name. Entrambi ti permettono di scriptare il ciclo di verifica senza lasciare il terminale."}, {"label": "MCP e temi", "body": "Pi si connette a server MCP per portare contesto di design esterno (più rilevante un server MCP Figma), e i temi si ricaricano a caldo così l'UI del terminale resta leggibile mentre lavori."}]}, {"kind": "p", "text": "Sono capacità portabili — Skill e MCP in particolare — esattamente il tipo di cosa che Open Design è costruito per orchestrare, invece di ricrearle per ogni progetto."}]}, {"id": "vs", "heading": "Pi vs Codex vs Claude Code vs Cursor vs Gemini CLI per il design", "blocks": [{"kind": "p", "text": "Non c'è un unico vincitore per il lavoro di design — ogni agente ha un punto di forza diverso, e i team esperti li combinano. Un riepilogo onesto:"}, {"kind": "table", "columns": ["Agente", "Punto di forza nel design", "Ideale per"], "rows": [["Pi", "Indipendente dal provider e BYOK — instrada verso qualsiasi modello (Anthropic, OpenAI, Google…) e cambia a metà sessione; MIT, auto-estensibile", "Scegliere il modello migliore per task senza vincolo a un fornitore"], ["Codex", "Forte rifinitura visiva con una skill frontend; build asincrone in sandbox", "Build asincrone delegate e regole AGENTS.md portabili"], ["Claude Code", "Decisioni di design specifiche (hex, spaziatura, tipografia) e UX consapevole del codebase", "Ragionamento frontend e refactoring a grande contesto"], ["Cursor", "Ciclo visivo build-and-see con anteprima live e modifiche inline", "Lavoro su UI stretto, itera-e-osserva dentro un IDE"], ["Gemini CLI", "Forte comprensione multimodale delle immagini e contesto da 1M token; tier gratuito", "Lavoro ricco di screenshot e mantenere un intero design system nel contesto"]]}, {"kind": "p", "text": "L'angolazione di Pi è ortogonale alle altre: è l'agente che ti permette di usare uno qualsiasi di quei modelli sottostanti con le tue chiavi. Il verdetto ricorrente della community vale ancora — il gusto viene dalle persone: tutti ripiegano su un'estetica generica senza skill, riferimenti e vincoli. Questo è il vero problema da risolvere, ed è di forma da strumento di design, non da modello."}]}, {"id": "pitfalls", "heading": "Insidie, e come evitare l'aspetto da “AI slop”", "blocks": [{"kind": "p", "text": "La lamentela più comune sul design generato dall'AI è che sembra generico — gradienti morbidi, pannelli fluttuanti, angoli arrotondati sovradimensionati, ombre drammatiche, un'atmosfera Inter-e-viola che “urla che l'ha fatto un'AI”. Altri problemi segnalati includono layout mobile rotti e istruzioni che finiscono nei testi dell'UI. Nessuno di questi è esclusivo di Pi o di un singolo modello; sono ciò che accade quando un qualsiasi agente gira senza un contesto di design curato."}, {"kind": "steps", "items": [{"label": "Aggiungi una skill estetica", "body": "Una skill di design curata costringe l'agente a impegnarsi su una direzione reale invece dell'aspetto predefinito — e poiché è una Skill portabile, viaggia con te tra i modelli."}, {"label": "Verifica in un browser reale", "body": "Scegli un modello multimodale e fai renderizzare e autocontrollare a Pi attraverso i breakpoint così i layout non si rompono silenziosamente su mobile."}, {"label": "Fornisci token e riferimenti", "body": "Token di design reali e screenshot di riferimento sono la leva singola più grande sulla qualità dell'output."}, {"label": "Codifica le regole dove Pi le legge", "body": "Metti regole in stile “niente hero card, massimo due font, gerarchia brand-first” in una Skill che l'agente carica a ogni esecuzione."}]}, {"kind": "p", "text": "Nota che ogni mitigazione riguarda il fornire all'agente un contesto di design curato — indipendentemente dal provider verso cui instradi. Mantenere quel contesto a mano, progetto per progetto, è la fatica che Open Design elimina."}]}, {"id": "open-design", "heading": "Progettare con Pi dentro Open Design", "blocks": [{"kind": "p", "text": "Open Design è il livello di design open source che il flusso di lavoro qui sopra continua a richiedere. Tratta Pi come un adattatore di prima parte e lo avvolge in una libreria curata di skill e design system, una pipeline di rendering strutturata e un'UI desktop locale — così il contesto di design che rende Pi valido è presente dalla prima esecuzione, non assemblato a mano ogni volta. Entrambi sono open source e local-first, il che rende l'abbinamento naturale."}, {"kind": "ol", "items": ["Installa Open Design e seleziona Pi come tuo agente.", "Autentica con la tua chiave API del provider (BYOK) o un accesso ad abbonamento — le credenziali restano sulla tua macchina in ~/.pi/agent/auth.json e non passano mai attraverso di noi tramite proxy.", "Scegli un design system e una skill, poi genera deck, prototipi e landing page con un gusto coerente.", "Ogni artefatto e file DESIGN.md vive nel tuo repo, non in un cloud ospitato."]}, {"kind": "p", "text": "Stesso agente Pi, stesse chiavi, stessa libertà di cambiare modello — più un flusso di lavoro di design reale, portabile e open source attorno ad esso. È local-first e MIT, quindi nulla del tuo lavoro o delle tue credenziali lascia la tua macchina."}]}], "faqTitle": "Domande frequenti", "faq": [{"name": "Pi può davvero fare lavoro di design?", "text": "Sì — con una skill estetica, un design system e immagini di riferimento reali nel contesto, Pi produce UI responsive di qualità da produzione, e puoi instradarlo verso un forte modello multimodale per verificare l'output rispetto ai riferimenti. Senza quel contesto tende a ripiegare su un aspetto generico, che è il divario che Open Design colma."}, {"name": "Devo pagare per progettare con Pi?", "text": "Pi in sé è gratuito e open source (MIT). Paghi solo per il modello sottostante — porta la tua chiave API del provider (BYOK), oppure usa un abbonamento Claude Pro/Max, ChatGPT Plus/Pro o GitHub Copilot tramite /login. Open Design non fa comunque mai da proxy alle tue credenziali."}, {"name": "Cosa rende Pi buono per il design in particolare?", "text": "È indipendente dal provider: porti le tue chiavi e instradi verso uno qualsiasi di oltre 20 provider, scegliendo il modello i cui punti di forza si adattano al task e cambiando a metà sessione. Ma il gusto viene comunque dal design system, dalla skill e dai riferimenti che fornisci, non dal modello."}, {"name": "Quale modello dovrei usare con Pi per il design frontend?", "text": "Pi instrada verso molti provider, quindi scegli per task — un forte modello multimodale legge bene gli screenshot di riferimento, mentre altri possono adattarsi al refactoring. Il vantaggio di Pi è che puoi cambiare senza modificare il tuo flusso di lavoro. Open Design ti permette di mantenere lo stesso contesto di design indipendentemente dal modello che scegli."}, {"name": "Come collego Pi a Figma?", "text": "Pi supporta server MCP, così puoi aggiungere un server MCP Figma ed estrarre contesto di design reale — componenti, variabili, dati di layout — così il codice generato corrisponde alla fonte invece di approssimarla."}, {"name": "Open Design è affiliato a Pi?", "text": "No. Pi è un progetto open source indipendente di earendil-works; Open Design è un progetto open source indipendente e separato che supporta Pi come adattatore di prima parte."}, {"name": "I miei file e le mie credenziali sono al sicuro?", "text": "Sì — Open Design è local-first e open source. I tuoi file, gli artefatti e DESIGN.md restano nel tuo repo, e le tue chiavi del provider vengono usate direttamente da Pi (memorizzate in locale in ~/.pi/agent/auth.json), mai instradate attraverso i server di Open Design."}], "ctaTitle": "Progetta con Pi, alla maniera aperta.", "ctaBody": "Porta le tue chiavi del provider, instrada verso qualsiasi modello, tieni ogni file in locale e ottieni una libreria di design curata attorno all'agente che già usi.", "ctaActions": [{"label": "Usa Pi dentro Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Metti una stella su GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Scarica l'app desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Vedi tutti gli agenti supportati"},
      },
      'kiro': {
        ...en['kiro']!,
        title: "Kiro CLI per il design — Open Design",
        description: "Come si usa il Kiro CLI di Amazon per il design di UI e web — il suo sviluppo guidato dalle specifiche, gli agent hook, i file di steering e MCP — e come Open Design trasforma Kiro CLI in un agente di design open source e local-first.",
        breadcrumb: "Kiro CLI",
        label: "Agente · Kiro CLI",
        heading: "Kiro CLI per il design.",
        lead: "Kiro CLI è l'agente da terminale di Amazon per lo sviluppo guidato dalle specifiche — trasforma un prompt in una specifica dei requisiti, un documento di design e un elenco di task prima di scrivere codice. Quella struttura è esattamente ciò di cui ha bisogno il lavoro di design: prima l'intento, poi la build. Open Design lo collega a un flusso di lavoro di design open source: il tuo Builder ID o accesso, i tuoi file, local-first.",
        rich: {"heroCtaLead": "Open Design trasforma Kiro CLI in un agente di design open source e local-first — il tuo AWS Builder ID o accesso, i tuoi file, una libreria curata di skill e design system attorno ad esso.", "heroCtaActions": [{"label": "Usa Kiro CLI dentro Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Metti una stella su GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Scarica l'app desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Kiro CLI è l'agente da terminale di Amazon per lo sviluppo guidato dalle specifiche. Ciò che lo rende distintivo è il flusso di lavoro: invece di saltare direttamente da un prompt al codice, Kiro formalizza i requisiti in una specifica, produce un documento di design e un elenco di task in sequenza, e solo allora implementa — mantenendo la build responsabile rispetto all'intento dichiarato. Distribuisce anche agent hook che scattano su eventi come il salvataggio di un file, file di steering che portano i tuoi standard e le tue convenzioni in ogni esecuzione, e il supporto al Model Context Protocol per strumenti esterni. Kiro è in preview, disponibile come IDE, CLI e interfaccia web, e puoi iniziare gratis. Questa è una guida pratica ed end-to-end all'uso di Kiro CLI per il lavoro su UI, frontend e design system, e a come integrarlo in un flusso di lavoro di design strutturato con Open Design.", "Copre cos'è realmente Kiro CLI, perché un flusso di lavoro guidato dalle specifiche si adatta al design, come configurarlo da zero, il ciclo dallo screenshot all'UI, come steering, hook e MCP lo estendono, come si confronta con Codex, Claude Code, Cursor e Gemini CLI, le insidie che fanno sembrare generico l'output dell'AI, e come Open Design colma il divario come livello di design aperto e local-first attorno ad esso."], "heroImage": {"src": "/agents/kiro-design/kiro-design-hero.webp", "alt": "Ciclo di feedback del design con Kiro CLI: un agente da terminale che trasforma una specifica in un design, un browser che renderizza l'UI e un workspace, con una freccia di feedback che ritorna", "caption": "Il ciclo centrale: Kiro CLI trasforma il tuo intento in una specifica e un elenco di task nel terminale, costruisce e verifica l'UI in un browser reale, e itera rispetto ai tuoi riferimenti."}, "tocLabel": "In questa pagina", "toc": [{"id": "what-is-kiro", "label": "Cos'è realmente Kiro CLI"}, {"id": "why-design", "label": "Perché lo sviluppo guidato dalle specifiche si adatta al design"}, {"id": "setup", "label": "Configura Kiro CLI per il design (da zero)"}, {"id": "screenshot-workflow", "label": "Il flusso di lavoro dallo screenshot all'UI"}, {"id": "extend", "label": "Specifiche, steering, hook e MCP"}, {"id": "vs", "label": "Kiro vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Insidie e l'aspetto da “AI slop”"}, {"id": "open-design", "label": "Progettare con Kiro CLI in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-kiro", "heading": "Cos'è realmente Kiro CLI", "blocks": [{"kind": "p", "text": "Kiro è un'AI agentica di Amazon che viene distribuita come IDE, interfaccia da riga di comando e interfaccia web, costruita per portarti dal prototipo alla produzione con lo sviluppo guidato dalle specifiche. Il Kiro CLI porta quell'agente nel tuo terminale: puoi avviare una sessione di chat interattiva, creare e gestire agenti, ed eseguire server Model Context Protocol — tutto dalla riga di comando. Kiro è in preview."}, {"kind": "p", "text": "Per il lavoro di design, la proprietà che lo definisce è il flusso di lavoro. Anziché trasformare un prompt direttamente in codice, Kiro scrive prima una specifica — requisiti, un documento di design e un elenco di task in sequenza — e implementa rispetto ad essa. Questo rende il piano dell'agente visibile e revisionabile prima che venga costruita alcuna UI, il che si mappa in modo pulito su come dovrebbero essere prese le decisioni di design: prima l'intento, poi l'esecuzione."}, {"kind": "steps", "items": [{"label": "Specifiche", "body": "Kiro trasforma un prompt in una specifica strutturata — requisiti, un documento di design e task discreti — prima di scrivere codice, così il piano è revisionabile fin dall'inizio."}, {"label": "Steering + hook", "body": "I file di steering portano i tuoi standard, le tue convenzioni e gli strumenti preferiti in ogni esecuzione; gli agent hook scattano su eventi come il salvataggio di un file per eseguire automaticamente task in background."}, {"label": "Gratuito per iniziare, pronto per MCP", "body": "Accedi con un Builder ID, Google, GitHub o la tua organizzazione e inizia gratis; Kiro CLI gestisce anche server MCP per portare contesto esterno."}]}, {"kind": "ul", "items": ["Fornitore: Amazon (AWS)", "Credenziale: AWS Builder ID, Google, GitHub o AWS IAM Identity Center tramite kiro-cli login (non è richiesto alcun account AWS)", "Stato: In preview; disponibile come IDE, CLI e interfaccia web"]}]}, {"id": "why-design", "heading": "Perché lo sviluppo guidato dalle specifiche si adatta al design", "blocks": [{"kind": "p", "text": "Il vantaggio di Kiro CLI nel design deriva dal suo flusso di lavoro — ma, come con ogni agente, il gusto va comunque fornito."}, {"kind": "steps", "items": [{"label": "Intento prima dei pixel", "body": "Poiché Kiro scrive prima una specifica e un documento di design, puoi correggere layout, gerarchia e ambito in fase di pianificazione — prima che l'agente si sia impegnato in un'implementazione generica."}, {"label": "Lo steering porta il tuo brand", "body": "I file di steering tengono i tuoi token, componenti e convenzioni davanti all'agente a ogni esecuzione, così l'output lavora rispetto a un brand invece che su un aspetto predefinito."}, {"label": "Gli hook fanno rispettare il ciclo", "body": "Gli agent hook possono eseguire controlli automaticamente al salvataggio — un posto dove cablare un passo di verifica o revisione anziché affidarsi alla memoria dell'agente."}]}, {"kind": "image", "src": "/agents/kiro-design/kiro-design-taste-triangle.webp", "alt": "Diagramma che mostra design system, skill e immagine di riferimento che convergono in un buon output di design", "caption": "Il gusto deriva da tre input che fornisci tu: un design system, una skill e immagini di riferimento reali."}, {"kind": "p", "text": "La lezione è la stessa che insegna ogni agente: Kiro CLI non ha gusto per impostazione predefinita. Una specifica mantiene onesta una build, ma produce un buon design solo quando gli dai dei vincoli — un design system, una skill estetica e riferimenti concreti. Open Design impacchetta esattamente questi input, ed è per questo che i due si integrano bene (più avanti il dettaglio)."}]}, {"id": "setup", "heading": "Configura Kiro CLI per il lavoro di design, da zero", "blocks": [{"kind": "p", "text": "Ecco il percorso completo da una macchina pulita a un Kiro CLI capace di costruire e verificare UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Kiro CLI (see kiro.dev/docs/cli for the macOS/Linux/Windows command)\n\n# 2. Authenticate — opens your browser to complete sign-in\nkiro-cli login   # choose Builder ID, Google, GitHub, or your organization\n\n# 3. Confirm you are signed in\nkiro-cli whoami\n\n# 4. Start an interactive session in your project\ncd your-project\nkiro-cli chat\n\n# 5. Wire MCP servers (optional, e.g. for design handoff)\nkiro-cli mcp add ..."}, {"kind": "image", "src": "/agents/kiro-design/kiro-design-setup-flow.webp", "alt": "Flusso di configurazione in cinque passi: installa, autentica, aggiungi lo steering, aggiungi una skill, verifica", "caption": "La sequenza di configurazione: installa → autentica → aggiungi steering e una specifica di design → aggiungi una skill → abilita la verifica nel browser."}, {"kind": "steps", "items": [{"label": "Codifica le tue regole di design", "body": "Metti i tuoi token, le primitive e le convenzioni nei file di steering così l'agente le legge a ogni esecuzione, e l'output corrisponde a un brand invece di ripiegare su un aspetto generico."}, {"label": "Aggiungi la verifica nel browser", "body": "Collega un server MCP Playwright o di browser così Kiro renderizza in un browser reale e controlla il suo output attraverso i breakpoint invece di limitarsi a confermare che la build passi."}]}]}, {"id": "screenshot-workflow", "heading": "Il flusso di lavoro dallo screenshot all'UI", "blocks": [{"kind": "p", "text": "Il ciclo di design a maggior leva con Kiro CLI è trasformare un'immagine di riferimento in un'UI funzionante e responsive e iterare finché non corrisponde — lasciando che la specifica catturi prima l'intento, poi costruendo rispetto ad essa."}, {"kind": "ol", "items": ["Parti dai riferimenti visivi più chiari che hai — e includi più stati (desktop e mobile, hover, vuoto, caricamento), non solo un'unica schermata hero.", "Lascia che Kiro scriva una specifica e un documento di design dal tuo prompt, e revisiona il piano prima che costruisca — è qui che intercetti precocemente i problemi di layout e ambito.", "Tieni il tuo design system e le tue convenzioni nei file di steering, e indica a Kiro dove si trovano i token e le primitive canoniche.", "Avvia un dev server e fai renderizzare a Kiro in un browser reale, ridimensionando ai breakpoint per controllare il risultato.", "Itera facendo confrontare a Kiro la sua implementazione con i riferimenti — non limitarti a confermare che si compili."]}, {"kind": "p", "text": "Apri una sessione interattiva e dai vincoli concreti fin da subito, così la specifica che scrive riflette il tuo intento reale:"}, {"kind": "code", "lang": "bash", "code": "kiro-cli chat\n# in the prompt:\n> Here are my references: reference-desktop.png and reference-mobile.png.\n  Write a spec, then implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens (see my steering files).\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the references\n  across breakpoints."}, {"kind": "p", "text": "Tieni i task piccoli e mirati, committa le buone iterazioni e annulla quelle cattive (dicendolo a Kiro quando annulli), così ogni passaggio si costruisce su una base pulita."}]}, {"id": "extend", "heading": "Specifiche, steering, hook e MCP", "blocks": [{"kind": "p", "text": "Quattro punti di estensione rendono Kiro CLI pratico per un lavoro di design continuativo, e tutti e quattro si mappano in modo pulito su un flusso di lavoro di design aperto."}, {"kind": "steps", "items": [{"label": "Specifiche", "body": "Requisiti, un documento di design e un elenco di task in sequenza — il registro durevole di ciò che una funzionalità deve essere, revisionabile prima e durante la build."}, {"label": "File di steering", "body": "Aggiungi contesto, standard di codice e flussi di lavoro o strumenti preferiti che l'agente legge a ogni esecuzione — la sede naturale per le tue convenzioni di design e i tuoi token."}, {"label": "Agent hook", "body": "Automazioni che si attivano su eventi come il salvataggio di un file, eseguendo task in background come controlli o documentazione — un posto dove far rispettare automaticamente un passo di verifica."}, {"label": "Server MCP", "body": "Kiro CLI gestisce server Model Context Protocol, il modo portabile per portare contesto di design e strumenti esterni che funzionano tra gli agenti, non solo Kiro."}]}, {"kind": "p", "text": "Sono capacità portabili e multi-agente — esattamente il tipo di cosa che Open Design è costruito per orchestrare, invece di ricrearle per ogni progetto."}]}, {"id": "vs", "heading": "Kiro vs Codex vs Claude Code vs Cursor vs Gemini CLI per il design", "blocks": [{"kind": "p", "text": "Non c'è un unico vincitore per il lavoro di design — ogni agente ha un punto di forza diverso, e i team esperti li combinano. Un riepilogo onesto:"}, {"kind": "table", "columns": ["Agente", "Punto di forza nel design", "Ideale per"], "rows": [["Kiro CLI", "Flusso di lavoro guidato dalle specifiche — requisiti, documento di design ed elenco di task prima del codice; i file di steering e gli hook mantengono le build on-brand", "Build strutturate e revisionabili dove intento e ambito sono bloccati prima dell'implementazione"], ["Codex", "Forte rifinitura visiva con una skill frontend; build asincrone in sandbox", "Build asincrone delegate e regole AGENTS.md portabili"], ["Claude Code", "Decisioni di design specifiche (hex, spaziatura, tipografia) e UX consapevole del codebase", "Ragionamento frontend e refactoring a grande contesto"], ["Cursor", "Ciclo visivo build-and-see con anteprima live e modifiche inline", "Lavoro su UI stretto, itera-e-osserva dentro un IDE"], ["Gemini CLI", "Forte comprensione multimodale delle immagini e un contesto molto ampio; open source con tier gratuito", "Lavoro ricco di screenshot e mantenere un intero design system nel contesto"]]}, {"kind": "p", "text": "Il verdetto ricorrente della community è che il gusto viene dalle persone: tutti ripiegano su un'estetica generica senza skill, riferimenti e vincoli. Questo è il vero problema da risolvere — ed è di forma da strumento di design, non da modello."}]}, {"id": "pitfalls", "heading": "Insidie, e come evitare l'aspetto da “AI slop”", "blocks": [{"kind": "p", "text": "La lamentela più comune sul design generato dall'AI è che sembra generico — gradienti morbidi, pannelli fluttuanti, angoli arrotondati sovradimensionati, ombre drammatiche, un'atmosfera Inter-e-viola che “urla che l'ha fatto un'AI”. Altri problemi segnalati includono layout mobile rotti e istruzioni che finiscono nei testi dell'UI. Nessuno di questi è esclusivo di Kiro CLI; sono ciò che accade quando un qualsiasi agente gira senza un contesto di design curato — una specifica mantiene una build sul compito, ma non fornisce gusto."}, {"kind": "steps", "items": [{"label": "Aggiungi una skill estetica", "body": "Una skill di design curata costringe l'agente a impegnarsi su una direzione reale invece dell'aspetto predefinito."}, {"label": "Verifica in un browser reale", "body": "Renderizza e autocontrolla attraverso i breakpoint — cablalo come hook se puoi — così i layout non si rompono silenziosamente su mobile."}, {"label": "Fornisci token e riferimenti", "body": "Token di design reali e screenshot di riferimento sono la leva singola più grande sulla qualità dell'output."}, {"label": "Codifica le regole nei file di steering", "body": "Metti regole in stile “niente hero card, massimo due font, gerarchia brand-first” dove l'agente le legge a ogni esecuzione."}]}, {"kind": "p", "text": "Nota che ogni mitigazione riguarda il fornire all'agente un contesto di design curato. Mantenere quel contesto a mano, progetto per progetto, è la fatica che Open Design elimina."}]}, {"id": "open-design", "heading": "Progettare con Kiro CLI dentro Open Design", "blocks": [{"kind": "p", "text": "Open Design è il livello di design open source che il flusso di lavoro qui sopra continua a richiedere. Tratta Kiro CLI come un adattatore di prima parte e lo avvolge in una libreria curata di skill e design system, una pipeline di rendering strutturata e un'UI desktop locale — così il contesto di design che rende Kiro valido è presente dalla prima esecuzione, non assemblato a mano ogni volta. Open Design è local-first, il che mantiene semplice l'abbinamento: i tuoi file e il tuo accesso restano sulla tua macchina."}, {"kind": "ol", "items": ["Installa Open Design e seleziona Kiro CLI come tuo agente.", "Autentica con il tuo AWS Builder ID o un altro accesso — le credenziali restano sulla tua macchina e non passano mai attraverso di noi tramite proxy.", "Scegli un design system e una skill, poi genera deck, prototipi e landing page con un gusto coerente.", "Ogni artefatto e file DESIGN.md vive nel tuo repo, non in un cloud ospitato."]}, {"kind": "p", "text": "Stesso agente Kiro CLI, stesso accesso — più un flusso di lavoro di design reale, portabile e open source attorno ad esso. Open Design è local-first e Apache-2.0, quindi nulla del tuo lavoro o delle tue credenziali lascia la tua macchina."}]}], "faqTitle": "Domande frequenti", "faq": [{"name": "Kiro CLI può davvero fare lavoro di design?", "text": "Sì — con una skill estetica, un design system e immagini di riferimento reali nel contesto, Kiro CLI produce UI responsive di qualità da produzione, e il suo flusso di lavoro guidato dalle specifiche mantiene la build responsabile rispetto all'intento dichiarato. Senza quel contesto tende a ripiegare su un aspetto generico, che è il divario che Open Design colma."}, {"name": "Mi serve un account AWS per usare Kiro CLI?", "text": "No — Kiro ti permette di accedere con un AWS Builder ID, Google, GitHub o la tua organizzazione (AWS IAM Identity Center), e non ti serve un account AWS per usarlo. Kiro è in preview e gratuito per iniziare. Open Design non fa comunque mai da proxy alle tue credenziali."}, {"name": "Cosa rende Kiro CLI buono per il design in particolare?", "text": "Il suo flusso di lavoro guidato dalle specifiche: Kiro scrive requisiti, un documento di design e un elenco di task prima di programmare, così correggi layout e ambito prima che la build si impegni. I file di steering portano le tue convenzioni e gli hook possono far rispettare i controlli — ma il gusto viene comunque dal design system, dalla skill e dai riferimenti che fornisci."}, {"name": "Kiro CLI o Claude Code per il design frontend?", "text": "Entrambi sono forti. Claude Code è noto per decisioni di design specifiche e consapevoli del codebase; il vantaggio di Kiro CLI è il suo flusso di lavoro guidato dalle specifiche e revisionabile con steering e hook. Molti team usano entrambi — Open Design ti permette di cambiare agente senza cambiare il tuo flusso di lavoro di design."}, {"name": "Come collego Kiro CLI a strumenti di design esterni?", "text": "Kiro CLI gestisce server Model Context Protocol (MCP) — usa kiro-cli mcp per aggiungerli. Un server MCP può portare contesto di design e strumenti reali nell'agente così il codice generato corrisponde alla fonte invece di approssimarla."}, {"name": "Open Design è affiliato ad Amazon o AWS?", "text": "No. Kiro è un prodotto di Amazon (AWS); Open Design è un progetto open source indipendente che lo supporta come adattatore di prima parte. Kiro è un marchio di Amazon."}, {"name": "I miei file e le mie credenziali sono al sicuro?", "text": "Sì — Open Design è local-first e Apache-2.0. I tuoi file, gli artefatti e DESIGN.md restano nel tuo repo, e il tuo accesso Kiro viene usato direttamente dal tuo agente, mai instradato attraverso i server di Open Design."}], "ctaTitle": "Progetta con Kiro CLI, alla maniera aperta.", "ctaBody": "Porta il tuo AWS Builder ID o accesso, tieni ogni file in locale e ottieni una libreria di design curata attorno all'agente che già usi.", "ctaActions": [{"label": "Usa Kiro CLI dentro Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Metti una stella su GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Scarica l'app desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Vedi tutti gli agenti supportati"},
      },
      'kilo': {
        ...en['kilo']!,
        title: "Kilo Code per il design — Open Design",
        description: "Come si usa Kilo Code — l'agente di codice AI open source e indipendente dal modello — per il design di UI e web: le sue modalità Architect/Code, il supporto MCP, il BYOK su molti provider, e come Open Design trasforma Kilo in un agente di design open source e local-first.",
        breadcrumb: "Kilo",
        label: "Agente · Kilo",
        heading: "Kilo Code per il design.",
        lead: "Kilo Code è un agente di codice AI open source e indipendente dal modello per il tuo IDE e la CLI. Poiché puoi puntarlo verso quasi ogni modello e portare le tue chiavi del provider, diventa un vero strumento di design una volta che gli fornisci riferimenti, convenzioni e un ciclo di verifica. Open Design lo collega a un flusso di lavoro di design open source: le tue chiavi del provider, i tuoi file, local-first.",
        rich: {"heroCtaLead": "Open Design trasforma Kilo Code in un agente di design open source e local-first — le tue chiavi del provider, i tuoi file, una libreria curata di skill e design system attorno ad esso.", "heroCtaActions": [{"label": "Usa Kilo Code dentro Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Metti una stella su GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Scarica l'app desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Kilo Code è un agente di codice AI open source che gira in VS Code, negli IDE JetBrains e nel terminale. Due caratteristiche lo rendono interessante per il design in particolare: è indipendente dal modello, così puoi guidarlo con qualunque modello di frontiera con capacità di visione legga meglio uno screenshot; ed è BYOK su molti provider, così mantieni il controllo di costi e credenziali. Abbinato ai riferimenti giusti, alle convenzioni e a un ciclo di verifica, costruisce UI reali e responsive. Questa è una guida pratica ed end-to-end all'uso di Kilo Code per il lavoro su UI, frontend e design system, e a come integrarlo in un flusso di lavoro di design strutturato con Open Design.", "Copre cos'è realmente Kilo Code, perché un agente aperto e indipendente dal modello si adatta al design, come configurarlo da zero, il ciclo dallo screenshot all'UI, come le regole personalizzate e MCP lo estendono, come si confronta con Codex, Claude Code, Cursor e Gemini CLI, le insidie che fanno sembrare generico l'output dell'AI, e come Open Design colma il divario come livello di design aperto e local-first — un abbinamento naturale, dato che entrambi sono open source e girano sulla tua macchina."], "heroImage": {"src": "/agents/kilo-design/kilo-design-hero.webp", "alt": "Ciclo di feedback del design con Kilo Code: un agente nell'IDE e nel terminale che legge un'immagine di riferimento, un browser che renderizza l'UI e un workspace, con una freccia di feedback che ritorna", "caption": "Il ciclo centrale: Kilo Code legge i tuoi riferimenti nell'IDE o nella CLI, costruisce e verifica l'UI in un browser reale, e itera in base ad essi — con il modello che scegli."}, "tocLabel": "In questa pagina", "toc": [{"id": "what-is-kilo", "label": "Cos'è realmente Kilo Code"}, {"id": "why-design", "label": "Perché un agente aperto e indipendente dal modello si adatta al design"}, {"id": "setup", "label": "Configura Kilo Code per il design (da zero)"}, {"id": "screenshot-workflow", "label": "Il flusso di lavoro dallo screenshot all'UI"}, {"id": "extend", "label": "Modalità, regole personalizzate e MCP"}, {"id": "vs", "label": "Kilo Code vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Insidie e l'aspetto da “AI slop”"}, {"id": "open-design", "label": "Progettare con Kilo Code in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-kilo", "heading": "Cos'è realmente Kilo Code", "blocks": [{"kind": "p", "text": "Kilo Code è un agente di codice AI open source costruito da Kilo Code, Inc. Gira come estensione di VS Code, negli IDE JetBrains e come interfaccia da riga di comando — leggendo il tuo repository, modificando i file, eseguendo comandi, e pianificando e verificando il lavoro a partire da task in linguaggio naturale anziché limitarsi a completare righe. Il suo tratto distintivo è che è indipendente dal modello: scegli quale modello lo guida, e porti le tue chiavi del provider."}, {"kind": "p", "text": "Per il lavoro di design spiccano due proprietà. Poiché è indipendente dal modello, puoi puntarlo verso qualunque forte modello con capacità di visione legga meglio uno screenshot di riferimento e ragioni sul layout. E poiché è open source e BYOK, puoi ispezionare esattamente quale contesto viene inviato e mantenere credenziali e costi sotto il tuo controllo."}, {"kind": "steps", "items": [{"label": "Modalità dell'agente", "body": "Kilo distribuisce modalità specializzate — Architect per pianificare, Code per costruire, Debug per correggere e Ask per le domande — più modalità personalizzate, così puoi pianificare un design e poi implementarlo in passaggi separati e mirati."}, {"label": "Regole personalizzate + MCP", "body": "Legge regole personalizzate a livello di progetto per il contesto persistente e supporta server MCP (con un marketplace MCP), così puoi aggiungere contesto esterno come un file Figma live o strumenti di design."}, {"label": "Porta le tue chiavi", "body": "Kilo è BYOK su molti provider — Anthropic, OpenAI, Google, OpenRouter e altri — oppure puoi usare il gateway di Kilo, che espone oltre 500 modelli al costo del provider."}]}, {"kind": "ul", "items": ["Fornitore: Kilo Code, Inc. (open source)", "Credenziale: la tua chiave API del provider (BYOK — Anthropic, OpenAI, Google, OpenRouter e altri) o il gateway di Kilo", "Licenza: open source"]}]}, {"id": "why-design", "heading": "Perché un agente aperto e indipendente dal modello si adatta al design", "blocks": [{"kind": "p", "text": "Il vantaggio di Kilo Code nel design deriva dall'apertura e dalla scelta del modello — ma, come con ogni agente, il gusto va comunque fornito."}, {"kind": "steps", "items": [{"label": "Indipendente dal modello per progettazione", "body": "Poiché scegli il modello, puoi guidare Kilo con qualunque modello con capacità di visione legga meglio gli screenshot di riferimento — e cambiarlo quando ne appare uno migliore, senza modificare il tuo flusso di lavoro."}, {"label": "Aperto e ispezionabile", "body": "Kilo è open source, così puoi vedere esattamente quale contesto e quali prompt vengono inviati — utile quando vuoi che l'agente riutilizzi le tue primitive di design reali invece di inventare stili una tantum."}, {"label": "Convenzioni nelle regole personalizzate", "body": "Le regole personalizzate di progetto (più un server MCP per Figma) puntano l'agente verso i tuoi token, componenti e specifiche reali, così lavora rispetto a un brand invece che su un aspetto predefinito."}]}, {"kind": "image", "src": "/agents/kilo-design/kilo-design-taste-triangle.webp", "alt": "Diagramma che mostra design system, skill e immagine di riferimento che convergono in un buon output di design", "caption": "Il gusto deriva da tre input che fornisci tu: un design system, una skill e immagini di riferimento reali."}, {"kind": "p", "text": "La lezione è la stessa che insegna ogni agente: Kilo Code non ha gusto per impostazione predefinita. Produce un buon design quando gli dai dei vincoli — un design system, una skill estetica e riferimenti concreti. Open Design impacchetta esattamente questi input, ed è per questo che i due si integrano bene (più avanti il dettaglio)."}]}, {"id": "setup", "heading": "Configura Kilo Code per il lavoro di design, da zero", "blocks": [{"kind": "p", "text": "Ecco il percorso completo da una macchina pulita a un Kilo Code capace di costruire e verificare UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install the Kilo Code extension from the VS Code\n#    (or JetBrains) marketplace, or install the CLI.\n\n# 2. Open your project and sign in / add a provider key\ncd your-project\nkilo              # connect your provider (BYOK) or Kilo's gateway\n\n# 3. Add project context\n#    create custom rules for this project's design conventions\n\n# 4. Wire the Figma MCP server (optional, for design handoff)\n#    add it from the MCP marketplace / MCP settings"}, {"kind": "image", "src": "/agents/kilo-design/kilo-design-setup-flow.webp", "alt": "Flusso di configurazione in cinque passi: installa, autentica, aggiungi regole personalizzate, aggiungi una skill, verifica", "caption": "La sequenza di configurazione: installa → connetti un provider → aggiungi regole personalizzate → aggiungi una skill → abilita la verifica nel browser."}, {"kind": "steps", "items": [{"label": "Codifica le tue regole di design", "body": "Metti i tuoi token, le primitive e le convenzioni nelle regole personalizzate di Kilo e punta l'agente verso di esse, così l'output corrisponde a un brand invece di ripiegare su un aspetto generico."}, {"label": "Aggiungi la verifica nel browser", "body": "Collega un MCP Playwright o di browser così Kilo renderizza in un browser reale e controlla il suo output attraverso i breakpoint invece di limitarsi a confermare che la build passi."}]}]}, {"id": "screenshot-workflow", "heading": "Il flusso di lavoro dallo screenshot all'UI", "blocks": [{"kind": "p", "text": "Il ciclo di design a maggior leva con Kilo Code è trasformare un'immagine di riferimento in un'UI funzionante e responsive e iterare finché non corrisponde — appoggiandosi a un modello con capacità di visione per confrontare l'output con il riferimento."}, {"kind": "ol", "items": ["Parti dai riferimenti visivi più chiari che hai — e includi più stati (desktop e mobile, hover, vuoto, caricamento), non solo un'unica schermata hero.", "Sii specifico nel prompt; i prompt vaghi producono UI generiche anche con un modello forte.", "Tieni il tuo design system e le tue convenzioni nelle regole personalizzate di Kilo, e indica all'agente dove si trovano i token e le primitive canoniche.", "Avvia un dev server e fai renderizzare a Kilo in un browser reale, ridimensionando ai breakpoint per controllare il risultato.", "Itera facendo confrontare a Kilo la sua implementazione con gli screenshot — non limitarti a confermare che si compili."]}, {"kind": "p", "text": "Usa la modalità Architect per pianificare la build, poi passa alla modalità Code e allega i tuoi riferimenti con vincoli concreti:"}, {"kind": "code", "lang": "bash", "code": "# Plan in Architect mode, then build in Code mode:\n> Implement this design from @reference-desktop.png and\n  @reference-mobile.png in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens\n  from the custom rules.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the\n  references across breakpoints."}, {"kind": "p", "text": "Tieni i prompt piccoli e mirati, committa le buone iterazioni e annulla quelle cattive (dicendolo a Kilo quando annulli), così ogni passaggio si costruisce su una base pulita."}]}, {"id": "extend", "heading": "Modalità, regole personalizzate e MCP", "blocks": [{"kind": "p", "text": "Tre punti di estensione rendono Kilo Code pratico per un lavoro di design continuativo, e tutti e tre si mappano in modo pulito su un flusso di lavoro di design aperto."}, {"kind": "steps", "items": [{"label": "Modalità (Architect → Code)", "body": "Pianifica la struttura di una schermata in modalità Architect, poi implementala in modalità Code e correggi i problemi in modalità Debug — separando l'intento di design dall'implementazione. Le modalità personalizzate ti permettono di codificare un tuo passo di revisione del design."}, {"label": "Regole personalizzate", "body": "Le regole personalizzate di progetto sono la sede durevole per le tue convenzioni di design — token, primitive e checklist di revisione — lette a ogni esecuzione così che l'agente lavori rispetto al tuo brand."}, {"label": "Server MCP", "body": "Kilo supporta server MCP tramite il suo marketplace — il modo portabile per portare contesto di design e strumenti esterni, più rilevante un server MCP Figma, che funzionano tra gli agenti, non solo Kilo."}]}, {"kind": "p", "text": "Sono capacità portabili e multi-agente — esattamente il tipo di cosa che Open Design è costruito per orchestrare, invece di ricrearle per ogni progetto."}]}, {"id": "vs", "heading": "Kilo Code vs Codex vs Claude Code vs Cursor vs Gemini CLI per il design", "blocks": [{"kind": "p", "text": "Non c'è un unico vincitore per il lavoro di design — ogni agente ha un punto di forza diverso, e i team esperti li combinano. Un riepilogo onesto:"}, {"kind": "table", "columns": ["Agente", "Punto di forza nel design", "Ideale per"], "rows": [["Kilo Code", "Open source e indipendente dal modello con BYOK su molti provider; modalità Architect/Code e MCP", "Scegliere il tuo modello per task e mantenere costi e credenziali sotto il tuo controllo"], ["Codex", "Forte rifinitura visiva con una skill frontend; build asincrone in sandbox", "Build asincrone delegate e regole AGENTS.md portabili"], ["Claude Code", "Decisioni di design specifiche (hex, spaziatura, tipografia) e UX consapevole del codebase", "Ragionamento frontend e refactoring a grande contesto"], ["Cursor", "Ciclo visivo build-and-see con anteprima live e modifiche inline", "Lavoro su UI stretto, itera-e-osserva dentro un IDE"], ["Gemini CLI", "Forte comprensione multimodale delle immagini e contesto da 1M token", "Lavoro ricco di screenshot e mantenere un intero design system nel contesto"]]}, {"kind": "p", "text": "Il verdetto ricorrente della community è che il gusto viene dalle persone: tutti ripiegano su un'estetica generica senza skill, riferimenti e vincoli. Questo è il vero problema da risolvere — ed è di forma da strumento di design, non da modello."}]}, {"id": "pitfalls", "heading": "Insidie, e come evitare l'aspetto da “AI slop”", "blocks": [{"kind": "p", "text": "La lamentela più comune sul design generato dall'AI è che sembra generico — gradienti morbidi, pannelli fluttuanti, angoli arrotondati sovradimensionati, ombre drammatiche, un'atmosfera Inter-e-viola che “urla che l'ha fatto un'AI”. Altri problemi segnalati includono layout mobile rotti e istruzioni che finiscono nei testi dell'UI. Nessuno di questi è esclusivo di Kilo Code; sono ciò che accade quando un qualsiasi agente gira senza un contesto di design curato."}, {"kind": "steps", "items": [{"label": "Aggiungi una skill estetica", "body": "Una skill di design curata costringe l'agente a impegnarsi su una direzione reale invece dell'aspetto predefinito."}, {"label": "Verifica in un browser reale", "body": "Usa un modello con capacità di visione per renderizzare e autocontrollare attraverso i breakpoint così i layout non si rompono silenziosamente su mobile."}, {"label": "Fornisci token e riferimenti", "body": "Token di design reali e screenshot di riferimento sono la leva singola più grande sulla qualità dell'output."}, {"label": "Codifica le regole nelle regole personalizzate", "body": "Metti regole in stile “niente hero card, massimo due font, gerarchia brand-first” dove l'agente le legge a ogni esecuzione."}]}, {"kind": "p", "text": "Nota che ogni mitigazione riguarda il fornire all'agente un contesto di design curato. Mantenere quel contesto a mano, progetto per progetto, è la fatica che Open Design elimina."}]}, {"id": "open-design", "heading": "Progettare con Kilo Code dentro Open Design", "blocks": [{"kind": "p", "text": "Open Design è il livello di design open source che il flusso di lavoro qui sopra continua a richiedere. Tratta Kilo Code come un adattatore di prima parte e lo avvolge in una libreria curata di skill e design system, una pipeline di rendering strutturata e un'UI desktop locale — così il contesto di design che rende Kilo valido è presente dalla prima esecuzione, non assemblato a mano ogni volta. Entrambi sono open source e local-first, il che rende l'abbinamento naturale."}, {"kind": "ol", "items": ["Installa Open Design e seleziona Kilo Code come tuo agente.", "Autentica con la tua chiave del provider (BYOK) o il gateway di Kilo — le credenziali restano sulla tua macchina e non passano mai attraverso di noi tramite proxy.", "Scegli un design system e una skill, poi genera deck, prototipi e landing page con un gusto coerente.", "Ogni artefatto e file DESIGN.md vive nel tuo repo, non in un cloud ospitato."]}, {"kind": "p", "text": "Stesso agente Kilo Code, stesse chiavi — più un flusso di lavoro di design reale, portabile e open source attorno ad esso. È local-first e open source, quindi nulla del tuo lavoro o delle tue credenziali lascia la tua macchina."}]}], "faqTitle": "Domande frequenti", "faq": [{"name": "Kilo Code può davvero fare lavoro di design?", "text": "Sì — con una skill estetica, un design system e immagini di riferimento reali nel contesto, Kilo Code produce UI responsive di qualità da produzione, e un modello con capacità di visione verifica l'output rispetto ai riferimenti. Senza quel contesto tende a ripiegare su un aspetto generico, che è il divario che Open Design colma."}, {"name": "Devo pagare per progettare con Kilo Code?", "text": "Kilo Code è open source e gratuito da installare. Porti la tua chiave API del provider (BYOK) e paghi quel provider direttamente, oppure usi il gateway di Kilo al costo del provider. Open Design non fa comunque mai da proxy alle tue credenziali."}, {"name": "Cosa rende Kilo Code buono per il design in particolare?", "text": "È indipendente dal modello e open source, così puoi guidarlo con qualunque modello con capacità di visione legga meglio gli screenshot di riferimento, ispezionare esattamente quale contesto viene inviato e mantenere costi e credenziali sotto il tuo controllo. Il gusto viene comunque dal design system, dalla skill e dai riferimenti che fornisci."}, {"name": "Kilo Code o Claude Code per il design frontend?", "text": "Entrambi sono forti. Claude Code è noto per decisioni di design specifiche e consapevoli del codebase; il vantaggio di Kilo Code è l'essere open source e indipendente dal modello con BYOK, così scegli il modello. Molti team usano entrambi — Open Design ti permette di cambiare agente senza cambiare il tuo flusso di lavoro di design."}, {"name": "Come collego Kilo Code a Figma?", "text": "Aggiungi un server MCP Figma dal marketplace MCP di Kilo o dalle impostazioni MCP. Kilo può poi estrarre contesto di design reale — componenti, variabili, dati di layout — così il codice generato corrisponde alla fonte invece di approssimarla."}, {"name": "Open Design è affiliato a Kilo Code?", "text": "No. Kilo Code è un prodotto di Kilo Code, Inc.; Open Design è un progetto open source indipendente che lo supporta come adattatore di prima parte. Entrambi sono open source, ma sono progetti separati."}, {"name": "I miei file e le mie credenziali sono al sicuro?", "text": "Sì — Open Design è local-first e open source. I tuoi file, gli artefatti e DESIGN.md restano nel tuo repo, e le credenziali del tuo provider vengono usate direttamente dal tuo agente, mai instradate attraverso i server di Open Design."}], "ctaTitle": "Progetta con Kilo Code, alla maniera aperta.", "ctaBody": "Porta la tua chiave del provider, tieni ogni file in locale e ottieni una libreria di design curata attorno all'agente che già usi.", "ctaActions": [{"label": "Usa Kilo Code dentro Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Metti una stella su GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Scarica l'app desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Vedi tutti gli agenti supportati"},
      },
      'vibe': {
        ...en['vibe']!,
        title: "Mistral Vibe CLI per il design — Open Design",
        description: "Come si usa il Vibe CLI di Mistral per il design di UI e web — i suoi modelli di codice Devstral open-weights, l'editing agentico multi-file, config.toml, MCP e ACP — e come Open Design trasforma Vibe CLI in un agente di design open source e local-first.",
        breadcrumb: "Mistral Vibe CLI",
        label: "Agente · Mistral Vibe CLI",
        heading: "Mistral Vibe CLI per il design.",
        lead: "Mistral Vibe CLI è l'agente di codice da terminale open source di Mistral AI, alimentato dalla famiglia di modelli Devstral. Modifica i file, esegue comandi e lavora tramite l'Agent Client Protocol — il che lo rende un vero strumento di design una volta che gli fornisci riferimenti, convenzioni e un ciclo di verifica. Open Design lo collega a un flusso di lavoro di design open source: la tua chiave API Mistral (BYOK) o modelli locali, i tuoi file, local-first.",
        rich: {"heroCtaLead": "Open Design trasforma Mistral Vibe CLI in un agente di design open source e local-first — la tua chiave API Mistral o modelli Devstral locali, i tuoi file, una libreria curata di skill e design system attorno ad esso.", "heroCtaActions": [{"label": "Usa Vibe CLI dentro Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Metti una stella su GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Scarica l'app desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Mistral Vibe CLI è l'agente di codice open source (Apache-2.0) di Mistral AI per il terminale. Scansiona la struttura dei file e lo stato Git del tuo progetto per il contesto, poi esplora, modifica ed esegue cambiamenti in tutto il tuo codebase a partire da task in linguaggio naturale. Due caratteristiche lo rendono interessante per il design in particolare: è alimentato dai modelli di codice Devstral di Mistral, parte di un ecosistema open-weights che puoi eseguire in locale o nel cloud; e parla l'Agent Client Protocol (ACP), così si inserisce in editor e strumenti anziché vivere solo in un terminale. Abbinato ai riferimenti giusti, alle convenzioni e a un ciclo di verifica, costruisce UI reali e responsive. Questa è una guida pratica ed end-to-end all'uso di Vibe CLI per il lavoro su UI, frontend e design system, e a come integrarlo in un flusso di lavoro di design strutturato con Open Design.", "Copre cos'è realmente Vibe CLI, perché un agente di codice open-weights si adatta al design, come configurarlo da zero, il ciclo dal riferimento all'UI, come config.toml, MCP e ACP lo estendono, come si confronta con Codex, Claude Code, Cursor e Gemini CLI, le insidie che fanno sembrare generico l'output dell'AI, e come Open Design colma il divario come livello di design aperto e local-first — un abbinamento naturale, dato che entrambi sono open source e girano sulla tua macchina."], "heroImage": {"src": "/agents/vibe-design/vibe-design-hero.webp", "alt": "Ciclo di feedback del design con Mistral Vibe CLI: un agente da terminale che legge un riferimento, un browser che renderizza l'UI e un workspace, con una freccia di feedback che ritorna", "caption": "Il ciclo centrale: Vibe CLI legge i tuoi riferimenti nel terminale, costruisce e verifica l'UI in un browser reale, e itera in base ad essi — guidato dai modelli di codice Devstral di Mistral."}, "tocLabel": "In questa pagina", "toc": [{"id": "what-is-vibe", "label": "Cos'è realmente Mistral Vibe CLI"}, {"id": "why-design", "label": "Perché un agente di codice open-weights si adatta al design"}, {"id": "setup", "label": "Configura Vibe CLI per il design (da zero)"}, {"id": "screenshot-workflow", "label": "Il flusso di lavoro dal riferimento all'UI"}, {"id": "extend", "label": "config.toml, MCP e ACP"}, {"id": "vs", "label": "Vibe CLI vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Insidie e l'aspetto da “AI slop”"}, {"id": "open-design", "label": "Progettare con Vibe CLI in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-vibe", "heading": "Cos'è realmente Mistral Vibe CLI", "blocks": [{"kind": "p", "text": "Mistral Vibe CLI è un agente di codice open source (Apache-2.0) che Mistral AI distribuisce per il terminale. Fornisce un'interfaccia di chat interattiva con strumenti per la manipolazione dei file, la ricerca nel codice, il controllo di versione e l'esecuzione di comandi, e scansiona automaticamente la struttura dei file e lo stato Git del tuo progetto per dare all'agente contesto rilevante. È alimentato dai modelli di codice Devstral di Mistral — pianificando e verificando il lavoro a partire da task in linguaggio naturale anziché limitarsi a completare righe."}, {"kind": "p", "text": "Per il lavoro di design spiccano due proprietà. Gira sulla famiglia Devstral open-weights di Mistral (Devstral 2 e il più piccolo Devstral Small 2), così puoi eseguire l'agente rispetto all'API Mistral nel cloud o rispetto a modelli locali — utile per il lavoro di design sensibile alla privacy o offline. E parla l'Agent Client Protocol, così lo stesso agente può pilotare editor e strumenti, non solo una sessione di terminale."}, {"kind": "steps", "items": [{"label": "File di configurazione", "body": "Vibe CLI è configurato tramite un file config.toml (a livello di progetto ./.vibe/config.toml, con un fallback in ~/.vibe/config.toml). È un posto pratico per codificare i tuoi provider, la scelta del modello e le impostazioni di progetto."}, {"label": "Strumenti integrati + MCP", "body": "Distribuisce strumenti per file, ricerca, controllo di versione ed esecuzione di comandi, e supporta server MCP (configurati sotto una sezione [[mcp_servers]]) per aggiungere contesto esterno come un file Figma live."}, {"label": "BYOK o locale", "body": "Autentica con una chiave API Mistral dalla console Mistral, oppure puntalo verso modelli locali/compatibili così funziona completamente offline."}]}, {"kind": "ul", "items": ["Fornitore: Mistral AI", "Credenziale: chiave API Mistral (BYOK) dalla console Mistral, oppure modelli locali / compatibili", "Licenza: Apache-2.0, open source"]}]}, {"id": "why-design", "heading": "Perché un agente di codice open-weights si adatta al design", "blocks": [{"kind": "p", "text": "Il vantaggio di Vibe CLI nel design deriva dalla sua famiglia di modelli open-weights e dalla sua portata di protocollo — ma, come con ogni agente, il gusto va comunque fornito."}, {"kind": "steps", "items": [{"label": "Modelli di codice Devstral", "body": "Vibe gira sulla famiglia Devstral di Mistral, modelli ottimizzati per il codice e costruiti per il lavoro agentico e multi-file — così l'agente modifica in tutto un codebase frontend reale anziché emettere snippet isolati."}, {"label": "Open-weights e adatto al locale", "body": "Devstral Small 2 è abbastanza piccolo da girare su hardware consumer, così il lavoro di design può restare completamente locale e offline — riferimenti e codice non devono mai lasciare la tua macchina."}, {"label": "Convenzioni in config.toml + contesto", "body": "La configurazione di progetto e le tue istruzioni puntano l'agente verso i tuoi token, componenti e specifiche reali, così lavora rispetto a un brand invece che su un aspetto predefinito."}]}, {"kind": "image", "src": "/agents/vibe-design/vibe-design-taste-triangle.webp", "alt": "Diagramma che mostra design system, skill e immagine di riferimento che convergono in un buon output di design", "caption": "Il gusto deriva da tre input che fornisci tu: un design system, una skill e immagini di riferimento reali."}, {"kind": "p", "text": "La lezione è la stessa che insegna ogni agente: Vibe CLI non ha gusto per impostazione predefinita. Produce un buon design quando gli dai dei vincoli — un design system, una skill estetica e riferimenti concreti. Open Design impacchetta esattamente questi input, ed è per questo che i due si integrano bene (più avanti il dettaglio)."}]}, {"id": "setup", "heading": "Configura Vibe CLI per il lavoro di design, da zero", "blocks": [{"kind": "p", "text": "Ecco il percorso completo da una macchina pulita a un Vibe CLI capace di costruire e verificare UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Mistral Vibe CLI\nuv tool install mistral-vibe\n# or: pip install mistral-vibe\n\n# 2. Run the setup wizard to register your API key\nvibe --setup     # saves config to ~/.vibe/config.toml and ~/.vibe/.env\n#    or set it directly:  export MISTRAL_API_KEY=...\n\n# 3. Start Vibe in your project\ncd your-project\nvibe\n\n# 4. Wire the Figma MCP server (optional, for design handoff)\n#    add an [[mcp_servers]] entry in your config.toml"}, {"kind": "image", "src": "/agents/vibe-design/vibe-design-setup-flow.webp", "alt": "Flusso di configurazione in cinque passi: installa, autentica, configura config.toml, aggiungi una skill, verifica", "caption": "La sequenza di configurazione: installa → autentica → configura config.toml → aggiungi una skill → abilita la verifica nel browser."}, {"kind": "steps", "items": [{"label": "Codifica le tue regole di design", "body": "Tieni i tuoi token, le primitive e le convenzioni dove l'agente le legge e punta Vibe verso di esse, così l'output corrisponde a un brand invece di ripiegare su un aspetto generico."}, {"label": "Aggiungi la verifica nel browser", "body": "Collega un MCP Playwright o di browser così Vibe renderizza in un browser reale e controlla il suo output attraverso i breakpoint invece di limitarsi a confermare che la build passi."}]}]}, {"id": "screenshot-workflow", "heading": "Il flusso di lavoro dal riferimento all'UI", "blocks": [{"kind": "p", "text": "Il ciclo di design a maggior leva con Vibe CLI è trasformare un riferimento chiaro in un'UI funzionante e responsive e iterare finché non corrisponde — appoggiandosi agli strumenti dell'agente per renderizzare, ispezionare e correggere il proprio output."}, {"kind": "ol", "items": ["Parti dai riferimenti più chiari che hai — e descrivi più stati (desktop e mobile, hover, vuoto, caricamento), non solo un'unica schermata hero.", "Sii specifico nel prompt; i prompt vaghi producono UI generiche anche con un modello forte.", "Tieni il tuo design system e le tue convenzioni dove Vibe le legge, e indicagli dove si trovano i token e le primitive canoniche.", "Avvia un dev server e fai renderizzare a Vibe in un browser reale, ridimensionando ai breakpoint per controllare il risultato.", "Itera facendo confrontare a Vibe la sua implementazione con i riferimenti — non limitarti a confermare che si compili."]}, {"kind": "p", "text": "Fai riferimento ai file con @ (Vibe completa automaticamente i percorsi dei file) e guida i comandi slash con /, poi dai vincoli concreti:"}, {"kind": "code", "lang": "bash", "code": "vibe\n# in the prompt:\n> @design-spec.md @tokens.css\n  Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Run the dev server, render it in the browser, and iterate until\n  it matches the references across breakpoints."}, {"kind": "p", "text": "Tieni i prompt piccoli e mirati, committa le buone iterazioni e annulla quelle cattive (dicendolo a Vibe quando annulli), così ogni passaggio si costruisce su una base pulita."}]}, {"id": "extend", "heading": "config.toml, MCP e ACP", "blocks": [{"kind": "p", "text": "Tre punti di estensione rendono Vibe CLI pratico per un lavoro di design continuativo, e tutti e tre si mappano in modo pulito su un flusso di lavoro di design aperto."}, {"kind": "steps", "items": [{"label": "config.toml", "body": "Le regole di progetto e le impostazioni di provider/modello vivono in un config.toml (a livello di progetto, con un fallback in ~/.vibe). È la sede durevole di come l'agente è cablato nel tuo progetto, letta a ogni esecuzione."}, {"label": "Server MCP", "body": "Configura i server MCP nel tuo config.toml ([[mcp_servers]], con trasporti HTTP, streamable-HTTP e stdio) — il modo portabile per portare contesto di design e strumenti esterni, più rilevante il server MCP Figma, che funzionano tra gli agenti, non solo Vibe."}, {"label": "Agent Client Protocol", "body": "Vibe parla ACP, così lo stesso agente può essere pilotato da editor e altri client ACP. È esattamente così che Open Design lo integra — tramite ACP attraverso il binario vibe-acp."}]}, {"kind": "p", "text": "Sono capacità portabili e multi-agente — esattamente il tipo di cosa che Open Design è costruito per orchestrare, invece di ricrearle per ogni progetto."}]}, {"id": "vs", "heading": "Vibe CLI vs Codex vs Claude Code vs Cursor vs Gemini CLI per il design", "blocks": [{"kind": "p", "text": "Non c'è un unico vincitore per il lavoro di design — ogni agente ha un punto di forza diverso, e i team esperti li combinano. Un riepilogo onesto:"}, {"kind": "table", "columns": ["Agente", "Punto di forza nel design", "Ideale per"], "rows": [["Mistral Vibe CLI", "Modelli di codice Devstral open-weights che puoi eseguire in locale; Apache-2.0 e nativo ACP", "Lavoro di design sensibile alla privacy o offline e uno stack open-weights"], ["Codex", "Forte rifinitura visiva con una skill frontend; build asincrone in sandbox", "Build asincrone delegate e regole AGENTS.md portabili"], ["Claude Code", "Decisioni di design specifiche (hex, spaziatura, tipografia) e UX consapevole del codebase", "Ragionamento frontend e refactoring a grande contesto"], ["Cursor", "Ciclo visivo build-and-see con anteprima live e modifiche inline", "Lavoro su UI stretto, itera-e-osserva dentro un IDE"], ["Gemini CLI", "Forte comprensione multimodale delle immagini e una finestra di contesto molto ampia", "Lavoro ricco di screenshot e mantenere un intero design system nel contesto"]]}, {"kind": "p", "text": "Il verdetto ricorrente della community è che il gusto viene dalle persone: tutti ripiegano su un'estetica generica senza skill, riferimenti e vincoli. Questo è il vero problema da risolvere — ed è di forma da strumento di design, non da modello."}]}, {"id": "pitfalls", "heading": "Insidie, e come evitare l'aspetto da “AI slop”", "blocks": [{"kind": "p", "text": "La lamentela più comune sul design generato dall'AI è che sembra generico — gradienti morbidi, pannelli fluttuanti, angoli arrotondati sovradimensionati, ombre drammatiche, un'atmosfera Inter-e-viola che “urla che l'ha fatto un'AI”. Altri problemi segnalati includono layout mobile rotti e istruzioni che finiscono nei testi dell'UI. Nessuno di questi è esclusivo di Vibe CLI; sono ciò che accade quando un qualsiasi agente gira senza un contesto di design curato."}, {"kind": "steps", "items": [{"label": "Aggiungi una skill estetica", "body": "Una skill di design curata costringe l'agente a impegnarsi su una direzione reale invece dell'aspetto predefinito."}, {"label": "Verifica in un browser reale", "body": "Fai renderizzare e autocontrollare a Vibe attraverso i breakpoint così i layout non si rompono silenziosamente su mobile."}, {"label": "Fornisci token e riferimenti", "body": "Token di design reali e screenshot di riferimento sono la leva singola più grande sulla qualità dell'output."}, {"label": "Codifica le regole nella configurazione e nel contesto", "body": "Metti regole in stile “niente hero card, massimo due font, gerarchia brand-first” dove l'agente le legge a ogni esecuzione."}]}, {"kind": "p", "text": "Nota che ogni mitigazione riguarda il fornire all'agente un contesto di design curato. Mantenere quel contesto a mano, progetto per progetto, è la fatica che Open Design elimina."}]}, {"id": "open-design", "heading": "Progettare con Vibe CLI dentro Open Design", "blocks": [{"kind": "p", "text": "Open Design è il livello di design open source che il flusso di lavoro qui sopra continua a richiedere. Tratta Mistral Vibe CLI come un adattatore di prima parte — pilotandolo tramite ACP attraverso il binario vibe-acp — e lo avvolge in una libreria curata di skill e design system, una pipeline di rendering strutturata e un'UI desktop locale. Così il contesto di design che rende Vibe valido è presente dalla prima esecuzione, non assemblato a mano ogni volta. Entrambi sono open source e local-first, il che rende l'abbinamento naturale."}, {"kind": "ol", "items": ["Installa Open Design e seleziona Mistral Vibe CLI come tuo agente.", "Autentica con la tua chiave API Mistral (BYOK) o punta Vibe verso modelli locali — le credenziali restano sulla tua macchina e non passano mai attraverso di noi tramite proxy.", "Scegli un design system e una skill, poi genera deck, prototipi e landing page con un gusto coerente.", "Ogni artefatto e file DESIGN.md vive nel tuo repo, non in un cloud ospitato."]}, {"kind": "p", "text": "Stesso agente Vibe CLI, stessa chiave — più un flusso di lavoro di design reale, portabile e open source attorno ad esso. È local-first e Apache-2.0, quindi nulla del tuo lavoro o delle tue credenziali lascia la tua macchina."}]}], "faqTitle": "Domande frequenti", "faq": [{"name": "Mistral Vibe CLI può davvero fare lavoro di design?", "text": "Sì — con una skill estetica, un design system e riferimenti reali nel contesto, Vibe CLI produce UI responsive di qualità da produzione, e i suoi modelli Devstral modificano in tutto un codebase frontend reale. Senza quel contesto tende a ripiegare su un aspetto generico, che è il divario che Open Design colma."}, {"name": "Come autentico Vibe CLI?", "text": "Esegui il wizard di configurazione con vibe --setup per registrare una chiave API Mistral (dalla console Mistral), oppure imposta MISTRAL_API_KEY nel tuo ambiente. Può anche girare rispetto a modelli locali o compatibili, completamente offline. Open Design non fa comunque mai da proxy alle tue credenziali."}, {"name": "Cosa rende Vibe CLI buono per il design in particolare?", "text": "È un agente Apache-2.0, nativo ACP, alimentato dai modelli di codice Devstral open-weights di Mistral — così puoi eseguirlo in locale per il lavoro sensibile alla privacy e modificare in tutto un codebase reale. Ma il gusto viene comunque dal design system, dalla skill e dai riferimenti che fornisci."}, {"name": "Vibe CLI o Claude Code per il design frontend?", "text": "Entrambi sono forti. Claude Code è noto per decisioni di design specifiche e consapevoli del codebase; il vantaggio di Vibe CLI è uno stack Devstral open-weights che puoi eseguire in locale e una licenza Apache-2.0. Molti team usano entrambi — Open Design ti permette di cambiare agente senza cambiare il tuo flusso di lavoro di design."}, {"name": "Come collego Vibe CLI a Figma?", "text": "Aggiungi il server MCP Figma come voce [[mcp_servers]] nel tuo config.toml. Vibe può poi estrarre contesto di design reale — componenti, variabili, dati di layout — così il codice generato corrisponde alla fonte invece di approssimarla."}, {"name": "Open Design è affiliato a Mistral AI?", "text": "No. Mistral Vibe CLI è un prodotto di Mistral AI; Open Design è un progetto open source indipendente che lo supporta come adattatore di prima parte, pilotato tramite ACP. Mistral è un marchio di Mistral AI."}, {"name": "I miei file e le mie credenziali sono al sicuro?", "text": "Sì — Open Design è local-first e Apache-2.0. I tuoi file, gli artefatti e DESIGN.md restano nel tuo repo, e le tue credenziali Mistral vengono usate direttamente dal tuo agente, mai instradate attraverso i server di Open Design."}], "ctaTitle": "Progetta con Mistral Vibe CLI, alla maniera aperta.", "ctaBody": "Porta la tua chiave API Mistral o modelli locali, tieni ogni file in locale e ottieni una libreria di design curata attorno all'agente che già usi.", "ctaActions": [{"label": "Usa Vibe CLI dentro Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Metti una stella su GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Scarica l'app desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Vedi tutti gli agenti supportati"},
      },
      'qoder': {
        ...en['qoder']!,
        title: "Qoder CLI per il design — Open Design",
        description: "Come si usa Qoder CLI — la piattaforma di coding agentico di Alibaba — per il design di UI e web: le sue modalità agent e quest, la profonda comprensione del repository e la repo wiki, e i tier di modello Lite/Efficient/Auto — e come Open Design trasforma Qoder CLI in un agente di design open source e local-first.",
        breadcrumb: "Qoder CLI",
        label: "Agente · Qoder CLI",
        heading: "Qoder CLI per il design.",
        lead: "Qoder CLI è l'agente da terminale di Qoder, la piattaforma di coding agentico di Alibaba. Comprende un intero repository — architettura, pattern e le convenzioni catturate nella sua repo wiki — ed esegue lavoro autonomo guidato dalle specifiche, il che lo rende un vero strumento di design una volta che gli fornisci riferimenti, convenzioni e un ciclo di verifica. Open Design lo collega a un flusso di lavoro di design open source: il tuo account Qoder, i tuoi file, local-first.",
        rich: {"heroCtaLead": "Open Design trasforma Qoder CLI in un agente di design open source e local-first — il tuo account Qoder, i tuoi file, una libreria curata di skill e design system attorno ad esso.", "heroCtaActions": [{"label": "Usa Qoder CLI dentro Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Metti una stella su GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Scarica l'app desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Qoder CLI è l'agente da terminale di Qoder, la piattaforma di coding agentico di Alibaba. Due caratteristiche lo rendono interessante per il design in particolare: costruisce un profondo contesto sul tuo repository — architettura, pattern di design e le convenzioni che distilla in una repo wiki — così riutilizza le tue primitive reali invece di inventare stili una tantum; ed esegue quest autonome e guidate dalle specifiche che pianificano, implementano e verificano un task da capo a fondo anziché limitarsi a completare righe. Abbinato ai riferimenti giusti, alle convenzioni e a un ciclo di verifica, costruisce UI reali e responsive. Questa è una guida pratica ed end-to-end all'uso di Qoder CLI per il lavoro su UI, frontend e design system, e a come integrarlo in un flusso di lavoro di design strutturato con Open Design.", "Copre cos'è realmente Qoder CLI, perché la sua comprensione del repo e le quest agentiche si adattano al design, come configurarlo da zero, il ciclo dal riferimento all'UI, come regole, MCP e la repo wiki lo estendono, come si confronta con Codex, Claude Code, Cursor e Gemini CLI, le insidie che fanno sembrare generico l'output dell'AI, e come Open Design colma il divario come livello di design aperto e local-first attorno all'agente che già usi."], "heroImage": {"src": "/agents/qoder-design/qoder-design-hero.webp", "alt": "Ciclo di feedback del design con Qoder CLI: un agente da terminale che legge un'immagine di riferimento con contesto della repo wiki, un browser che renderizza l'UI e un workspace, con una freccia di feedback che ritorna", "caption": "Il ciclo centrale: Qoder CLI legge i tuoi riferimenti e il contesto del repo nel terminale, costruisce e verifica l'UI in un browser reale, e itera in base ad essi."}, "tocLabel": "In questa pagina", "toc": [{"id": "what-is-qoder", "label": "Cos'è realmente Qoder CLI"}, {"id": "why-design", "label": "Perché agentico + contesto del repo si adattano al design"}, {"id": "setup", "label": "Configura Qoder CLI per il design (da zero)"}, {"id": "screenshot-workflow", "label": "Il flusso di lavoro dal riferimento all'UI"}, {"id": "extend", "label": "Regole, MCP e la repo wiki"}, {"id": "vs", "label": "Qoder CLI vs Codex vs Claude Code vs Cursor vs Gemini CLI"}, {"id": "pitfalls", "label": "Insidie e l'aspetto da “AI slop”"}, {"id": "open-design", "label": "Progettare con Qoder CLI in Open Design"}, {"id": "faq", "label": "FAQ"}], "sections": [{"id": "what-is-qoder", "heading": "Cos'è realmente Qoder CLI", "blocks": [{"kind": "p", "text": "Qoder è una piattaforma di coding agentico di Alibaba — un ambiente di sviluppo AI, disponibile come app desktop e CLI, che comprende codebase reali e gestisce task di sviluppo da capo a fondo. Qoder CLI porta quel motore nel terminale: legge il tuo repository, modifica i file, esegue comandi shell e lavora sui task a partire dal linguaggio naturale anziché limitarsi a completare righe. Accede con un account Qoder."}, {"kind": "p", "text": "Per il lavoro di design spiccano due proprietà. Qoder costruisce un profondo contesto sul tuo repository — architettura, pattern di design e convenzioni distillate in una repo wiki — così ancora l'output alle tue primitive reali. Ed esegue un flusso di lavoro agentico e guidato dalle specifiche: delinei cosa vuoi e lui pianifica, implementa e verifica il lavoro, anche attraverso più passi."}, {"kind": "steps", "items": [{"label": "Modalità Agent e Quest", "body": "La modalità Agent è programmazione in coppia conversazionale con checkpoint human-in-the-loop; la modalità Quest delega lavoro più lungo e multi-step a un agente autonomo che pianifica, implementa e si autoverifica — il luogo naturale per affidare un task di design guidato dalle specifiche."}, {"label": "Repo wiki + MCP", "body": "Qoder distilla il tuo codebase in una repo wiki di architettura e convenzioni, e supporta server MCP per portare contesto esterno come un file Figma live."}, {"label": "Tier di modello", "body": "Qoder CLI espone i tier Lite, Efficient e Auto; Auto lascia che il suo scheduler scelga un modello per task, così non gestisci la selezione del modello a mano."}]}, {"kind": "ul", "items": ["Fornitore: Alibaba", "Credenziale: account Qoder (accesso tramite browser, oppure un token di accesso personale Qoder per l'uso non interattivo)", "Tier di modello: Lite, Efficient, Auto"]}]}, {"id": "why-design", "heading": "Perché un agente agentico e consapevole del repo si adatta al design", "blocks": [{"kind": "p", "text": "Il vantaggio di Qoder CLI nel design deriva da due proprietà — ma, come con ogni agente, il gusto va comunque fornito."}, {"kind": "steps", "items": [{"label": "Profonda comprensione del repository", "body": "Poiché Qoder costruisce contesto sull'intero codebase e lo distilla in una repo wiki, l'agente riutilizza i tuoi componenti e token esistenti invece di inventare stili una tantum per ogni schermata."}, {"label": "Quest autonome e guidate dalle specifiche", "body": "La modalità Quest trasforma una specifica scritta in un risultato pianificato, implementato e autoverificato, così un task di design gira da capo a fondo anziché fermarsi a una prima bozza."}, {"label": "Convenzioni che l'agente legge", "body": "Le regole di progetto (più il server MCP Figma) puntano l'agente verso i tuoi token, componenti e specifiche reali, così lavora rispetto a un brand invece che su un aspetto predefinito."}]}, {"kind": "image", "src": "/agents/qoder-design/qoder-design-taste-triangle.webp", "alt": "Diagramma che mostra design system, skill e immagine di riferimento che convergono in un buon output di design", "caption": "Il gusto deriva da tre input che fornisci tu: un design system, una skill e immagini di riferimento reali."}, {"kind": "p", "text": "La lezione è la stessa che insegna ogni agente: Qoder CLI non ha gusto per impostazione predefinita. Produce un buon design quando gli dai dei vincoli — un design system, una skill estetica e riferimenti concreti. Open Design impacchetta esattamente questi input, ed è per questo che i due si integrano bene (più avanti il dettaglio)."}]}, {"id": "setup", "heading": "Configura Qoder CLI per il lavoro di design, da zero", "blocks": [{"kind": "p", "text": "Ecco il percorso completo da una macchina pulita a un Qoder CLI capace di costruire e verificare UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Qoder CLI (Node 20+)\nnpm install -g @qoder-ai/qodercli\n# (macOS/Linux via Homebrew also available)\n\n# 2. Verify the install\nqodercli --version\n\n# 3. Start it in your project and sign in on first run\ncd your-project\nqodercli          # then /login — sign in via browser or a Qoder access token\n\n# 4. Pick a model tier for the session\n#    Lite, Efficient, or Auto (Auto lets the scheduler choose per task)"}, {"kind": "image", "src": "/agents/qoder-design/qoder-design-setup-flow.webp", "alt": "Flusso di configurazione in cinque passi: installa, autentica, configura le regole, aggiungi una skill, verifica", "caption": "La sequenza di configurazione: installa → accedi → configura le regole di progetto → aggiungi una skill → abilita la verifica nel browser."}, {"kind": "steps", "items": [{"label": "Codifica le tue regole di design", "body": "Metti i tuoi token, le primitive e le convenzioni dove l'agente le legge, così l'output corrisponde a un brand invece di ripiegare su un aspetto generico. La repo wiki di Qoder aiuta a mantenere quel contesto aggiornato."}, {"label": "Aggiungi la verifica nel browser", "body": "Collega un MCP Playwright o di browser così Qoder renderizza in un browser reale e controlla il suo output attraverso i breakpoint invece di limitarsi a confermare che la build passi."}]}]}, {"id": "screenshot-workflow", "heading": "Il flusso di lavoro dal riferimento all'UI", "blocks": [{"kind": "p", "text": "Il ciclo di design a maggior leva con Qoder CLI è trasformare un riferimento in un'UI funzionante e responsive e iterare finché non corrisponde — appoggiandosi al contesto del repo dell'agente e a un ciclo di verifica reale per confrontare l'output con il riferimento."}, {"kind": "ol", "items": ["Parti dai riferimenti visivi più chiari che hai — e includi più stati (desktop e mobile, hover, vuoto, caricamento), non solo un'unica schermata hero.", "Sii specifico nel prompt; i prompt vaghi producono UI generiche anche con un agente capace.", "Punta Qoder verso il tuo design system e le tue convenzioni, e indicagli dove si trovano i token e le primitive canoniche.", "Avvia un dev server e fai renderizzare a Qoder in un browser reale, ridimensionando ai breakpoint per controllare il risultato.", "Itera facendo confrontare a Qoder la sua implementazione con i riferimenti — non limitarti a confermare che si compili."]}, {"kind": "p", "text": "Scrivi il task come una specifica chiara e lascia che una quest lo porti a termine, dando vincoli concreti:"}, {"kind": "code", "lang": "bash", "code": "qodercli\n# in the prompt:\n> Implement this design from reference-desktop.png and\n  reference-mobile.png in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the references\n  across breakpoints."}, {"kind": "p", "text": "Tieni i prompt piccoli e mirati, committa le buone iterazioni e annulla quelle cattive (dicendolo a Qoder quando annulli), così ogni passaggio si costruisce su una base pulita."}]}, {"id": "extend", "heading": "Regole, MCP e la repo wiki", "blocks": [{"kind": "p", "text": "Tre punti di estensione rendono Qoder CLI pratico per un lavoro di design continuativo, e tutti e tre si mappano in modo pulito su un flusso di lavoro di design aperto."}, {"kind": "steps", "items": [{"label": "Regole di progetto", "body": "Codifica le tue convenzioni di design come regole di progetto durevoli che l'agente legge a ogni esecuzione — la sede per token, primitive e checklist di revisione."}, {"label": "Server MCP", "body": "MCP è il modo portabile per portare contesto di design e strumenti esterni, più rilevante il server MCP Figma, e funziona tra gli agenti, non solo Qoder."}, {"label": "La repo wiki", "body": "La repo wiki di Qoder distilla automaticamente architettura e convenzioni, così l'agente continua a riutilizzare i tuoi componenti reali invece di riapprendere il codebase a ogni task."}]}, {"kind": "p", "text": "Sono capacità portabili e multi-agente — esattamente il tipo di cosa che Open Design è costruito per orchestrare, invece di ricrearle per ogni progetto."}]}, {"id": "vs", "heading": "Qoder CLI vs Codex vs Claude Code vs Cursor vs Gemini CLI per il design", "blocks": [{"kind": "p", "text": "Non c'è un unico vincitore per il lavoro di design — ogni agente ha un punto di forza diverso, e i team esperti li combinano. Un riepilogo onesto:"}, {"kind": "table", "columns": ["Agente", "Punto di forza nel design", "Ideale per"], "rows": [["Qoder CLI", "Profonda comprensione del repository con una repo wiki e quest autonome e guidate dalle specifiche; tier Lite/Efficient/Auto", "Lavoro ricco di contesto del repo e delega di build multi-step guidate dalle specifiche"], ["Codex", "Forte rifinitura visiva con una skill frontend; build asincrone in sandbox", "Build asincrone delegate e regole AGENTS.md portabili"], ["Claude Code", "Decisioni di design specifiche (hex, spaziatura, tipografia) e UX consapevole del codebase", "Ragionamento frontend e refactoring a grande contesto"], ["Cursor", "Ciclo visivo build-and-see con anteprima live e modifiche inline", "Lavoro su UI stretto, itera-e-osserva dentro un IDE"], ["Gemini CLI", "Forte comprensione multimodale delle immagini e contesto da 1M token; tier gratuito", "Lavoro ricco di screenshot e mantenere un intero design system nel contesto"]]}, {"kind": "p", "text": "Il verdetto ricorrente della community è che il gusto viene dalle persone: tutti ripiegano su un'estetica generica senza skill, riferimenti e vincoli. Questo è il vero problema da risolvere — ed è di forma da strumento di design, non da modello."}]}, {"id": "pitfalls", "heading": "Insidie, e come evitare l'aspetto da “AI slop”", "blocks": [{"kind": "p", "text": "La lamentela più comune sul design generato dall'AI è che sembra generico — gradienti morbidi, pannelli fluttuanti, angoli arrotondati sovradimensionati, ombre drammatiche, un'atmosfera Inter-e-viola che “urla che l'ha fatto un'AI”. Altri problemi segnalati includono layout mobile rotti e istruzioni che finiscono nei testi dell'UI. Nessuno di questi è esclusivo di Qoder CLI; sono ciò che accade quando un qualsiasi agente gira senza un contesto di design curato."}, {"kind": "steps", "items": [{"label": "Aggiungi una skill estetica", "body": "Una skill di design curata costringe l'agente a impegnarsi su una direzione reale invece dell'aspetto predefinito."}, {"label": "Verifica in un browser reale", "body": "Renderizza e autocontrolla attraverso i breakpoint così i layout non si rompono silenziosamente su mobile."}, {"label": "Fornisci token e riferimenti", "body": "Token di design reali e screenshot di riferimento sono la leva singola più grande sulla qualità dell'output."}, {"label": "Codifica le regole che l'agente legge", "body": "Metti regole in stile “niente hero card, massimo due font, gerarchia brand-first” nelle regole di progetto e nella repo wiki, dove l'agente le legge a ogni esecuzione."}]}, {"kind": "p", "text": "Nota che ogni mitigazione riguarda il fornire all'agente un contesto di design curato. Mantenere quel contesto a mano, progetto per progetto, è la fatica che Open Design elimina."}]}, {"id": "open-design", "heading": "Progettare con Qoder CLI dentro Open Design", "blocks": [{"kind": "p", "text": "Open Design è il livello di design open source che il flusso di lavoro qui sopra continua a richiedere. Tratta Qoder CLI come un adattatore di prima parte e lo avvolge in una libreria curata di skill e design system, una pipeline di rendering strutturata e un'UI desktop locale — così il contesto di design che rende Qoder valido è presente dalla prima esecuzione, non assemblato a mano ogni volta. Open Design è local-first, quindi il tuo lavoro resta sulla tua macchina."}, {"kind": "ol", "items": ["Installa Open Design e seleziona Qoder CLI come tuo agente.", "Autentica con il tuo account Qoder — le credenziali restano sulla tua macchina e non passano mai attraverso di noi tramite proxy.", "Scegli un design system e una skill, poi genera deck, prototipi e landing page con un gusto coerente.", "Ogni artefatto e file DESIGN.md vive nel tuo repo, non in un cloud ospitato."]}, {"kind": "p", "text": "Stesso agente Qoder CLI, stesso account — più un flusso di lavoro di design reale, portabile e open source attorno ad esso. È local-first e Apache-2.0, quindi nulla del tuo lavoro o delle tue credenziali lascia la tua macchina."}]}], "faqTitle": "Domande frequenti", "faq": [{"name": "Qoder CLI può davvero fare lavoro di design?", "text": "Sì — con una skill estetica, un design system e immagini di riferimento reali nel contesto, Qoder CLI produce UI responsive di qualità da produzione, e la sua profonda comprensione del repository lo aiuta a riutilizzare i tuoi componenti reali. Senza quel contesto tende a ripiegare su un aspetto generico, che è il divario che Open Design colma."}, {"name": "Come autentico Qoder CLI?", "text": "Esegui qodercli e usa /login per accedere con il tuo account Qoder tramite il browser, oppure fornisci un token di accesso personale Qoder per gli ambienti non interattivi. Open Design non fa mai da proxy alle tue credenziali — l'agente le usa direttamente."}, {"name": "Cosa rende Qoder CLI buono per il design in particolare?", "text": "Due cose: costruisce un profondo contesto sul tuo repository — architettura, convenzioni e una repo wiki — così riutilizza le tue primitive reali, e le sue quest guidate dalle specifiche eseguono un task di design da capo a fondo. Entrambe aiutano, ma il gusto viene comunque dal design system, dalla skill e dai riferimenti che fornisci."}, {"name": "Cosa sono i tier di modello Lite, Efficient e Auto?", "text": "Qoder CLI ti permette di scegliere un tier di modello: Lite, Efficient o Auto. Auto lascia che lo scheduler di Qoder scelga un modello per task, così non gestisci la selezione del modello a mano. Scegli il tier adatto al lavoro; Auto è un default sensato."}, {"name": "Come collego Qoder CLI a Figma?", "text": "Aggiungi il server MCP Figma alla configurazione MCP di Qoder. Qoder può poi estrarre contesto di design reale — componenti, variabili, dati di layout — così il codice generato corrisponde alla fonte invece di approssimarla."}, {"name": "Open Design è affiliato a Qoder o Alibaba?", "text": "No. Qoder è un prodotto di Alibaba; Open Design è un progetto open source indipendente che lo supporta come adattatore di prima parte. Qoder è un marchio del rispettivo proprietario."}, {"name": "I miei file e le mie credenziali sono al sicuro?", "text": "Sì — Open Design è local-first e Apache-2.0. I tuoi file, gli artefatti e DESIGN.md restano nel tuo repo, e le tue credenziali Qoder vengono usate direttamente dal tuo agente, mai instradate attraverso i server di Open Design."}], "ctaTitle": "Progetta con Qoder CLI, alla maniera aperta.", "ctaBody": "Porta il tuo account Qoder, tieni ogni file in locale e ottieni una libreria di design curata attorno all'agente che già usi.", "ctaActions": [{"label": "Usa Qoder CLI dentro Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Metti una stella su GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Scarica l'app desktop", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Vedi tutti gli agenti supportati"},
      },
    },
  };
}
